import React, { useState, useEffect } from 'react';

// Context to hold the seating map data and coordinates
const SeatingMapContext = React.createContext();

function App() {
  // State to hold the seating map data
  const [seats, setSeats] = useState([]);
  // State to hold the error message (if any)
  const [error, setError] = useState(null);

  useEffect(() => {
    // Fetching data from an API or a static file
    fetch('https://example.com/seating-map')
      .then(response => response.json())
      .then(data => {
        setSeats(data);
      })
      .catch(err => {
        setError(`Error fetching seating map: ${err}`);
      });
  }, []);

  // Function to handle seat selection (example)
  const handleSelectSeat = seatId => {
    // Example state update logic
    console.log(`Selected seat: ${seatId}`);
  };

  return (
    <SeatingMapContext.Provider value={{ seats, error }}>
      {error && <div style={{ color: 'red' }}>{error}</div>}
      <SeatMap />
    </SeatingMapContext.Provider>
  );
}

function SeatMap() {
  const { seats, error } = React.useContext(SeatingMapContext);

  if (error) return null;

  // Mapping over the seats to create a grid of seat components
  return (
    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(10, 50px)', gap: '5px' }}>
      {seats.map(seat => (
        <button
          key={seat.id}
          onClick={() => handleSelectSeat(seat.id)}
          style={{
            width: '50px',
            height: '50px',
            backgroundColor: seat.isSelected ? 'lightblue' : '#f0f0f0', // Conditional color based on selection status
            cursor: 'pointer',
          }}
        />
      ))}
    </div>
  );
}

export default App;
