import React, { useState, useEffect } from 'react';
import PropTypes from 'prop-types';

const InteractiveTable = ({ seats }) => {
  const [selectedRow, setSelectedRow] = useState(null);
  const [selectedSeat, setSelectedSeat] = useState(null);

  // Define a function to handle seat selection changes
  const handleSeatSelect = (rowIndex, seatIndex) => {
    setSelectedRow(rowIndex);
    setSelectedSeat(seatIndex);
  };

  // Define the color for selected seats based on their index
  const getColor = (seatIndex) => {
    // Simple logic: red if odd, blue if even
    return seatIndex % 2 === 0 ? 'blue' : 'red';
  };

  // Example data structure for seats. Adjust this according to your actual data format
  const initialSeats = [
    ['A1', 'A2', 'A3'],
    ['B1', 'B2', 'B3'],
    ['C1', 'C2', 'C3']
  ];

  // Use useEffect to handle seat data changes if needed
  useEffect(() => {
    if (seats) {
      initialSeats.forEach((row, rowIndex) => {
        row.forEach((seat, seatIndex) => {
          handleSeatSelect(rowIndex, seatIndex);
        });
      });
    }
  }, [seats]);

  // Render the table
  return (
    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 100px)', gap: 5 }}>
      {initialSeats.map((row, rowIndex) => (
        <React.Fragment key={rowIndex}>
          {row.map((seat, seatIndex) => (
            <div
              key={`${rowIndex}-${seatIndex}`}
              style={{
                width: '100px',
                height: '100px',
                backgroundColor: getColor(seatIndex),
                cursor: selectedRow === rowIndex && selectedSeat === seatIndex ? 'pointer' : 'auto'
              }}
              onClick={() => handleSeatSelect(rowIndex, seatIndex)}
            >
              {seat}
            </div>
          ))}
        </React.Fragment>
      ))}
    </div>
  );
};

InteractiveTable.propTypes = {
  seats: PropTypes.arrayOf(PropTypes.string).isRequired
};

export default InteractiveTable;
```

