// ConditionalColoringLogic.js

/**
 * Class to handle conditional coloring based on state.
 */
class ConditionalColoringLogic {
    constructor(data) {
        this.data = data;
    }

    /**
     * Applies conditional color mapping based on the current state of each coordinate.
     * @returns An array of objects, each with coordinates and their corresponding colors.
     */
    applyConditionalColoring() {
        return this.data.map(coord => ({
            // Default color
            color: 'lightgray',

            // Conditional coloring logic
            ...((coord.state === 'occupied') && { color: 'red' }),
            ...((coord.state === 'available') && { color: 'green' }),
            ...((coord.state === 'busy') && { color: 'yellow' })
        }));
    }
}

export default ConditionalColoringLogic;
