// utils.js - Utility functions for Interactive Seating Map

/**
 * Converts a numeric row index to its corresponding color based on conditional state.
 * @param {number} rowIndex - The row index (1-based).
 * @returns {string} A CSS color string representing the background color of the seat.
 */
function getRowColor(rowIndex) {
    // Conditional logic for setting different colors based on row index
    if (rowIndex % 2 === 0) return '#f4f4f9'; // Light gray background for even rows
    else return '#e1e1e8'; // Light blue background for odd rows
}

/**
 * Calculates the color of a specific seat based on its column and row index.
 * @param {number} columnIndex - The column index (1-based).
 * @param {number} rowIndex - The row index (1-based).
 * @returns {string} A CSS color string representing the background color of the seat.
 */
function getSeatColor(columnIndex, rowIndex) {
    // Basic grid coloring logic
    const baseColors = ['#FFFFFF', '#DDDDDD']; // White and light gray colors
    const colorCycle = 2; // Two colors cycle through
    return baseColors[(columnIndex + rowIndex - 1) % colorCycle];
}

/**
 * Calculates the CSS background position for a seat given its row and column index.
 * @param {number} columnIndex - The column index (1-based).
 * @param {number} rowIndex - The row index (1-based).
 * @returns {string} A CSS 'background-position' string.
 */
function getSeatPosition(columnIndex, rowIndex) {
    // Positioning based on a 5x10 grid
    const xPos = ((columnIndex - 1) * 72); // 72px per column
    const yPos = ((rowIndex - 1) * 68); // 68px per row
    return `${xPos}px ${yPos}px`;
}

// Example usage in a map component
function renderSeat(columnIndex, rowIndex) {
    const seatColor = getSeatColor(columnIndex, rowIndex);
    const rowStyle = `background-color: ${getRowColor(rowIndex)}; position: relative;`;
    const seatPosition = `background-position: ${getSeatPosition(columnIndex, rowIndex)}`;

    return `
        <div class="seat" style="${rowStyle}">${seatPosition}</div>
    `;
}
