// Define a class to handle API calls
class APIWrapper {
    constructor(apiUrl) {
        this.apiUrl = apiUrl;
    }

    // Method to fetch data from the API using GET request
    async fetchData() {
        try {
            const response = await axios.get(this.apiUrl);
            return response.data; // Return the fetched data as JSON
        } catch (error) {
            console.error('Error fetching data:', error); // Log any errors that occur during the fetch
            throw error;
        }
    }

    // Method to post data to the API using POST request
    async postData(data) {
        try {
            const response = await axios.post(this.apiUrl, data);
            return response.data; // Return the response from the server as JSON
        } catch (error) {
            console.error('Error posting data:', error); // Log any errors that occur during the post
            throw error;
        }
    }
