import React, { useState, useEffect } from 'react';
import i18n from './i18n'; // Import your translation file

const LanguageSelect = () => {
  const [currentLocale, setCurrentLocale] = useState(i18n.locale);

  const handleLanguageChange = (locale) => {
    try {
      // Attempt to change the locale
      i18n.changeLanguage(locale);
      // Update the state with the new locale
      setCurrentLocale(locale);
      console.log(`Language changed to: ${locale}`);
    } catch (error) {
      console.error('Error changing language:', error);
    }
  };

  useEffect(() => {
    // Listen for changes in the i18n locale and update the component's state
    const onLocaleChange = () => setCurrentLocale(i18n.locale);
    i18n.on('change', onLocaleChange);

    // Cleanup function to remove the listener when the component unmounts
    return () => {
      i18n.off('change', onLocaleChange);
    };
  }, []);

  const languages = ['en', 'fr', 'es']; // List of available locales

  return (
    <select value={currentLocale} onChange={(e) => handleLanguageChange(e.target.value)}>
      {languages.map((lang, index) => (
        <option key={index} value={lang}>
          {i18n.t(`language.${lang}`)} {/* Use i18n to get language names */}
        </option>
      ))}
    </select>
  );
};

export default LanguageSelect;
```

**Explanation**:
- This component uses React hooks (`useState` and `useEffect`) for state management and side effects.
- It imports the translation file `i18n.js`, which contains locale-specific translations.
- The `handleLanguageChange` function updates both the i18n library's current language and the component's internal state.
- An effect hook is used to listen for changes in the i18n locale, updating the component's state accordingly.
- A `<select>` element allows users to choose a language from a list of available locales. The selected option updates the page language using i18n.
- Error handling is included in case of issues changing the language, such as missing translations or unsupported languages.
