// LanguageContext.js

class LanguageContext {
  constructor() {
    this.locale = 'en'; // Default locale
    this.translations = {}; // Placeholder for translations
    this.initializeTranslations();
  }

  /**
   * Sets a new language and updates translations if available.
   * @param {string} lang - The language code (e.g., 'fr', 'es')
   */
  setLanguage(lang) {
    const supportedLangs = ['en', 'fr', 'es']; // Supported languages
    if (supportedLangs.includes(lang)) {
      this.locale = lang;
      this.initializeTranslations();
    } else {
      console.error(`Unsupported language: ${lang}`);
    }
  }

  /**
   * Initializes translations based on the current locale.
   */
  initializeTranslations() {
    const translationFileUrl = `/translations/${this.locale}.json`;
    fetch(translationFileUrl)
      .then(response => response.json())
      .then(data => {
        this.translations = data;
        console.log(`Loaded translations for ${this.locale}`);
      })
      .catch(error => {
        console.error(`Error loading translations for ${this.locale}:`, error);
      });
  }

  /**
   * Translates a key from the current locale's translation file.
   * @param {string} key - The key to translate
   * @returns {string} - The translated string or the original key if not found
   */
  t(key) {
    return this.translations[key] || key;
  }
}

// Usage example:
const context = new LanguageContext();
context.setLanguage('fr'); // Switches to French
console.log(context.t('hello')); // Outputs: Bonjour
