const LocaleUtils = (() => {
  const translations = new Map();

  // Function to load locale data into the translations map
  function loadLocaleData(locale, data) {
    if (!translations.has(locale)) {
      translations.set(locale, data);
    } else {
      console.error(`Locale ${locale} already exists.`);
    }
  }

  // Function to get a localized string for a given key and locale
  function getString(key, locale = 'en-US') {
    if (translations.has(locale) && translations.get(locale).hasOwnProperty(key)) {
      return translations.get(locale)[key];
    } else {
      console.error(`Locale ${locale} or key ${key} not found.`);
      return `Translation for ${key} not available in ${locale}.`;
    }
  }

  // Function to get a localized array of strings
  function getStrings(keys, locale = 'en-US') {
    const result = [];
    keys.forEach(key => {
      const translation = getString(key, locale);
      if (translation) {
        result.push(translation);
      } else {
        result.push(`Translation for ${key} not available in ${locale}.`);
      }
    });
    return result;
  }

  // Function to check if a specific key exists for a given locale
  function hasKey(key, locale = 'en-US') {
    return translations.has(locale) && translations.get(locale).hasOwnProperty(key);
  }

  // Function to add new keys or update existing keys in the locale data
  function setLocaleData(locale, key, value) {
    if (translations.has(locale)) {
      translations.get(locale)[key] = value;
    } else {
      loadLocaleData(locale, { [key]: value });
    }
  }

  // Exporting functions
  return {
    loadLocaleData,
    getString,
    getStrings,
    hasKey,
    setLocaleData
  };
})();

export default LocaleUtils;
```

