import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';

// Initialize i18n with your desired locale and translation files
i18n.use(initReactI18next).init({
  lng: localStorage.getItem('locale') || 'en',
  resources: {
    en: {
      translation: {
        WELCOME: "Welcome to the multi-language site!",
        LANGUAGE_SELECT: "Select language",
        CHANGE_LANGUAGE: "Change Language"
      }
    },
    es: {
      translation: {
        WELCOME: "¡Bienvenido a la página web multilinguista!",
        LANGUAGE_SELECT: "Selecciona idioma",
        CHANGE_LANGUAGE: "Cambiar Idioma"
      }
    }
  }
});

function App() {
  // Use the i18n hook to access the t function for translations
  const { t } = useTranslation();

  // State to manage the current language
  const [currentLanguage, setCurrentLanguage] = useState(i18n.language);

  // Function to handle language change
  const handleChangeLanguage = (language) => {
    i18n.changeLanguage(language);
    localStorage.setItem('locale', language);
    setCurrentLanguage(language);
  };

  useEffect(() => {
    // Optional: Load additional translations if needed
    // Here you could fetch a new set of resources based on the current language
  }, [currentLanguage]);

  return (
    <div className="App">
      {/* Display the welcome message */}
      <h1>{t('WELCOME')}</h1>

      {/* Language select dropdown */}
      <select value={currentLanguage} onChange={(e) => handleChangeLanguage(e.target.value)}>
        <option value="en">English</option>
        <option value="es">Spanish</option>
      </select>

      {/* Change language button */}
      <button onClick={() => handleChangeLanguage(currentLanguage === 'en' ? 'es' : 'en')}>
        {t('CHANGE_LANGUAGE')}
      </button>
    </div>
  );
}

export default App;
