import React, { useState, useEffect, useContext } from 'react';
import { useTranslation } from 'react-i18next';

// Context to hold locale data
const LocaleContext = React.createContext();

function Custom404Page() {
  // Use context for language and locale files
  const { t } = useTranslation('common');

  // State to manage the locale
  const [locale, setLocale] = useState(() => {
    const storedLocale = localStorage.getItem('locale');
    return storedLocale || 'en';
  });

  useEffect(() => {
    // Update the document title with current language
    document.title = t('404.pageTitle');

    // Fetch locale files and update context
    fetch(`/locales/${locale}.json`)
      .then(response => response.json())
      .then(data => setLocaleContext(context, data))
      .catch(error => console.error('Error loading locale:', error));
  }, [locale]);

  return (
    <div className="error-page">
      <h1>{t('404.title')}</h1>
      <p>{t('404.description')}</p>
    </div>
  );
}

// Context provider to share the locale data
function LocaleProvider({ children }) {
  const [localeContext, setLocaleContext] = useState({});

  // Update context value when locale changes
  useEffect(() => {
    if (localeContext !== {}) {
      setLocaleContext(localeContext);
    }
  }, [localeContext]);

  return (
    <LocaleContext.Provider value={localeContext}>
      {children}
    </LocaleContext.Provider>
  );
}

export default function App() {
  return (
    <LocaleProvider>
      {/* Wrap the custom 404 page with LocaleProvider */}
      <Custom404Page />
    </LocaleProvider>
  );
}
