import React, { useState, useRef, useEffect } from 'react';
import './DrawCanvasComponent.css';

const DrawCanvasComponent = () => {
  // State to manage drawing color and size
  const [color, setColor] = useState('#000000');
  const [size, setSize] = useState(5);

  // Ref for the canvas element
  const canvasRef = useRef(null);

  useEffect(() => {
    // Initialize the canvas context
    const ctx = canvasRef.current.getContext('2d');

    // Set default drawing properties
    ctx.strokeStyle = color;
    ctx.lineWidth = size;

    // Function to handle mouse move events for drawing
    function draw(e) {
      if (e.buttons === 1) { // Check if left mouse button is pressed
        const rect = canvasRef.current.getBoundingClientRect();
        ctx.beginPath();
        ctx.moveTo(e.clientX - rect.left, e.clientY - rect.top);
        ctx.lineTo(e.clientX - rect.left + e.offsetX, e.clientY - rect.top + e.offsetY);
        ctx.stroke();
      }
    }

    // Add event listener for mouse move
    canvasRef.current.addEventListener('mousemove', draw);

    return () => {
      // Clean up the event listener when component unmounts
      canvasRef.current.removeEventListener('mousemove', draw);
    };
  }, [color, size]);

  const handleColorChange = (e) => setColor(e.target.value);
  const handleSizeChange = (e) => setSize(Number(e.target.value));

  return (
    <div className="draw-canvas-container">
      <canvas
        ref={canvasRef}
        width="500"
        height="500"
        style={{ border: '1px solid #ccc' }}
      />
      <div className="controls">
        <label>Color:</label>
        <input
          type="color"
          value={color}
          onChange={handleColorChange}
        />
        <br />
        <label>Size:</label>
        <input
          type="range"
          min="1"
          max="20"
          value={size}
          onChange={handleSizeChange}
        />
      </div>
    </div>
  );
};

export default DrawCanvasComponent;
