/**
 * Utility class to manage canvas references.
 */
class CanvasRefManager {
    private canvasRefs: any = {};

    /**
     * Set a canvas reference by name.
     * @param name - The unique identifier for the canvas.
     * @param ref - The actual HTML5 Canvas reference object.
     */
    setCanvasRef(name: string, ref: React.RefObject<HTMLCanvasElement>) {
        if (!ref.current) {
            throw new Error(`Canvas with name ${name} has no current value.`);
        }
        this.canvasRefs[name] = ref;
    }

    /**
     * Get a canvas reference by its name.
     * @param name - The unique identifier for the canvas.
     * @returns The HTML5 Canvas reference object if found, otherwise null.
     */
    getCanvasRef(name: string): React.RefObject<HTMLCanvasElement> | null {
        return this.canvasRefs[name];
    }

    /**
     * Clear all stored canvas references.
     */
    clear() {
        this.canvasRefs = {};
    }
}

/**
 * Hook to manage canvas references within a React component.
 * @param refs - An array of objects containing name and ref properties.
 * @returns A single CanvasRefManager instance for the component.
 */
function useCanvasRef(...refs: { name: string, ref: React.RefObject<HTMLCanvasElement> }[]): CanvasRefManager {
    const canvasRefManager = useRef(new CanvasRefManager());

    refs.forEach(ref => {
        if (ref.name) {
            canvasRefManager.current.setCanvasRef(ref.name, ref.ref);
        }
    });

    return canvasRefManager.current;
}

export { useCanvasRef };
