import React, { createContext, useState, useEffect } from 'react';

// Create a context object for drawing canvas state
const DrawingContext = createContext();

// Provider component to manage drawing context state
export const DrawingProvider = ({ children }) => {
  // State for canvas dimensions and drawing state
  const [canvasWidth, setCanvasWidth] = useState(400);
  const [canvasHeight, setCanvasHeight] = useState(300);
  const [currentStrokeColor, setCurrentStrokeColor] = useState('#000000');
  const [isDrawing, setIsDrawing] = useState(false);

  // Reference to the canvas element
  const canvasRef = useRef(null);

  useEffect(() => {
    if (canvasRef.current) {
      const context = canvasRef.current.getContext('2d');

      // Set initial drawing style
      context.strokeStyle = currentStrokeColor;
      context.lineWidth = 5;

      // Handle mouse down event to start drawing
      const handleMouseDown = (event) => {
        setIsDrawing(true);
        context.beginPath();
        context.moveTo(event.clientX - canvasRef.current.offsetLeft, event.clientY - canvasRef.current.offsetTop);
      };

      // Handle mouse move event to draw while dragging
      const handleMouseMove = (event) => {
        if (isDrawing) {
          context.lineTo(event.clientX - canvasRef.current.offsetLeft, event.clientY - canvasRef.current.offsetTop);
          context.stroke();
        }
      };

      // Handle mouse up event to stop drawing
      const handleMouseUp = () => {
        setIsDrawing(false);
      };

      // Add event listeners
      document.addEventListener('mousedown', handleMouseDown);
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);

      // Clean up event listeners on component unmount
      return () => {
        document.removeEventListener('mousedown', handleMouseDown);
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
      };
    }
  }, [currentStrokeColor, isDrawing]);

  // Function to clear the canvas
  const clearCanvas = () => {
    if (canvasRef.current) {
      const context = canvasRef.current.getContext('2d');
      context.clearRect(0, 0, canvasWidth, canvasHeight);
    }
  };

  return (
    <DrawingContext.Provider
      value={{
        canvasWidth,
        setCanvasWidth,
        canvasHeight,
        setCanvasHeight,
        currentStrokeColor,
        setCurrentStrokeColor,
        isDrawing,
        setIsDrawing,
        clearCanvas,
      }}
    >
      {children}
    </DrawingContext.Provider>
  );
};

// Custom hook to use the drawing context
export const useDrawingContext = () => useContext(DrawingContext);
