// DrawingAPI.js

import { useRef, useEffect } from 'react';

class CanvasUtil {
  constructor(canvasRef) {
    this.canvas = canvasRef.current;
    this.ctx = this.canvas.getContext('2d');
    if (!this.ctx) {
      throw new Error('Failed to get the 2D context of the canvas.');
    }
  }

  clearCanvas() {
    this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);
  }

  drawLine(startX, startY, endX, endY, color = 'black', lineWidth = 1) {
    if (!this.ctx) throw new Error('Context not available.');
    this.ctx.beginPath();
    this.ctx.strokeStyle = color;
    this.ctx.lineWidth = lineWidth;
    this.ctx.moveTo(startX, startY);
    this.ctx.lineTo(endX, endY);
    this.ctx.stroke();
  }

  drawCircle(x, y, radius, color = 'black', lineWidth = 1) {
    if (!this.ctx) throw new Error('Context not available.');
    this.ctx.beginPath();
    this.ctx.arc(x, y, radius, 0, Math.PI * 2);
    this.ctx.strokeStyle = color;
    this.ctx.lineWidth = lineWidth;
    this.ctx.stroke();
  }

  drawText(text, x, y, color = 'black', fontSize = '16px') {
    if (!this.ctx) throw new Error('Context not available.');
    this.ctx.font = `${fontSize} Arial`;
    this.ctx.fillStyle = color;
    this.ctx.fillText(text, x, y);
  }

  saveCanvas() {
    const mimeType = 'image/png';
    const canvasDataUrl = this.canvas.toDataURL(mimeType);

    const link = document.createElement('a');
    link.href = canvasDataUrl;
    link.download = `drawing_${Date.now()}.png`;
    link.click();
  }
}

export default function DrawingAPI(canvasRef) {
  useEffect(() => {
    if (!canvasRef.current) return;

    const canvasUtil = new CanvasUtil(canvasRef);
    const handleDrawStart = (event) => {
      canvasUtil.ctx.beginPath();
      canvasUtil.ctx.moveTo(event.offsetX, event.offsetY);
    };

    const handleDrawMove = (event) => {
      canvasUtil.ctx.lineTo(event.offsetX, event.offsetY);
      canvasUtil.ctx.stroke();
    };

    const handleDrawEnd = () => {
      canvasUtil.ctx.closePath();
    };

    document.addEventListener('mousedown', handleDrawStart);
    document.addEventListener('mousemove', handleDrawMove);
    document.addEventListener('mouseup', handleDrawEnd);

    return () => {
      document.removeEventListener('mousedown', handleDrawStart);
      document.removeEventListener('mousemove', handleDrawMove);
      document.removeEventListener('mouseup', handleDrawEnd);
    };
  }, [canvasRef]);

  const clearCanvas = () => canvasUtil.clearCanvas();
  const drawLine = (startX, startY, endX, endY) => {
    canvasUtil.drawLine(startX, startY, endX, endY);
  };
  const drawCircle = (x, y, radius) => canvasUtil.drawCircle(x, y, radius);
  const drawText = (text, x, y) => canvasUtil.drawText(text, x, y);
  const saveCanvas = () => canvasUtil.saveCanvas();

  return {
    clearCanvas,
    drawLine,
    drawCircle,
    drawText,
    saveCanvas,
  };
}
