// CanvasEventsHandler.js

import { useRef, useEffect } from 'react';

/**
 * Handles mouse events on a canvas element.
 * @param {HTMLElement} ref - A React ref to the HTML5 canvas element.
 * @param {Function} onMouseDown - Callback function for mouse down event.
 * @param {Function} onMouseMove - Callback function for mouse move event.
 * @param {Function} onMouseUp - Callback function for mouse up event.
 */
export const useCanvasEvents = (
  ref,
  onMouseDown = () => {},
  onMouseMove = () => {},
  onMouseUp = () => {}
) => {
  if (!ref.current) {
    console.warn('useCanvasEvents: The canvas element is not mounted yet.');
    return;
  }

  useEffect(() => {
    const handleMouseDown = (event) => {
      onMouseDown(event, ref);
    };

    const handleMouseMove = (event) => {
      onMouseMove(event, ref);
    };

    const handleMouseUp = () => {
      onMouseUp({}, ref);
    };

    // Add event listeners
    ref.current.addEventListener('mousedown', handleMouseDown);
    ref.current.addEventListener('mousemove', handleMouseMove);
    ref.current.addEventListener('mouseup', handleMouseUp);

    return () => {
      // Remove event listeners on unmount to avoid memory leaks
      ref.current.removeEventListener('mousedown', handleMouseDown);
      ref.current.removeEventListener('mousemove', handleMouseMove);
      ref.current.removeEventListener('mouseup', handleMouseUp);
    };
  }, [ref, onMouseDown, onMouseMove, onMouseUp]);
};

