// watcher.js

const express = require('express');
const WebSocket = require('ws');
const { Client } = require('pg'); // PostgreSQL database client

const app = express();
app.use(express.json());

const wss = new WebSocket.Server({ port: 8080 });

// Database connection configuration
const dbConfig = {
  user: 'your_db_user',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
};

const client = new Client(dbConfig);

async function fetchMarketData() {
  try {
    await client.connect();
    const queryResult = await client.query('SELECT * FROM stock_data');
    return queryResult.rows;
  } catch (error) {
    console.error('Error fetching market data:', error);
    throw error;
  } finally {
    await client.end();
  }
}

async function sendMarketDataToClients() {
  try {
    const marketData = await fetchMarketData();
    wss.clients.forEach(client => {
      if (client.readyState === WebSocket.OPEN) {
        client.send(JSON.stringify(marketData));
      }
    });
  } catch (error) {
    console.error('Error sending market data to clients:', error);
  }
}

// Start the WebSocket server and send initial data
wss.on('connection', () => {
  console.log('Client connected');
  setTimeout(() => sendMarketDataToClients(), 1000); // Send data every second
});

// Schedule regular updates
setInterval(sendMarketDataToClients, 5000);

// Start the Express server
app.listen(3000, () => {
  console.log('Stock Market Watcher is running on port 3000');
});
