import React, { useState, useEffect } from 'react';
import { SocketContext } from './SocketProvider'; // Assuming there's a context for WebSocket

const DataHandler = () => {
  const [data, setData] = useState(null);
  const [error, setError] = useState(null);

  // Use useContext to access the global socket connection
  const { socket } = React.useContext(SocketContext);

  useEffect(() => {
    if (socket) {
      // Subscribe to real-time data updates
      socket.on('data', handleNewData);
    }

    return () => {
      // Clean up on component unmount
      if (socket) {
        socket.off('data', handleNewData);
      }
    };
  }, [socket]);

  const handleNewData = (newData) => {
    setData(newData);
  };

  const handleError = (err) => {
    setError(err);
  };

  useEffect(() => {
    // Handle any errors from the WebSocket connection
    socket.on('error', handleError);

    return () => {
      if (socket) {
        socket.off('error', handleError);
      }
    };
  }, [socket]);

  return (
    <div>
      {data && <pre>{JSON.stringify(data, null, 2)}</pre>}
      {error && <p>Error: {error.message}</p>}
    </div>
  );
};

export default DataHandler;
