<?php

// Set up database connection
require_once 'db.php';

// Function to sanitize input
function sanitizeInput($input) {
    return htmlspecialchars(trim($input), ENT_QUOTES, 'UTF-8');
}

// Register REST API routes
add_action('rest_api_init', function() {
    register_rest_route('stock/v1', '/ticker/(?P<symbol>[a-zA-Z0-9]+)', [
        'methods' => 'GET',
        'callback' => 'get_stock_data'
    ]);
});

// Callback function to get stock data
function get_stock_data($request) {
    $symbol = sanitizeInput($request['symbol']);

    // Sanitize and validate the symbol
    if (!preg_match('/^[a-zA-Z0-9]+$/', $symbol)) {
        return new WP_Error('invalid_symbol', 'Invalid stock symbol.', ['status' => 400]);
    }

    try {
        // Prepare SQL query
        $stmt = $GLOBALS['wpdb']->prepare("SELECT * FROM stocks WHERE symbol = %s", [$symbol]);

        // Execute the query and get results
        $result = $GLOBALS['wpdb']->get_row($stmt);

        if (!$result) {
            return new WP_Error('stock_not_found', 'Stock not found.', ['status' => 404]);
        }

        // Return stock data in JSON format
        return rest_ensure_response([
            'symbol' => $result->symbol,
            'price' => $result->price,
            'change' => $result->change,
            'percent_change' => $result->percent_change,
            'volume' => $result->volume
        ]);

    } catch (Exception $e) {
        // Log the error and return a generic error message
        error_log($e->getMessage());
        return new WP_Error('internal_server_error', 'Internal server error.', ['status' => 500]);
    }
}
