// utils.js - Utility functions for the Stock Market Watcher

const WebSocket = require('ws'); // Importing WebSockets module

/**
 * Function to connect to a WebSocket server
 * @param {string} url - The URL of the WebSocket server
 * @returns {WebSocket} The connected WebSocket object
 */
function connectToWebSocket(url) {
    const socket = new WebSocket(url);
    return socket;
}

/**
 * Function to handle incoming messages from the WebSocket connection
 * @param {WebSocket} ws - The WebSocket object
 * @param {Function} callback - Callback function to process incoming data
 */
function onMessage(ws, callback) {
    ws.on('message', (data) => {
        callback(data);
    });
}

/**
 * Function to handle errors in the WebSocket connection
 * @param {WebSocket} ws - The WebSocket object
 * @param {Function} errorHandler - Error handling function
 */
function onError(ws, errorHandler) {
    ws.onerror = (error) => {
        errorHandler(error);
    };
}

/**
 * Function to handle WebSocket connection close events
 * @param {WebSocket} ws - The WebSocket object
 * @param {Function} handleClose - Close event handler function
 */
function onClose(ws, handleClose) {
    ws.on('close', () => {
        handleClose();
    });
}

module.exports = {
    connectToWebSocket,
    onMessage,
    onError,
    onClose
};
