import React, { useState, useEffect, useContext } from 'react';
import ErrorAlertContext from './ErrorAlertContext'; // Assuming this context is used to manage error alerts

// Define the AppErrorBoundary component
function AppErrorBoundary({ children }) {
  const [error, setError] = useState(null);
  const [isErrorHandled, setIsErrorHandled] = useState(false);

  // Context to access error alerts
  const { addErrorAlert } = useContext(ErrorAlertContext);

  useEffect(() => {
    if (error && !isErrorHandled) {
      addErrorAlert({ message: 'An error occurred. Please try again.', severity: 'error' });
      setError(null);
      setIsErrorHandled(true); // Flag to handle the error once
    }
  }, [error, isErrorHandled, addErrorAlert]);

  const handleError = (err) => {
    console.error('Uncaught error:', err);
    setError(err);
  };

  return (
    <div onUnhandledRejection={handleError} onError={handleError}>
      {error ? (
        <div className="error-boundary">
          <h1>Error occurred</h1>
          <p>{error.message}</p>
          {/* Add more error handling logic here if needed */}
        </div>
      ) : (
        children
      )}
    </div>
  );
}

export default AppErrorBoundary;
