// ErrorHandler.js

/**
 * This module provides utility functions to handle errors globally in an application.
 */

class ErrorHandler {
  constructor() {
    // Initialize error handling state
  }

  /**
   * Logs an error message to console and optionally sends it to a centralized logging service.
   * @param {Error} error - The error object to be logged or sent for analysis.
   */
  logError(error) {
    console.error('An error occurred:', error);
    // Implement logic to send the error to a logging service if needed
  }

  /**
   * Handles errors thrown in components and provides an error boundary mechanism.
   * @param {React.Component} Component - The component to wrap with error handling.
   * @returns {React.Component} Wrapped component that includes error handling logic.
   */
  wrapWithErrorBoundary(Component) {
    return class ErrorBoundary extends React.Component {
      static getDerivedStateFromError(error) {
        this.setState({ hasError: true, error });
        // Handle the error state here if needed
        return { hasError: true };
      }

      componentDidCatch(error, errorInfo) {
        this.logError(error);
        console.error('Error caught in ErrorBoundary:', errorInfo);
        // Optionally log component stack trace for debugging purposes
      }

      render() {
        const { hasError, error } = this.state;
        if (hasError) {
          return (
            <div>
              <h1>Something went wrong</h1>
              <p>{error.message}</p>
              {/* Add more UI elements to display error details or provide alternative content */}
            </div>
          );
        }
        return <Component {...this.props} />;
      }
    };
  }

  /**
   * Handles errors during API requests and provides a generic error message.
   * @param {Promise} promise - The promise returned by an API call.
   * @returns {Promise} A promise that resolves to the data or rejects with a generic error message.
   */
  handleAPIError(promise) {
    return promise.catch(error => {
      this.logError(error);
      return Promise.reject('An error occurred while fetching data.');
    });
  }
}

export default new ErrorHandler();
