const express = require('express');
const bcrypt = require('bcryptjs'); // For password hashing

// Initialize Express app
const app = express();
app.use(express.json()); // Middleware to parse JSON bodies

// In-memory database for demonstration purposes
let users = [
  { id: 1, username: 'user1', password: 'password' }
];

// Hashing function (async)
const hashPassword = async (password) => {
  return await bcrypt.hash(password, 10);
};

// Middleware to handle user login (async/await)
const authenticateUser = async (req, res) => {
  const { username, password } = req.body;
  const user = users.find(u => u.username === username);

  if (!user || !bcrypt.compareSync(password, user.password)) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  // Set a session or token for authentication
  // Here we're just using a simple in-memory check
  req.session = { userId: user.id };
  res.json({ message: 'Login successful', user });
};

// Middleware to require authentication (async/await)
const requireAuth = async (req, res, next) => {
  if (!req.session || !req.session.userId) {
    return res.status(401).json({ error: 'Unauthorized' });
  }

  try {
    const user = users.find(u => u.id === req.session.userId);
    if (!user) {
      throw new Error('User not found');
    }
    next(); // Proceed to the next middleware/route
  } catch (error) {
    res.status(500).json({ error: 'Authentication failed' });
  }
};

// Example route that requires authentication
app.get('/protected', requireAuth, (req, res) => {
  res.json({ message: 'You accessed a protected route!' });
});

// Error handling middleware (asynchronous)
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).json({ error: 'Internal Server Error' });
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});
