// errorTrackingService.js

/**
 * Utility service for tracking and reporting errors.
 */

class ErrorTrackingService {
  // Function to handle unhandled promise rejections globally
  static async handleUncaughtPromiseRejection(error) {
    console.error('Unhandled Promise Rejection:', error);
    this.reportError(error);
  }

  // Function to report errors via a custom API
  static async reportError(error, context = {}) {
    const { message, stack, name } = error;
    const payload = {
      message,
      stack,
      name,
      ...context,
    };

    try {
      await fetch('/api/report-error', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(payload),
      });
      console.log('Error reported successfully:', payload);
    } catch (reportingError) {
      console.error('Failed to report error:', reportingError);
    }
  }

  // Function to capture errors within component life cycles
  static wrapComponentWithErrorTracking(Component) {
    return class WrappedComponent extends Component {
      componentDidMount() {
        window.addEventListener('error', this.handleUnexpectedError.bind(this));
      }

      componentWillUnmount() {
        window.removeEventListener('error', this.handleUnexpectedError.bind(this));
      }

      handleUnexpectedError(errorEvent) {
        const { message, stack } = errorEvent.error;
        console.error('Component Error:', message, stack);
        ErrorTrackingService.reportError(new Error(message), { component: this.constructor.name });
        errorEvent.preventDefault();
      }
    };
  }
}

export { ErrorTrackingService };
```

**Explanation**: The `ErrorTrackingService` class provides utility functions to handle unhandled promise rejections and report errors via a custom API. It also includes a method to wrap components with error tracking, capturing errors in component life cycles and reporting them.
