// utils/treeDataGenerator.js

/**
 * Utility function to generate sample tree data.
 *
 * @param {number} depth - The depth of the tree.
 * @param {string} [name] - The name of the root node.
 * @returns {Array<Object>} - An array representing a tree structure.
 */

function generateTreeData(depth, name = 'Root') {
  // Check if the input values are valid
  if (typeof depth !== 'number' || depth <= 0) {
    throw new Error('Depth must be a positive integer.');
  }

  const nodes = [];

  for (let i = 0; i < depth; i++) {
    nodes.push({
      id: Math.random().toString(36).substring(2, 8),
      name,
      children: generateTreeData(depth - 1)
    });
  }

  return nodes;
}

// Export the function
module.exports = { generateTreeData };
