    try {
        const data = await db.query('SELECT * FROM tree_view');
        res.status(200).json(data.rows);
    } catch (error) {
        console.error(error);
        res.status(500).send('Server error');
    }
});

/**
 * POST /api/tree-view
 * Create a new node in the tree view.
 */
router.post('/tree-view', async (req, res) => {
    try {
        const { name, parent_id } = req.body;
        if (!name || !parent_id) {
            return res.status(400).send('Name and parent_id are required');
        }

        await db.query('INSERT INTO tree_view (name, parent_id) VALUES ($1, $2)', [name, parent_id]);
        res.status(201).send('Node created successfully');
    } catch (error) {
        console.error(error);
        res.status(500).send('Server error');
    }
});

/**
 * PUT /api/tree-view/:id
 * Update an existing node in the tree view.
 */
router.put('/tree-view/:id', async (req, res) => {
    try {
        const { name } = req.body;
        if (!name) {
            return res.status(400).send('Name is required');
        }

        await db.query('UPDATE tree_view SET name = $1 WHERE id = $2', [name, req.params.id]);
        res.status(200).send('Node updated successfully');
    } catch (error) {
        console.error(error);
        res.status(500).send('Server error');
