import React, { useState, useEffect } from 'react';

// Define a context for sharing calendar data between components
const CalendarContext = React.createContext();

function CalendarBookingSystem() {
  const [selectedDates, setSelectedDates] = useState([]);
  const [availableDates, setAvailableDates] = useState([]);

  // Fetch the available dates based on the current month/year
  useEffect(() => {
    fetch('https://api.example.com/calendar/dates')
      .then(response => response.json())
      .then(data => setAvailableDates(data))
      .catch(error => console.error('Error fetching available dates:', error));
  }, []);

  // Handle date selection changes
  const handleDateSelect = (date) => {
    if (!selectedDates.includes(date)) {
      setSelectedDates([...selectedDates, date]);
    } else {
      setSelectedDates(selectedDates.filter(d => d !== date));
    }
  };

  return (
    <CalendarContext.Provider value={{ selectedDates, availableDates }}>
      <div>
        <h1>Calendar Booking System</h1>
        <DatePicker onSelect={handleDateSelect} />
        {selectedDates.length > 0 && (
          <ul>
            {selectedDates.map(date => <li key={date}>{date}</li>)}
          </ul>
        )}
      </div>
    </CalendarContext.Provider>
  );
}

function DatePicker({ onSelect }) {
  const today = new Date();
  const [date, setDate] = useState(today);

  // Create an array of dates for the current month
  const daysInMonth = [];
  for (let i = 1; i <= Math.floor(new Date(date.getFullYear(), date.getMonth() + 1, 0).getDate()); i++) {
    daysInMonth.push(new Date(date.getFullYear(), date.getMonth(), i));
  }

  // Handle date navigation
  const handlePrevMonth = () => setDate(prevDate => new Date(prevDate.getFullYear(), prevDate.getMonth() - 1, 1));
  const handleNextMonth = () => setDate(prevDate => new Date(prevDate.getFullYear(), prevDate.getMonth() + 1, 1));

  return (
    <div style={{ marginBottom: '20px' }}>
      <h2>Available Dates</h2>
      <button onClick={handlePrevMonth}>Previous Month</button>
      <span>{date.toLocaleString('default', { month: 'long', year: 'numeric' })}</span>
      <button onClick={handleNextMonth}>Next Month</button>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(7, 50px)', gap: '2px' }}>
        <div></div> {/* Days of the week */}
        {daysInMonth.map(day => (
          <div
            key={day.toISOString()}
            style={{
              cursor: availableDates.includes(day) ? 'pointer' : 'not-allowed',
              color: selectedDates.includes(day) ? 'red' : availableDates.includes(day) ? 'black' : 'gray'
            }}
            onClick={() => onSelect(day)}
          >
            {day.getDate()}
          </div>
        ))}
      </div>
    </div>
  );
}

export default CalendarBookingSystem;
