<?php

namespace App\Http\Controllers;

use Illuminate\Http\Request;
use Illuminate\Support\Facades\DB;
use Illuminate\Database\QueryException;

class APIRoutes extends Controller
{
    /**
     * Register all routes related to calendar booking.
     *
     * @return void
     */
    public function register()
    {
        // Define the base route for calendar operations
        Route::group(['prefix' => 'calendar'], function () {
            // Route to get all available dates in a month
            Route::get('/dates', [CalendarController::class, 'getAvailableDates']);
        });
