namespace App\Http\Controllers\Api;

use Illuminate\Support\Facades\DB;
use Illuminate\Support\Facades\Validator;
use Illuminate\Database\QueryException;

class CalendarController extends Controller
{
    /**
     * Get all available dates in a month.
     *
     * @param  Request  $request
     * @return \Illuminate\Http\Response
     */
    public function getAvailableDates(Request $request)
    {
        // Validate the input parameters
        $validator = Validator::make($request->all(), [
            'year' => ['required', 'integer'],
            'month' => ['required', 'integer']
        ]);

        if ($validator->fails()) {
            return response()->json(['error' => $validator->errors()], 400);
        }

        // Get the current year and month
        $year = $request->input('year');
        $month = $request->input('month');

        try {
            // Prepare the query to get available dates in the specified month and year
            $query = DB::table('bookings')
                ->select('date')
                ->whereYear('date', '=', $year)
                ->whereMonth('date', '=', $month)
                ->distinct()
                ->get();

            return response()->json($query->toArray());
        } catch (QueryException $e) {
            // Log the error and return a generic error message
            \Log::error('Error fetching available dates: ' . $e->getMessage());

            return response()->json(['error' => 'An error occurred while fetching dates'], 500);
        }
    }
}
