    constructor() {}

    // Function to populate array based on date logic
    populateDateArray(startDate, endDate) {
        const result = [];
        const currentDate = new Date(startDate);

        while (currentDate <= endDate) {
            // Add specific logic for each day's population
            if (this.isWeekend(currentDate)) {
                result.push({ date: currentDate.toISOString().split('T')[0], type: 'Weekend' });
            } else {
                result.push({ date: currentDate.toISOString().split('T')[0], type: 'Workday' });
            }

            // Increment to the next day
            currentDate.setDate(currentDate.getDate() + 1);
        }

        return result;
    }

    // Helper function to determine if a day is weekend
    isWeekend(date) {
        const day = date.getDay();
        // 0 (Sunday) and 6 (Saturday) are considered weekends
        return day === 0 || day === 6;
    }
}

