// BookingSystem.js

class BookingSystem {
  constructor() {
    this.bookings = []; // Array to store all booking records
  }

  addBooking(date, time) {
    // Add a new booking with date and time
    if (this.isDateValid(date)) {
      this.bookings.push({ date, time });
      console.log(`Booking added for ${date} at ${time}`);
    } else {
      console.error('Invalid date format. Please use YYYY-MM-DD');
    }
  }

  removeBooking(date, time) {
    // Remove a booking by date and time
    const index = this.bookings.findIndex(booking => 
      booking.date === date && booking.time === time);
    if (index !== -1) {
      this.bookings.splice(index, 1);
      console.log(`Booking removed for ${date} at ${time}`);
    } else {
      console.error('Booking not found');
    }
  }

  listBookings() {
    // List all bookings
    if (this.bookings.length > 0) {
      console.table(this.bookings);
    } else {
      console.log('No bookings available');
    }
  }

  isDateValid(date) {
    // Validate date format YYYY-MM-DD
    const regex = /^\d{4}-\d{2}-\d{2}$/;
    return regex.test(date);
  }
}

module.exports = BookingSystem;
