<?php

namespace App\Http\Controllers;

use Illuminate\Support\Facades\DB;
use Illuminate\Http\Request;
use Illuminate\Support\Facades\Validator;

class CalendarBookingController extends Controller
{
    /**
     * Store a new booking.
     *
     * @param \Illuminate\Http\Request $request
     * @return \Illuminate\Http\Response
     */
    public function store(Request $request)
    {
        // Validate input data
        $validator = Validator::make($request->all(), [
            'date' => 'required|date',
            'time' => 'required|string|max:255',
            'duration' => 'required|integer|min:1',
            'description' => 'nullable|string|max:2048',
        ]);

        if ($validator->fails()) {
            return response()->json(['errors' => $validator->errors()], 400);
        }

        // Sanitize inputs
        $date = $request->input('date');
        $time = $request->input('time');
        $duration = (int)$request->input('duration');
        $description = $request->input('description');

        // Prepare database query for inserting booking
        DB::beginTransaction();
        try {
            $bookingId = DB::table('bookings')->insertGetId([
                'date' => $date,
                'time' => $time,
                'duration' => $duration,
                'description' => $description
            ]);

            // Commit transaction if booking is successfully inserted
            DB::commit();

            return response()->json(['booking_id' => $bookingId], 201);
        } catch (\Exception $e) {
            // Rollback transaction in case of error
            DB::rollBack();
            return response()->json(['error' => 'Failed to create booking'], 500);
        }
    }

    /**
     * Retrieve all bookings.
     *
     * @return \Illuminate\Http\Response
     */
    public function index()
    {
        // Query all bookings from the database
        $bookings = DB::table('bookings')->get();

        return response()->json($bookings, 200);
    }

    /**
     * Update an existing booking.
     *
     * @param \Illuminate\Http\Request $request
     * @param int $id
     * @return \Illuminate\Http\Response
     */
    public function update(Request $request, $id)
    {
        // Validate input data
        $validator = Validator::make($request->all(), [
            'date' => 'nullable|date',
            'time' => 'nullable|string|max:255',
            'duration' => 'nullable|integer|min:1',
            'description' => 'nullable|string|max:2048',
        ]);

        if ($validator->fails()) {
            return response()->json(['errors' => $validator->errors()], 400);
        }

        // Sanitize inputs
        $date = $request->input('date');
        $time = $request->input('time');
        $duration = (int)$request->input('duration');
        $description = $request->input('description');

        // Prepare database query for updating booking
        DB::beginTransaction();
        try {
            $updatedRows = DB::table('bookings')->where('id', $id)->update([
                'date' => $date,
                'time' => $time,
                'duration' => $duration,
                'description' => $description
            ]);

            // Commit transaction if booking is successfully updated
            DB::commit();

            return response()->json(['updated_rows' => $updatedRows], 200);
        } catch (\Exception $e) {
            // Rollback transaction in case of error
            DB::rollBack();
            return response()->json(['error' => 'Failed to update booking'], 500);
        }
    }

    /**
     * Delete a booking.
     *
     * @param int $id
     * @return \Illuminate\Http\Response
     */
    public function destroy($id)
    {
        // Prepare database query for deleting booking
        DB::beginTransaction();
        try {
            $deletedRows = DB::table('bookings')->where('id', $id)->delete();

            // Commit transaction if booking is successfully deleted
            DB::commit();

            return response()->json(['deleted_rows' => $deletedRows], 200);
        } catch (\Exception $e) {
            // Rollback transaction in case of error
            DB::rollBack();
            return response()->json(['error' => 'Failed to delete booking'], 500);
        }
    }
}
