/**
 * Generates an array of dates for a given month and year, including the start day of the week.
 * @param {number} year - The year for the calendar.
 * @param {number} month - The month (1-based index) for the calendar.
 * @returns {Array<Date>} - An array of Date objects representing each day in the specified month and year.
 */
function generateDates(year, month) {
  const firstDayOfMonth = new Date(Date.UTC(year, month - 1, 1));
  const lastDayOfMonth = new Date(Date.UTC(year, month, 0));
  const daysInMonth = (lastDayOfMonth.getUTCDay() || 7) - (firstDayOfMonth.getUTCDay() || 7) + 1;
  const datesArray = [];

  for (let i = 0; i < daysInMonth; i++) {
    datesArray.push(new Date(Date.UTC(year, month - 1, firstDayOfMonth.getUTCDate() + i)));
  }

  return datesArray;
}

/**
 * Calculates the number of weeks in a given year.
 * @param {number} year - The year to calculate the number of weeks for.
 * @returns {number} - The number of weeks in the specified year.
 */
function getNumberOfWeeks(year) {
  const firstDayOfYear = new Date(Date.UTC(year, 0, 1));
  const lastDayOfYear = new Date(Date.UTC(year + 1, 0, 1));
  return Math.ceil((lastDayOfYear - firstDayOfYear) / (24 * 60 * 60 * 1000 * 7)) + 1;
}

