// Define a function to calculate the number of days in a given month and year
function getDaysInMonth(year, month) {
    return new Date(year, month + 1, 0).getDate();
}

// Function to check if two dates are on the same day
function isSameDay(date1, date2) {
    return (
        date1.getFullYear() === date2.getFullYear() &&
        date1.getMonth() === date2.getMonth() &&
        date1.getDate() === date2.getDate()
    );
}

// Function to calculate the difference in days between two dates
function getDaysDifference(date1, date2) {
    const oneDay = 1000 * 60 * 60 * 24;
    return Math.ceil((date2 - date1) / oneDay);
}

// Function to check if a given date is within the range of two other dates
function isDateInRange(date, startDate, endDate) {
    return (
        date >= startDate &&
        date <= endDate
    );
}

// Function to generate a list of all available booking slots for a given date range
function getBookingSlots(startDate, endDate, slotDuration) {
    const slots = [];
    let currentDate = new Date(startDate);

    while (currentDate <= endDate) {
        if (!isDateInRange(currentDate, startDate, endDate)) {
            // Skip dates outside the valid range
            currentDate.setDate(currentDate.getDate() + 1);
            continue;
        }

        for (let i = 0; i < getDaysInMonth(currentDate.getFullYear(), currentDate.getMonth()); i++) {
            const date = new Date(currentDate).setDate(i + 1);

            // Calculate the number of available slots on this day
            let availableSlots = Math.ceil(getDaysDifference(date, endDate) / slotDuration);
            if (availableSlots > 0) {
                slots.push({
                    date: new Date(date),
                    availableSlots: availableSlots,
                    slotDuration: slotDuration
                });
            }
        }

        currentDate.setDate(currentDate.getDate() + 1);
    }

    return slots;
}

