/**
 * Converts a Date object to an ISO string.
 * @param {Date} date - The Date object to convert.
 * @returns {string} The ISO formatted date string.
 */
function formatDateToISO(date) {
  return date.toISOString();
}

/**
 * Adds or subtracts days from a given date.
 * @param {Date} originalDate - The base date.
 * @param {number} daysToAdd - Number of days to add. Negative numbers for subtraction.
 * @returns {Date} The new Date object after adding/subtracting days.
 */
function addDaysToDate(originalDate, daysToAdd) {
  const newDate = new Date(originalDate);
  newDate.setDate(newDate.getDate() + daysToAdd);
  return newDate;
}

/**
 * Generates an array of dates within a specified range.
 * @param {Date} startDate - The starting date.
 * @param {number} daysCount - Number of days in the range.
 * @returns {Array<Date>} An array of Date objects representing the range.
 */
function generateDateRange(startDate, daysCount) {
  const dateArray = [];
  for (let i = 0; i < daysCount; i++) {
    dateArray.push(addDaysToDate(startDate, i));
  }
  return dateArray;
}

/**
 * Checks if two dates are on the same day.
 * @param {Date} date1 - The first Date object.
 * @param {Date} date2 - The second Date object.
 * @returns {boolean} True if the dates are on the same day, false otherwise.
 */
function areDatesSameDay(date1, date2) {
  return (
    date1.getFullYear() === date2.getFullYear() &&
    date1.getMonth() === date2.getMonth() &&
    date1.getDate() === date2.getDate()
  );
}

/**
 * Formats a Date object as 'YYYY-MM-DD'.
 * @param {Date} date - The Date object to format.
 * @returns {string} The formatted date string.
 */
function formatDate(date) {
  return `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
}

