// api.js - API module for Calender Booking System

const axios = require('axios'); // Import Axios for HTTP requests

/**
 * Fetches available booking slots for a given date and location.
 * @param {string} dateString - The date to check for availability (e.g., '2023-10-05').
 * @param {string} location - The location of the event (e.g., 'Conference Hall').
 * @returns {Promise<Array>} A promise resolving to an array of booking slots.
 */
function fetchAvailableSlots(dateString, location) {
  return axios.get(`/api/booking-slots?date=${dateString}&location=${location}`)
    .then(response => response.data)
    .catch(error => {
      console.error('Error fetching available slots:', error);
      throw error;
    });
}

/**
 * Book a slot for a specific user.
 * @param {string} userId - The ID of the user booking.
 * @param {string} dateString - The date of the event (e.g., '2023-10-05').
 * @param {number} slotId - The ID of the slot to book.
 * @returns {Promise<Object>} A promise resolving to the booked slot details.
 */
function bookSlot(userId, dateString, slotId) {
  return axios.post(`/api/bookings`, { userId, date: dateString, slotId })
    .then(response => response.data)
    .catch(error => {
      console.error('Error booking slot:', error);
      throw error;
    });
}

/**
 * Check the availability of a specific date and location.
 * @param {string} dateString - The date to check (e.g., '2023-10-05').
 * @param {string} location - The location of the event (e.g., 'Conference Hall').
 * @returns {Promise<boolean>} A promise resolving to true if available, false otherwise.
 */
function isDateAvailable(dateString, location) {
  return axios.get(`/api/availability?date=${dateString}&location=${location}`)
    .then(response => response.data.available)
    .catch(error => {
      console.error('Error checking date availability:', error);
      throw error;
    });
}

// Export the API functions
module.exports = {
  fetchAvailableSlots,
  bookSlot,
  isDateAvailable
};
