<?php

namespace Blog\Models;

use PDO;
use PDOException;
use App\Exceptions\CommentModelException;

class CommentsModel {
    private $db;

    public function __construct(PDO $db) {
        $this->db = $db;
    }

    /**
     * Insert a new comment into the database.
     *
     * @param int $postId The ID of the post to which the comment belongs.
     * @param string $text The text of the comment.
     * @param int|null $parentId The ID of the parent comment (if this is a reply).
     * @return int|bool The ID of the newly inserted comment, or false on error.
     */
    public function insertComment($postId, $text, $parentId = null) {
        try {
            $sql = "INSERT INTO comments (post_id, text, parent_id, created_at)
                    VALUES (:postId, :text, :parentId, NOW())";

            $stmt = $this->db->prepare($sql);
            $stmt->bindParam(':postId', $postId);
            $stmt->bindParam(':text', $text);
            $stmt->bindParam(':parentId', $parentId);

            if ($stmt->execute()) {
                return $this->db->lastInsertId();
            }
        } catch (PDOException $e) {
            throw new CommentModelException("Error inserting comment: " . $e->getMessage());
        }

        return false;
    }

    /**
     * Retrieve a list of comments for a specific post.
     *
     * @param int $postId The ID of the post.
     * @return array An array of comments, or an empty array on error.
     */
    public function getCommentsForPost($postId) {
        try {
            $sql = "SELECT c.id, c.text, c.created_at,
                       u.username AS author
                    FROM comments c
                    JOIN users u ON c.user_id = u.id
                    WHERE c.post_id = :postId
                    ORDER BY c.created_at";

            $stmt = $this->db->prepare($sql);
            $stmt->bindParam(':postId', $postId);

            if ($stmt->execute()) {
                return $stmt->fetchAll(PDO::FETCH_ASSOC);
            }
        } catch (PDOException $e) {
            throw new CommentModelException("Error retrieving comments: " . $e->getMessage());
        }

        return [];
    }

    /**
     * Update a comment's text.
     *
     * @param int $commentId The ID of the comment to update.
     * @param string $text The new text for the comment.
     * @return bool True if the update was successful, false otherwise.
     */
    public function updateComment($commentId, $text) {
        try {
            $sql = "UPDATE comments
                    SET text = :text
                    WHERE id = :commentId";

            $stmt = $this->db->prepare($sql);
            $stmt->bindParam(':commentId', $commentId);
