            $content = htmlspecialchars(strip_tags(trim($content)));

            // Prepare statement for updating an existing reply
            $stmt = $this->db->prepare("UPDATE replies SET content = ? WHERE id = ?");
            $stmt->bind_param("si", $content, $replyId);

            if ($stmt->execute()) {
                return true;
            } else {
                throw new Exception($stmt->error);
            }
        } catch (Exception $e) {
            echo "Error updating reply: " . $e->getMessage();
            return false;
        }
    }

