    public function deleteReply($replyId) {
        try {
            // Sanitize inputs
            $replyId = filter_var($replyId, FILTER_SANITIZE_NUMBER_INT);

            // Prepare statement for deleting an existing reply
            $stmt = $this->db->prepare("DELETE FROM replies WHERE id = ?");
            $stmt->bind_param("i", $replyId);

            if ($stmt->execute()) {
                return true;
            } else {
                throw new Exception($stmt->error);
            }
        } catch (Exception $e) {
            echo "Error deleting reply: " . $e->getMessage();
            return false;
        }
    }

