            // Prepare statement for fetching replies by comment ID
            $stmt = $this->db->prepare("SELECT * FROM replies WHERE comment_id = ?");
            $stmt->bind_param("i", $commentId);
            $stmt->execute();

            if ($result = $stmt->get_result()) {
                $replies = [];
                while ($row = $result->fetch_assoc()) {
