    public function countByState($state) {
        // Sanitize inputs
        $state = htmlspecialchars(strip_tags($state), ENT_QUOTES);

        try {
            // Prepare and bind parameters
            $stmt = $pdo->prepare("SELECT COUNT(*) FROM replies WHERE state = ?");
            $stmt->execute([$state]);

            // Fetch the count as an integer
            return ['success' => true, 'count' => $stmt->fetchColumn()];
        } catch (\PDOException $e) {
