class NotificationHandler {

    private $db;

    public function __construct() {
        $this->db = new Database();
    }

    public function handleReplyNotification($userId, $commentId) {
        try {
            // Sanitize and validate inputs
            if (!is_int($userId) || !is_int($commentId)) {
                throw new InvalidArgumentException('Invalid user or comment ID');
            }

            // Prepare and bind parameters for the query
            $stmt = $this->db->prepare("SELECT * FROM notifications WHERE user_id = :user_id AND comment_id = :comment_id");
            $stmt->bindParam(':user_id', $userId, PDO::PARAM_INT);
            $stmt->bindParam(':comment_id', $commentId, PDO::PARAM_INT);

            // Execute the query
            $stmt->execute();

            // Check if there are any notifications for this user and comment
            if ($stmt->rowCount() > 0) {
                // Update or create a notification (assuming update is used)
                $this->db->query("UPDATE notifications SET last_notification_date = NOW(), status = 'read' WHERE user_id = :user_id AND comment_id = :comment_id", [
                    ':user_id' => $userId,
                    ':comment_id' => $commentId
                ]);
            } else {
                // Insert a new notification (assuming insert is used)
                $this->db->query("INSERT INTO notifications (user_id, comment_id, last_notification_date, status) VALUES (:user_id, :comment_id, NOW(), 'unread')", [
                    ':user_id' => $userId,
                    ':comment_id' => $commentId
                ]);
            }

        } catch (PDOException $e) {
            // Log the error and return an error response
            error_log($e->getMessage());
            http_response_code(500);
            echo json_encode(['error' => 'An error occurred while handling the notification']);
        }
    }
