// Import necessary libraries
const express = require('express');
const bodyParser = require('body-parser');
const { json } = require('stream');

// Initialize Express application
const app = express();
app.use(bodyParser.json());

// In-memory storage for comments (replace with database in production)
let comments = [];

// API endpoint to create a new comment
app.post('/comments', (req, res) => {
  const { author, text, postId } = req.body;
  if (!author || !text || !postId) return res.status(400).send('Missing required fields');

  const newComment = {
    id: comments.length + 1,
    author,
    text,
    postId,
    replies: [],
    isApproved: false,
  };

  comments.push(newComment);
  res.status(201).send(newComment);
});

// API endpoint to get all comments
app.get('/comments', (req, res) => {
  res.json(comments);
});

// API endpoint to create a reply to an existing comment
app.post('/comments/:commentId/replies', (req, res) => {
  const { commentId } = req.params;
  const { author, text } = req.body;

  const comment = comments.find(c => c.id === parseInt(commentId, 10));
  if (!comment) return res.status(404).send('Comment not found');

  const newReply = {
    id: replies.length + 1,
    author,
    text,
    postId: comment.postId,
    isApproved: false,
  };

  comment.replies.push(newReply);
  res.status(201).send(newReply);
});

// API endpoint to mark a comment as approved
app.patch('/comments/:commentId/approve', (req, res) => {
  const { commentId } = req.params;
  const comment = comments.find(c => c.id === parseInt(commentId, 10));
  if (!comment) return res.status(404).send('Comment not found');

  comment.isApproved = true;
  res.send(comment);
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});
