const { formatISO, parseISO } = require('date-fns');

/**
 * Converts a date string to a more readable ISO format.
 * @param {string} dateString - The date string to convert.
 * @returns {string} - The converted date in ISO format.
 */
function formatDate(dateString) {
  try {
    const parsedDate = parseISO(dateString);
    return formatISO(parsedDate, { year: 'numeric', month: '2-digit', day: '2-digit' });
  } catch (error) {
    console.error('Error formatting date:', error);
    return dateString;
  }
}

/**
 * Checks if a comment or its replies have been replied to.
 * @param {Array} comments - An array of comments and their replies.
 * @returns {boolean} - True if any comment has replies, false otherwise.
 */
function hasReplies(comments) {
  for (let i = 0; i < comments.length; i++) {
    const currentComment = comments[i];
    if (currentComment.replies && currentComment.replies.length > 0) {
      return true;
    }
  }
  return false;
}

/**
 * Formats a number to include commas as thousands separators.
 * @param {number} num - The number to format.
 * @returns {string} - The formatted number with commas.
 */
function formatNumber(num) {
  if (isNaN(num)) {
    return '0';
  }
  const parts = num.toString().split('.');
  parts[0] = parts[0].replace(/\B(?=(\d{3})+(?!\d))/g, ',');
  return parts.join('.');
}

module.exports = {
  formatDate,
  hasReplies,
  formatNumber,
};
