import React, { useState, useEffect } from 'react';

const WindowResizer = () => {
  // State to store window width and height
  const [windowSize, setWindowSize] = useState({ width: window.innerWidth, height: window.innerHeight });

  // Function to handle window resize event
  const handleResize = () => {
    setWindowSize({
      width: window.innerWidth,
      height: window.innerHeight,
    });
  };

  useEffect(() => {
    // Add window resize listener
    window.addEventListener('resize', handleResize);

    // Cleanup function to remove the listener when component unmounts
    return () => {
      window.removeEventListener('resize', handleResize);
    };
  }, []); // Empty dependency array means this effect runs once after the initial render

  // Error handling: check if windowSize is defined
  if (!windowSize) {
    throw new Error("Window size not initialized properly.");
  }

  return (
    <div>
      <h2>Window Resizer</h2>
      <p>Current Width: {windowSize.width}px, Current Height: {windowSize.height}px</p>
    </div>
  );
};

export default WindowResizer;
```

