// Create context for window size
const WindowSizeContext = createContext();

// InfoCardContainer Component
function InfoCardContainer() {
  const [windowWidth, setWindowWidth] = useState(window.innerWidth);
  const [isSmallScreen, setIsSmallScreen] = useState(window.innerWidth < 768);

  // Effect to update window width and check screen size on resize
  useEffect(() => {
    const handleResize = () => {
      setWindowWidth(window.innerWidth);
      setIsSmallScreen(window.innerWidth < 768);
    };

    window.addEventListener('resize', handleResize);
    return () => {
      window.removeEventListener('resize', handleResize);
    };
  }, []);

  // Error handling
  useEffect(() => {
    if (window.innerWidth !== window.screen.width) {
      console.error('Mismatch between innerWidth and screen.width');
    }
  }, [windowWidth]);

  return (
    <WindowSizeContext.Provider value={{ windowWidth, isSmallScreen }}>
      <div className="info-card-container">
        {/* Conditional rendering based on screen size */}
        {isSmallScreen ? (
          <InfoCard title="Mobile Info" content="Responsive design for mobile devices." />
        ) : (
          <InfoCard title="Desktop Info" content="Optimized for desktop viewing." />
        )}
      </div>
    </WindowSizeContext.Provider>
  );
}

