const express = require('express');
const { Pool } = require('pg');

// Set up Express app
const app = express();
app.use(express.json());

// Database connection configuration
const pool = new Pool({
  user: 'your_database_user',
  host: 'localhost', // Replace with your database host if it's not localhost
  database: 'your_database_name',
  password: 'your_database_password',
  port: 5432, // Default PostgreSQL port
});

// Middleware to log requests and errors
app.use((req, res, next) => {
  console.log(`Received ${req.method} request for ${req.url}`);
  next();
});

// Middleware to handle errors globally
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).send('Internal Server Error');
});

// Endpoint to cast a vote
app.post('/vote/:pollId', async (req, res) => {
  const { pollId } = req.params;
  const { optionId } = req.body;

  try {
    // Check if the poll exists and validate the option
    const checkPollQuery = 'SELECT * FROM polls WHERE id = $1';
    const result = await pool.query(checkPollQuery, [pollId]);
    if (result.rows.length === 0) {
      return res.status(404).send('Poll not found');
    }

    const validateOptionQuery = 'SELECT id FROM options WHERE poll_id = $1 AND id = $2';
    const optionResult = await pool.query(validateOptionQuery, [pollId, optionId]);
    if (optionResult.rows.length === 0) {
      return res.status(400).send('Invalid option');
    }

    // Increment the vote count for the selected option
    const updateVoteQuery = 'UPDATE options SET votes = votes + 1 WHERE id = $1';
    await pool.query(updateVoteQuery, [optionId]);

    res.status(200).send('Vote recorded successfully');
  } catch (error) {
    next(error);
  }
});

// Endpoint to get the current vote percentages
app.get('/vote/:pollId', async (req, res) => {
  const { pollId } = req.params;

  try {
    // Get total votes for each option
    const fetchVotesQuery = 'SELECT option_id, SUM(votes) as total_votes FROM options WHERE poll_id = $1 GROUP BY option_id';
    const result = await pool.query(fetchVotesQuery, [pollId]);

    // Calculate percentages and get the winning option if needed
    const voteData = result.rows;
    let totalVotes = 0;
    let winningOptionId = null;

    voteData.forEach(option => {
      option.percentage = Math.round((option.total_votes / totalVotes) * 100);
      totalVotes += option.total_votes;
      if (winningOptionId === null || option.percentage > voteData[winningOptionId].percentage) {
        winningOptionId = option.id;
      }
    });

    res.json(voteData);

    // Check if there is a winner
    const fetchWinnerQuery = 'SELECT * FROM options WHERE id = $1';
    const winnerResult = await pool.query(fetchWinnerQuery, [winningOptionId]);
    if (winnerResult.rows.length > 0) {
      res.status(200).send('Vote percentages and the winning option');
    } else {
      res.status(400).send('No votes cast');
    }
  } catch (error) {
    next(error);
  }
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});
