  try {
    // Fetch total number of polls and total votes across all polls
    const [totalPolls, totalVotes] = await Promise.all([
      Poll.countDocuments(),
      Vote.aggregate([{ $group: { _id: null, total: { $sum: '$optionIndex' } } }])
        .exec()
        .then(result => result[0].total || 0),
    ]);

    // Respond with the statistics
    res.json({
      totalPolls,
      totalVotes,
    });
