import React, { useState, useEffect } from 'react';

// Context to share progress data between components
const ProgressContext = React.createContext();

function ProgressBar() {
  // State to hold the current progress percentage
  const [progress, setProgress] = useState(0);

  // UseEffect hook to simulate fetching real-time progress
  useEffect(() => {
    let intervalId;
    let timer = 0;

    const updateProgress = () => {
      if (timer >= 100) {
        clearInterval(intervalId);
        setProgress(timer); // Set final progress to 100
      } else {
        setProgress((prevProgress) => prevProgress + 5); // Increase progress by 5 every second
        timer++;
      }
    };

    intervalId = setInterval(updateProgress, 1000);

    return () => clearInterval(intervalId);
  }, []);

  const { children } = React.useContext(ProgressContext);

  if (!children) {
    throw new Error('ProgressBar requires a child component.');
  }

  return (
    <ProgressContext.Provider value={{ progress }}>
      {React.cloneElement(children, { progress })}
    </ProgressContext.Provider>
  );
}

// Example usage
function ProgressBarContainer() {
  return (
    <div className="progress-bar-container">
      <ProgressBar>
        {(props) => (
          <div style={{ width: `${props.progress}%`, height: '20px', backgroundColor: '#4caf50' }}>
            {props.progress}%
          </div>
        )}
      </ProgressBar>
    </div>
  );
}

export default ProgressBarContainer;
```

