import React, { useState, useEffect } from 'react';

// Context for managing toasts
const ToastContext = React.createContext();

// Provider component to manage the toast queue
export const ToastProvider = ({ children }) => {
  const [toasts, setToasts] = useState([]);

  // Function to add a new toast to the queue
  const showToast = (message, duration) => {
    setToasts([...toasts, { message, duration }]);
  };

  // useEffect to remove expired toasts from the queue
  useEffect(() => {
    const timeoutIds = toasts.map((toast, index) => {
      const id = setTimeout(() => {
        setToasts(toasts.filter(t => t !== toast));
      }, toast.duration);
      return id;
    });

    return () => {
      timeoutIds.forEach(id => clearTimeout(id));
    };
  }, [toasts]);

  // Context provider value
  const contextValue = { showToast };

  return (
    <ToastContext.Provider value={contextValue}>
      {children}
    </ToastContext.Provider>
  );
};

// Consumer component to display toasts
export const ToastConsumer = ({ children }) => {
  return (
    <ToastContext.Consumer>{value => (
      <>
        {toasts.map((toast, index) => (
          <div key={index}>{toast.message}</div>
        ))}
        {children}
      </>
    )}</ToastContext.Consumer>
  );
};

// ToastManager component
export const ToastManager = ({ children }) => {
  return (
    <div>
      <ToastProvider>{children}</ToastProvider>
      <ToastConsumer>{props => (
        <button onClick={() => props.showToast("Hello, world!", 5000)}>Show Toast</button>
      )}</ToastConsumer>
    </div>
  );
};
