class DelayQueue {
  constructor() {
    this.queue = new Map();
    this.runningTasks = {};
  }

  // Adds an item to the queue with a specified delay
  add(item, delay) {
    const id = Date.now().toString(); // Use current timestamp as unique identifier
    this.queue.set(id, { item, delay });
    this.scheduleTask(id);
  }

  // Schedules a task for execution after the delay
  scheduleTask(id) {
    setTimeout(() => {
      if (!this.runningTasks[id]) {
        const task = this.queue.get(id);
        if (task) {
          delete this.queue.get(id); // Remove from queue once executed
          this.runningTasks[id] = true; // Mark as running
          // Execute the item (replace with actual implementation)
          console.log('Executing:', task.item);
          // After execution, clear the running flag
          setTimeout(() => {
            delete this.runningTasks[id];
          }, 0); // Use a zero delay to ensure completion after execution
        }
      }
    }, delay);
  }

  // Stops all scheduled tasks and clears the queue
  stop() {
    Object.keys(this.queue).forEach(id => {
      clearTimeout(this.queue.get(id));
    });
    this.runningTasks = {};
    this.queue.clear();
  }
}

// Example usage:
const manager = new DelayQueue();
manager.add('Alert: System Update', 5000); // Show alert after 5 seconds
manager.add('Error: Connection Lost', 10000); // Show error after 10 seconds
setTimeout(() => {
  manager.stop(); // Stop all tasks before they execute
}, 7000);
```

**Explanation**: 
- **DelayQueue Class**: Manages a queue of items to be displayed at specified delays.
- **add Method**: Adds an item with a given delay, schedules it for execution, and stores its state in `runningTasks`.
- **scheduleTask Method**: Uses `setTimeout` to execute the item after the delay.
- **stop Method**: Clears all scheduled tasks and resets the queue and running task states.
- **Example Usage**: Demonstrates adding items to the queue with different delays and stopping them before execution.
