import React, { useState, useEffect } from 'react';

// Notification context to manage notifications globally
const NotificationContext = React.createContext();

// Notifier component for displaying notifications
function Notifier() {
  const [notifications, setNotifications] = useState([]);

  // Effect to remove expired notifications after a delay
  useEffect(() => {
    const timerIds = notifications.map((notification, index) => setTimeout(() => {
      setNotifications(notifications.filter((_, i) => i !== index));
    }, notification.delay));

    return () => timerIds.forEach(clearTimeout);
  }, [notifications]);

  // Function to add a new notification
  function showNotification(notification) {
    if (typeof notification !== 'object' || !('text' in notification) || !('delay' in notification)) {
      throw new Error('Invalid notification object. Expected { text: string, delay: number }');
    }
    setNotifications([...notifications, notification]);
  }

  // Provide context to child components
  return (
    <NotificationContext.Provider value={showNotification}>
      {/* Notification list */}
      {notifications.map((notification, index) => (
        <div key={index} style={{ background: 'yellow', padding: '10px', margin: '5px 0' }}>
          {notification.text}
        </div>
      ))}
    </NotificationContext.Provider>
  );
}

// Hook to consume the notification context
function useNotifications() {
  const context = React.useContext(NotificationContext);
  if (context === undefined) {
    throw new Error('useNotifications must be used within a Notifier component');
  }
  return context;
}

export { Notifier, useNotifications };
