class ToastService {
  constructor() {
    this.queue = [];
  }

  // Adds a toast to the queue with specified message, duration, and position
  addToast(message, duration = 3000, position = 'top-right') {
    this.queue.push({ message, duration, position });
    this.displayNextToast();
  }

  // Displays the next toast in the queue if it exists
  displayNextToast() {
    const { message, duration, position } = this.queue.shift();

    if (message) {
      const element = document.createElement('div');
      element.classList.add('toast', `position-${position}`);

      const textElement = document.createElement('span');
      textElement.textContent = message;
      element.appendChild(textElement);

      // Position the toast and add it to the DOM
      this.positionToast(element, position);
      document.body.appendChild(element);

      // Remove the toast after the specified duration or when closed manually
      setTimeout(() => {
        document.body.removeChild(element);
      }, duration + 100); // Adding a small delay to ensure toast is fully removed before closing

      // Optionally add a close button or handle manual dismissal
    }
  }

  // Positions the toast based on the specified position
  positionToast(toastElement, position) {
    const positions = {
      'top-right': { top: '10px', right: '10px' },
      'top-left': { top: '10px', left: '10px' },
      'bottom-right': { bottom: '10px', right: '10px' },
      'bottom-left': { bottom: '10px', left: '10px' }
    };

    const style = toastElement.style;
    Object.assign(style, positions[position]);
  }

  // Clear the entire queue of toasts
  clearQueue() {
    this.queue = [];
  }
}
```

