class NotificationHandler {
  constructor(maxQueueSize) {
    this.queue = [];
    this.maxQueueSize = maxQueueSize;
  }

  addNotification(notification, delay) {
    if (this.queue.length >= this.maxQueueSize) {
      console.error("Queue is full. Cannot add more notifications.");
      return false;
    }
    const notificationItem = { notification: notification, delay: delay };
    this.queue.push(notificationItem);
    this.scheduleNextNotification();
    return true;
  }

  scheduleNextNotification() {
    if (this.queue.length > 0) {
      const nextNotification = this.queue[0];
      setTimeout(() => {
        this.displayNotification(nextNotification.notification);
        this.queue.shift();
        this.scheduleNextNotification();
      }, nextNotification.delay);
    }
  }

  displayNotification(notification) {
    // Implement your notification display logic here
    console.log("Displaying notification:", notification);
    // Example: Show a toast or alert to the user
    alert(`"${notification}" will be displayed after ${nextNotification.delay} milliseconds.`);
  }

  removeNotification(notification) {
    this.queue = this.queue.filter(item => item.notification !== notification);
  }
}
