import React, { useState, useEffect, createContext } from 'react';

// Define the audio context provider context
const AudioContext = createContext();

export function useAudioContext() {
  // State to manage the current audio source URL and playback status
  const [audioUrl, setAudioUrl] = useState(null);
  const [isPlaying, setIsPlaying] = useState(false);

  // Use the useEffect hook to handle audio context setup and teardown
  useEffect(() => {
    let audio;
    if (isPlaying) {
      // Initialize or resume audio when isPlaying is true
      audio = new Audio(audioUrl);
      audio.play();
    } else {
      // Stop audio when isPlaying is false
      if (audio) {
        audio.pause();
        audio.currentTime = 0; // Reset to start position
      }
    }

    return () => {
      // Clean up the audio element on unmount
      if (audio) {
        audio.pause();
        audio.onended = null;
      }
    };
  }, [audioUrl, isPlaying]);

  // Function to handle audio URL change
  const setAudioSource = (url) => {
    setAudioUrl(url);
  };

  // Function to toggle play/pause
  const togglePlayPause = () => {
    setIsPlaying(!isPlaying);
  };

  return {
    audioUrl,
    isPlaying,
    setAudioSource,
    togglePlayPause,
  };
}

export function AudioContextProvider({ children }) {
  const audioState = useAudioContext();

  // Provide the audio context value to its children
  return (
    <AudioContext.Provider value={audioState}>
      {children}
    </AudioContext.Provider>
  );
}
