// audioUtils.js

// Function to load an audio file into a MediaElementAudioSourceNode
function loadAudio(url) {
    return new Promise((resolve, reject) => {
        const audio = new Audio();
        audio.src = url;
        audio.addEventListener('load', () => resolve(audio), { once: true });
        audio.addEventListener('error', (e) => reject(e));
    });
}

// Function to handle playback of an audio source node
function playAudio(node) {
    if (!node || !node.play) {
        throw new Error('Invalid audio source node');
    }
    try {
        node.play();
    } catch (e) {
        console.error('Error playing audio', e);
    }
}

// Function to stop playback of an audio source node
function stopAudio(node) {
    if (!node || !node.pause) {
        throw new Error('Invalid audio source node');
    }
    try {
        node.pause();
    } catch (e) {
        console.error('Error stopping audio', e);
    }
}

// Function to set the volume of an audio source node
function setVolume(node, volume) {
    if (!node || typeof volume !== 'number' || volume < 0 || volume > 1) {
        throw new Error('Invalid parameters for setting volume');
    }
    try {
        node.volume = volume;
    } catch (e) {
        console.error('Error setting audio volume', e);
    }
}

// Function to create a gain node for volume control
function createGainNode(context) {
    if (!context || !(context instanceof AudioContext)) {
        throw new Error('Invalid context');
    }
    return context.createGain();
}

// Exporting the functions
export { loadAudio, playAudio, stopAudio, setVolume, createGainNode };
