import React, { useState, useEffect } from 'react';

const useAudioContext = () => {
  const [audioCtx, setAudioCtx] = useState(null);
  const [currentTrack, setCurrentTrack] = useState(null);

  useEffect(() => {
    try {
      setAudioCtx(new window.AudioContext());
    } catch (error) {
      console.error('Error creating Audio Context:', error);
    }
  }, []);

  return { audioCtx, currentTrack };
};

const PlaylistPlayer = ({ tracks }) => {
  const { audioCtx, currentTrack } = useAudioContext();

  useEffect(() => {
    if (!audioCtx || !currentTrack) return;

    // Load and prepare the audio source
    const audioSource = new window.Audio();
    audioSource.src = currentTrack.url;
    audioSource.crossOrigin = 'anonymous'; // Allow cross-origin requests

    audioSource.onloadedmetadata = () => {
      audioSource.play();
    };

    audioSource.onerror = (error) => {
      console.error('Error loading track:', error);
    };
  }, [audioCtx, currentTrack]);

  const playTrack = () => {
    if (!currentTrack || !audioCtx) return;

    // Check if the track is already playing
    if (audioCtx.state === 'running') return;

    audioSource.play();
  };

  const pauseTrack = () => {
    if (!currentTrack || !audioCtx) return;

    if (audioCtx.state === 'suspended' || audioCtx.state === 'paused') return;

    audioSource.pause();
  };

  return (
    <div>
      <button onClick={playTrack}>Play</button>
      <button onClick={pauseTrack}>Pause</button>
      {currentTrack && (
        <p>Playing: {currentTrack.title}</p>
      )}
    </div>
  );
};

export default PlaylistPlayer;
```

