```
import React, { createContext, useContext, useState, useEffect } from 'react';

// Create AudioContext context
const AudioContext = createContext(null);

export function AudioContextProvider({ children }) {
  const [audioState, setAudioState] = useState({
    audio: null,
    isPlaying: false,
    volume: 0.5,
  });

  // Function to load and initialize audio element
  useEffect(() => {
    if (!audioState.audio) {
      const newAudio = new Audio();
      setAudioState({ ...audioState, audio: newAudio });
    }
  }, []);

  // Function to play or pause the audio
  const togglePlayPause = () => {
    const { audio } = audioState;
    if (audio) {
      if (audio.paused || audio.ended) {
        audio.play();
        setAudioState({ ...audioState, isPlaying: true });
      } else {
        audio.pause();
        setAudioState({ ...audioState, isPlaying: false });
      }
    }
  };

  // Function to adjust volume
  const setVolume = (newVolume) => {
    if (typeof newVolume === 'number' && newVolume >= 0 && newVolume <= 1) {
      setAudioState({ ...audioState, volume: newVolume });
      audio.setVolume(newVolume);
    } else {
      console.error('Volume must be a number between 0 and 1.');
    }
  };

  return (
    <AudioContext.Provider
      value={{
        audioState,
        togglePlayPause,
        setVolume,
      }}
    >
      {children}
    </AudioContext.Provider>
  );
}

export function useAudioContext() {
  const context = useContext(AudioContext);
  if (context === undefined) {
    throw new Error('useAudioContext must be used within an AudioContextProvider');
  }
  return context;
}
