import { useState, useEffect } from 'react';
import { useAudioContext } from './useAudioContext';

const AudioState = ({ src }) => {
  const [playing, setPlaying] = useState(false);
  const audioCtx = useAudioContext();

  // Error handling for invalid source URL
  if (!src) {
    throw new Error('Audio source URL is required');
  }

  useEffect(() => {
    let sourceNode;

    const onPlay = () => setPlaying(true);
    const onPause = () => setPlaying(false);

    try {
      // Create an AudioBufferSourceNode from the loaded audio data
      sourceNode = audioCtx.createBufferSource();
      sourceNode.connect(audioCtx.destination);
      sourceNode.start(0);

      // Set up event listeners
      sourceNode.onplay = onPlay;
      sourceNode.onpause = onPause;

      // Load audio file
      const request = new XMLHttpRequest();
      request.open('GET', src, true);
      request.responseType = 'arraybuffer';
      request.onload = () => {
        audioCtx.decodeAudioData(request.response).then(buffer => {
          sourceNode.buffer = buffer;
        });
      };
      request.onerror = () => {
        console.error(`Failed to load audio file: ${src}`);
      };
      request.send();
    } catch (error) {
      console.error('Error initializing audio:', error);
    }

    return () => {
      // Clean up on unmount
      if (sourceNode) {
        sourceNode.stop(0);
        sourceNode.disconnect(audioCtx.destination);
        sourceNode.onplay = null;
        sourceNode.onpause = null;
      }
    };
  }, [src, audioCtx]);

  return (
    <div>
      <button onClick={() => setPlaying(!playing)}>
        {playing ? 'Pause' : 'Play'}
      </button>
    </div>
  );
};

export default AudioState;
```

