import React, { useState, useEffect } from 'react';

const usePlaylist = (initialSongs) => {
  const [songs, setSongs] = useState(initialSongs);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [audioElement, setAudioElement] = useState(null);

  // Error handling for audio element
  useEffect(() => {
    if (!audioElement) {
      const newAudioElement = document.createElement('audio');
      setAudioElement(newAudioElement);
    }
  }, []);

  // Function to play the current song in the playlist
  const playCurrentSong = () => {
    if (songs.length === 0 || currentIndex >= songs.length) return;
    audioElement.src = songs[currentIndex].src;
    audioElement.play().catch(error => console.error('Error playing song:', error));
  };

  // Function to set a specific index as the current song
  const setCurrentSong = newIdx => {
    if (newIdx < 0 || newIdx >= songs.length) return;
    setCurrentIndex(newIdx);
    playCurrentSong();
  };

  // Function to handle playback end and move to the next song
  const handleEnd = () => {
    if (currentIndex + 1 >= songs.length) setCurrentIndex(0); // Loop back to the first song
    else setCurrentIndex(currentIndex + 1);
  };

  return [
    songs,
    currentIndex,
    setSongs,
    setCurrentSong,
    audioElement,
    playCurrentSong,
    handleEnd
  ];
};

export default usePlaylist;
