// utils/audioUtils.js

const audioUtils = (() => {
    const context = new (window.AudioContext || window.webkitAudioContext)();

    // Function to load an audio file and create a source node
    function loadAndCreateSource(url) {
        return new Promise((resolve, reject) => {
            const request = new XMLHttpRequest();
            request.open('GET', url, true);
            request.responseType = 'arraybuffer';

            request.onload = () => {
                context.decodeAudioData(request.response)
                    .then(buffer => resolve(new SourceNode(context, buffer)))
                    .catch(err => reject(err));
            };

            request.onerror = err => reject(err);

            request.send();
        });
    }

    // Class to manage audio source and playback
    class SourceNode {
        constructor(context, buffer) {
            this.source = context.createBufferSource();
            this.source.buffer = buffer;
            this.isPlaying = false;
        }

        play() {
            if (this.isPlaying) return;

            try {
                this.source.start(0);
                this.isPlaying = true;
            } catch (err) {
                console.error('Failed to start playback:', err);
            }
        }

        pause() {
            if (!this.isPlaying) return;

            try {
                this.source.stop();
                this.isPlaying = false;
            } catch (err) {
                console.error('Failed to pause playback:', err);
            }
        }

        // Add more methods as needed
    }

    // Function to create an audio player with basic controls
    function createAudioPlayer(audioUrl, parentElementId) {
        const audioContainer = document.getElementById(parentElementId);

        if (!audioContainer) {
            throw new Error('Parent element not found');
        }

        return {
            load: async (url) => {
                try {
                    const sourceNode = await loadAndCreateSource(url);
                    this.sourceNode = sourceNode;
                    audioContainer.appendChild(sourceNode.source.mediaElement);
                } catch (err) {
                    console.error('Error loading audio:', err);
                }
            },
            play: () => {
                if (!this.sourceNode) {
                    throw new Error('Audio not loaded');
                }

                this.sourceNode.play();
            },
            pause: () => {
                if (!this.sourceNode) {
                    throw new Error('Audio not loaded');
                }

                this.sourceNode.pause();
            }
        };
    }

    return {
        createAudioPlayer
    };
})();

export default audioUtils;
```

