));

// Callback functions for REST API routes
function get_or_create_playlist($request) {
    global $conn;
    $name = sanitize_input($request['name']);

    // Check if playlist exists, otherwise create it
    $sql = "SELECT * FROM playlists WHERE name = ?";
    $stmt = $conn->prepare($sql);
    $stmt->bind_param("s", $name);
    $stmt->execute();
    $result = $stmt->get_result();

    if ($result->num_rows > 0) {
        return array('data' => 'Playlist already exists');
    } else {
        $sql = "INSERT INTO playlists (name) VALUES (?)";
        $stmt = $conn->prepare($sql);
        $stmt->bind_param("s", $name);
        if ($stmt->execute()) {
            return array('data' => 'Playlist created successfully');
        }
        return new WP_Error('playlist_creation_failed', 'Failed to create playlist', 500);
    }
}

function get_playlist_details($request) {
    global $conn;
    $id = sanitize_input($request['id']);

    // Get playlist details
    $sql = "SELECT * FROM playlists WHERE id = ?";
    $stmt = $conn->prepare($sql);
    $stmt->bind_param("i", $id);
    $stmt->execute();
    $result = $stmt->get_result();

    if ($result->num_rows > 0) {
        return array('data' => $result->fetch_assoc());
    } else {
        return new WP_Error('playlist_not_found', 'Playlist not found', 404);
    }
}

function add_song_to_playlist($request) {
    global $conn;
    $id = sanitize_input($request['id']);
    $song_id = sanitize_input($request['song_id']);

    // Check if playlist exists
    $sql = "SELECT * FROM playlists WHERE id = ?";
    $stmt = $conn->prepare($sql);
    $stmt->bind_param("i", $id);
    $stmt->execute();
    $result = $stmt->get_result();

    if ($result->num_rows > 0) {
        // Check if song exists
        $sql = "SELECT * FROM songs WHERE id = ?";
        $stmt = $conn->prepare($sql);
        $stmt->bind_param("i", $song_id);
        $stmt->execute();
        $result = $stmt->get_result();

        if ($result->num_rows > 0) {
            // Add song to playlist
            $sql = "INSERT INTO playlist_songs (playlist_id, song_id) VALUES (?, ?)";
            $stmt = $conn->prepare($sql);
            $stmt->bind_param("ii", $id, $song_id);
            if ($stmt->execute()) {
                return array('data' => 'Song added to playlist successfully');
            }
        } else {
            return new WP_Error('song_not_found', 'Song not found', 404);
        }
    } else {
        return new WP_Error('playlist_not_found', 'Playlist not found', 404);
    }
}

function remove_song_from_playlist($request) {
    global $conn;
    $id = sanitize_input($request['id']);
    $song_id = sanitize_input($request['song_id']);

    // Check if playlist exists
    $sql = "SELECT * FROM playlists WHERE id = ?";
    $stmt = $conn->prepare($sql);
    $stmt->bind_param("i", $id);
    $stmt->execute();
    $result = $stmt->get_result();

    if ($result->num_rows > 0) {
        // Remove song from playlist
        $sql = "DELETE FROM playlist_songs WHERE playlist_id = ? AND song_id = ?";
        $stmt = $conn->prepare($sql);
        $stmt->bind_param("ii", $id, $song_id);
        if ($stmt->execute()) {
            return array('data' => 'Song removed from playlist successfully');
        }
    } else {
        return new WP_Error('playlist_not_found', 'Playlist not found', 404);
    }
