  useNewUrlParser: true,
  useUnifiedTopology: true,
});

// Define user schema and model
const userSchema = new mongoose.Schema({
  email: { type: String, required: true, unique: true, match: /^[^\s@]+@[^\s@]+\.[^\s@]+$/ },
  password: { type: String, required: true, minLength: 6, maxLength: 20 },
});

const User = mongoose.model('User', userSchema);

// Middleware for error handling
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).send('Internal Server Error');
});

// Middleware to log requests
app.use((req, res, next) => {
  console.log(`${req.method} ${req.url}`);
  next();
});

// Signup endpoint
app.post('/signup', async (req, res) => {
  try {
    const { email, password } = req.body;

    // Validate input using regex and minimum length requirements
    if (!email || !password) return res.status(400).send('Email and Password are required.');
    if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) return res.status(400).send('Invalid email format.');
    if (password.length < 6 || password.length > 20) return res.status(400).send('Password must be between 6 and 20 characters.');

    // Create a new user instance
    const newUser = new User({ email, password });

    // Hash the password before saving to database
    await newUser.hashPassword();

    // Save user to database
    await newUser.save();

    res.status(201).send('User created successfully.');
  } catch (error) {
    next(error);
  }
});

