// validation-rules.js

/**
 * Validates if a given string is a valid email address.
 * @param {string} email - The email string to validate.
 * @returns {boolean} - True if the email is valid, false otherwise.
 */
function isValidEmail(email) {
  // Regular expression for validating an email
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  return emailRegex.test(email);
}

/**
 * Validates if a given string is a valid username.
 * @param {string} username - The username string to validate.
 * @returns {boolean} - True if the username is valid, false otherwise.
 */
function isValidUsername(username) {
  // Regular expression for validating a username
  const usernameRegex = /^[a-zA-Z0-9._-]{3,20}$/;

  return usernameRegex.test(username);
}

/**
 * Validates if a given string is a valid password.
 * @param {string} password - The password string to validate.
 * @returns {boolean} - True if the password is valid, false otherwise.
 */
function isValidPassword(password) {
  // Regular expression for validating a password
  const passwordRegex = /^(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]{8,}$/;

  return passwordRegex.test(password);
}

/**
 * Validates if a given string is a valid phone number.
 * @param {string} phoneNumber - The phone number string to validate.
 * @returns {boolean} - True if the phone number is valid, false otherwise.
 */
function isValidPhoneNumber(phoneNumber) {
  // Regular expression for validating a phone number
  const phoneRegex = /^[0-9]{10}$/;

  return phoneRegex.test(phoneNumber);
}

/**
 * Validates if a given string is a valid social security number (SSN).
 * @param {string} ssn - The SSN string to validate.
 * @returns {boolean} - True if the SSN is valid, false otherwise.
 */
function isValidSSN(ssn) {
  // Regular expression for validating an SSN
  const ssnRegex = /^[0-9]{3}-[0-9]{2}-[0-9]{4}$/;

  return ssnRegex.test(ssn);
}

/**
 * Validates if a given string is a valid date.
 * @param {string} date - The date string to validate in 'YYYY-MM-DD' format.
 * @returns {boolean} - True if the date is valid, false otherwise.
 */
function isValidDate(date) {
  // Regular expression for validating a date
  const dateRegex = /^\d{4}-\d{2}-\d{2}$/;

  return dateRegex.test(date);
}

module.exports = {
  isValidEmail,
  isValidUsername,
  isValidPassword,
  isValidPhoneNumber,
  isValidSSN,
  isValidDate
};
