import React, { useState, useEffect } from 'react';
import { Formik, Form, Field, ErrorMessage } from 'formik';
import * as Yup from 'yup';

// Define form validation schema using Yup
const SignupFormSchema = Yup.object().shape({
  username: Yup.string()
    .required('Username is required')
    .min(4, 'Username must be at least 4 characters'),
  email: Yup.string()
    .email('Invalid email address')
    .required('Email is required'),
  password: Yup.string()
    .required('Password is required')
    .min(8, 'Password must be at least 8 characters')
    .matches(
      /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]{8,}$/,
      'Password must include at least one uppercase letter, one lowercase letter, one digit, and one special character'
    ),
  confirmPassword: Yup.string()
    .required('Confirm password is required')
    .oneOf([Yup.ref('password'), null], 'Passwords must match'),
});

const SignupForm = () => {
  const [submitted, setSubmitted] = useState(false);
  const [formErrors, setFormErrors] = useState({});

  useEffect(() => {
    if (submitted) {
      // Handle form submission logic here
      console.log('Form submitted with data:', values);
    }
  }, [submitted]);

  return (
    <div>
      <h2>Signup Form</h2>
      <Formik
        initialValues={{
          username: '',
          email: '',
          password: '',
          confirmPassword: '',
        }}
        validationSchema={SignupFormSchema}
        onSubmit={(values, { setSubmitting }) => {
          setSubmitting(false);
          setSubmitted(true);
        }}
      >
        {({ errors, touched, values, handleChange, handleSubmit }) => (
          <Form>
            <div>
              <label htmlFor="username">Username:</label>
              <Field type="text" id="username" name="username" onChange={handleChange} />
              {touched.username && errors.username ? <ErrorMessage name="username" /> : null}
            </div>
            <div>
              <label htmlFor="email">Email:</label>
              <Field type="email" id="email" name="email" onChange={handleChange} />
              {touched.email && errors.email ? <ErrorMessage name="email" /> : null}
            </div>
            <div>
              <label htmlFor="password">Password:</label>
              <Field type="password" id="password" name="password" onChange={handleChange} />
              {touched.password && errors.password ? <ErrorMessage name="password" /> : null}
            </div>
            <div>
              <label htmlFor="confirmPassword">Confirm Password:</label>
              <Field type="password" id="confirmPassword" name="confirmPassword" onChange={handleChange} />
              {touched.confirmPassword && errors.confirmPassword ? (
                <ErrorMessage name="confirmPassword" />
              ) : null}
            </div>
            <button type="submit" disabled={!formErrors}>
              Submit
            </button>
          </Form>
        )}
      </Formik>
    </div>
  );
};

export default SignupForm;
