import React, { useState, useEffect } from 'react';
import PropTypes from 'prop-types';

const InfiniteScrollGallery = ({ itemsPerPage, fetchMoreItems }) => {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(false);
  const [hasMore, setHasMore] = useState(true);

  useEffect(() => {
    if (loading || hasMore) return;

    setLoading(true);
    fetchMoreItems()
      .then(data => {
        setItems(prevItems => [...prevItems, ...data]);
        setLoading(false);
        setHasMore(data.length === itemsPerPage);
      })
      .catch(error => {
        console.error('Error fetching more data:', error);
        setLoading(false);
        setHasMore(false); // Indicate no more items to load
      });
  }, [loading, hasMore, fetchMoreItems]);

  return (
    <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))' }}>
      {items.map((item, index) => (
        <div key={index} style={{ padding: '16px', border: '1px solid #ccc', margin: '8px' }}>
          {item.content}
        </div>
      ))}
    </div>
  );
};

InfiniteScrollGallery.propTypes = {
  itemsPerPage: PropTypes.number.isRequired,
  fetchMoreItems: PropTypes.func.isRequired
};

export default InfiniteScrollGallery;
