/**
 * ImageFetcher.js - Utility/helper file for managing image fetching and gallery logic
 */

class ImageFetcher {
    constructor() {
        this.imageCache = new Map();
    }

    /**
     * Fetches an image by URL
     * @param {string} url - The URL of the image to fetch
     * @returns {Promise} A promise that resolves with the image element or rejects with an error
     */
    async fetchImage(url) {
        const cacheKey = `image-${url}`;
        if (this.imageCache.has(cacheKey)) {
            return Promise.resolve(this.imageCache.get(cacheKey));
        }

        try {
            const response = await fetch(url);
            if (!response.ok) {
                throw new Error(`Failed to fetch image at ${url}`);
            }
            const blob = await response.blob();
            const imgElement = document.createElement('img');
            imgElement.src = URL.createObjectURL(blob);
            this.imageCache.set(cacheKey, imgElement);
            return imgElement;
        } catch (error) {
            console.error(`Error fetching image at ${url}:`, error);
            throw error;
        }
    }

    /**
     * Handles intersection observer entries
     * @param {Array} entries - An array of IntersectionObserverEntry objects
     */
    handleIntersection(entries) {
        entries.forEach(entry => {
            if (entry.isIntersecting && entry.target.dataset.imageURL) {
                this.fetchImage(entry.target.dataset.imageURL)
                    .then(imgElement => {
                        imgElement.onload = () => {
                            // Handle image loading completion logic here
                            console.log(`Image loaded: ${imgElement.src}`);
                        };
                    })
                    .catch(error => {
                        console.error('Error fetching image:', error);
                    });
            }
        });
    }

    /**
     * Initializes the Intersection Observer for images
     */
    initIntersectionObserver() {
        const observer = new IntersectionObserver(this.handleIntersection.bind(this), {
            threshold: 0.25 // Adjust this threshold as needed
        });

        document.querySelectorAll('.gallery-image').forEach(image => {
            image.dataset.imageURL = image.src; // Store the original URL for reference
            observer.observe(image);
        });
    }
}

// Export the ImageFetcher class for use in your application
export default ImageFetcher;
```

### Explanation:
- **ImageCache**: A simple cache to store images fetched from URLs.
- **fetchImage**: Asynchronously fetches an image by its URL and caches it. Handles errors gracefully.
- **handleIntersection**: Processes intersection observer entries, fetching images when they enter the viewport.
- **initIntersectionObserver**: Sets up an Intersection Observer for all elements with a `.gallery-image` class, observing them to load images as they come into view.
- **Export**: Exports the `ImageFetcher` class so it can be used in your project.
