// IntersectionObserverHandler.js

class IntersectionObserverHandler {
    constructor() {
        this.observers = [];
    }

    // Function to add an observer for a specific element and callback
    addObserver(target, callback) {
        const config = { rootMargin: '0px', threshold: 0.1 };
        const observer = new IntersectionObserver(([entry]) => {
            if (entry.isIntersecting) {
                callback(entry.target);
                this.observers = this.observers.filter(obs => obs.target !== entry.target);
            }
        }, config);

        observer.observe(target);
        this.observers.push({ target, observer });
    }

    // Function to remove an observer based on the target element
    removeObserver(target) {
        const index = this.observers.findIndex(obs => obs.target === target);
        if (index !== -1) {
            const { observer } = this.observers[index];
            observer.disconnect();
            this.observers.splice(index, 1);
        }
    }

    // Function to clear all observers
    clearObservers() {
        this.observers.forEach(({ observer }) => observer.disconnect());
        this.observers = [];
    }
}

export default IntersectionObserverHandler;
