// ScrollListener.js

class ScrollListener {
    constructor(container, dataFetcher) {
        this.container = container;
        this.dataFetcher = dataFetcher;
        this.observer = null;

        this.init();
    }

    init() {
        if (!this.container || !this.dataFetcher) {
            console.error('ScrollListener: Container and dataFetcher are required.');
            return;
        }

        this.observer = new IntersectionObserver(
            (entries, observer) => this.handleIntersection(entries, observer),
            { threshold: 0.5 }
        );

        this.attachObserver();
    }

    attachObserver() {
        const elementsToObserve = Array.from(this.container.querySelectorAll('[data-load-on-scroll]'));
        elementsToObserve.forEach(element => {
            if (element && !this.observer.isIntersecting) {
                observer.observe(element);
            }
        });
    }

    handleIntersection(entries, observer) {
        entries.forEach(entry => {
            if (entry.isIntersecting && entry.target.hasAttribute('data-load-on-scroll')) {
                this.dataFetcher()
                    .then(response => this.handleDataResponse(response))
                    .catch(error => console.error('Error fetching data:', error));
            }
        });
    }

    handleDataResponse(data) {
        // Assuming data is an array of items to append to the container
        const itemsToAppend = document.createElement('div');
        itemsToAppend.innerHTML = data.map(item => `<div class="item">${item.content}</div>`).join('');

        this.container.appendChild(itemsToAppend);
    }
}

// Export function for use in other parts of the project
export default ScrollListener;
