// utils.js

/**
 * Utility Functions for Dashboard Analytics Grid
 */

/**
 * A utility function to format a number with commas as thousands separators.
 * @param {number} num - The number to be formatted.
 * @returns {string} - The formatted string with commas.
 */
function formatNumber(num) {
    if (typeof num !== 'number') {
        throw new Error('Input must be a number');
    }
    return num.toLocaleString();
}

/**
 * A utility function to calculate the average of an array of numbers.
 * @param {Array<number>} numbers - The array of numbers to calculate the average from.
 * @returns {number} - The calculated average.
 */
function calculateAverage(numbers) {
    if (!Array.isArray(numbers)) {
        throw new Error('Input must be an array');
    }
    if (numbers.length === 0) {
        return 0;
    }
    const sum = numbers.reduce((acc, num) => acc + num, 0);
    return sum / numbers.length;
}

/**
 * A utility function to group items in an array by a specified key.
 * @param {Array<Object>} data - The array of objects to group.
 * @param {string} key - The property of the object to group by.
 * @returns {Object} - An object with keys as the grouped values and arrays of items as values.
 */
function groupBy(data, key) {
    if (!Array.isArray(data)) {
        throw new Error('Input must be an array');
    }
    return data.reduce((acc, item) => {
        const group = item[key];
        acc[group] = acc[group] || [];
        acc[group].push(item);
        return acc;
    }, {});
}

/**
 * A utility function to debounce a function call.
 * @param {Function} func - The function to debounce.
 * @param {number} wait - The time in milliseconds to delay the execution of the function.
 * @returns {Function} - A debounced version of the function.
 */
function debounce(func, wait) {
    let timeout;
    return function(...args) {
        clearTimeout(timeout);
        timeout = setTimeout(() => func.apply(this, args), wait);
    };
}

/**
 * A utility function to memoize a function's result based on its arguments.
 * @param {Function} func - The function to memoize.
 * @returns {Function} - A memoized version of the function.
 */
function memoize(func) {
    const cache = new Map();
    return (...args) => {
        const key = args.toString(); // Using string representation for simplicity
        if (cache.has(key)) {
            return cache.get(key);
        }
        const result = func(...args);
        cache.set(key, result);
        return result;
    };
}

/**
 * A utility function to check if an object is empty.
 * @param {Object} obj - The object to check.
 * @returns {boolean} - True if the object is empty, false otherwise.
 */
function isEmpty(obj) {
    for (const key in obj) {
        if (obj.hasOwnProperty(key)) {
            return false;
        }
    }
    return true;
}

/**
 * A utility function to sort an array of objects based on a specified property and order.
 * @param {Array<Object>} data - The array of objects to sort.
 * @param {string} key - The property of the object to sort by.
 * @param {string} order - The sorting order, either 'asc' or 'desc'.
 * @returns {Array<Object>} - The sorted array of objects.
 */
function sortBy(data, key, order) {
    if (!Array.isArray(data)) {
        throw new Error('Input must be an array');
    }
    return data.slice().sort((a, b) => {
        const valueA = a[key];
        const valueB = b[key];
        if (valueA < valueB) {
            return order === 'desc' ? 1 : -1;
        }
        if (valueA > valueB) {
            return order === 'desc' ? -1 : 1;
        }
        return 0;
    });
}

// Export the utility functions
export { formatNumber, calculateAverage, groupBy, debounce, memoize, isEmpty, sortBy };
