 * @param {Array} arr - The array where the item needs to be moved.
 * @param {number} currentIndex - The index of the current position of the item.
 * @param {number} targetIndex - The index where the item should be moved to.
 */
function moveItem(arr, currentIndex, targetIndex) {
  if (currentIndex < 0 || currentIndex >= arr.length || targetIndex < 0 || targetIndex >= arr.length) return;
  const [item] = arr.splice(currentIndex, 1);
  arr.splice(targetIndex, 0, item);
