// Import necessary React hooks and useContext for state management and context
import React, { useState, useEffect } from 'react';
import { createContext, useContext } from 'react';

// Create a context for chat messages
const ChatContext = createContext();

function App() {
  // Initialize the chat messages in a local array
  const [messages, setMessages] = useState([
    { sender: 'Alice', text: 'Hello!' },
    { sender: 'Bob', text: 'Hi there!' }
  ]);

  // Function to add a new message to the chat
  const handleAddMessage = (message) => {
    if (message.text.trim()) {
      setMessages([...messages, message]);
    } else {
      alert('Please enter a valid message.');
    }
  };

  return (
    <ChatContext.Provider value={{ messages, handleAddMessage }}>
      <div className="chat-room">
        <h1>Chat Room</h1>
        <ChatInput onSendMessage={handleAddMessage} />
        <ChatList messages={messages} />
      </div>
    </ChatContext.Provider>
  );
}

function ChatInput({ onSendMessage }) {
  // State to hold the current message being typed
  const [message, setMessage] = useState('');

  // Function to handle input change and update the message state
  const handleChange = (e) => {
    setMessage(e.target.value);
  };

  // Function to send the current message when Enter is pressed
  const handleSubmit = (e) => {
    e.preventDefault();
    onSendMessage({ sender: 'You', text: message });
    setMessage('');
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        type="text"
        value={message}
        onChange={handleChange}
        placeholder="Type a message..."
      />
      <button type="submit">Send</button>
    </form>
  );
}

function ChatList({ messages }) {
  // Render each message in the chat list
  return (
    <div className="chat-list">
      {messages.map((msg, index) => (
        <div key={index} className={`message ${msg.sender}`}>
          <strong>{msg.sender}: </strong>
          {msg.text}
        </div>
      ))}
    </div>
  );
}

export default App;
