class MessageStream {
  constructor() {
    // Initialize an empty array to store messages
    this.messages = [];
  }

  /**
   * Adds a new message to the stream.
   * @param {string} message - The content of the message to add.
   */
  addMessage(message) {
    if (typeof message !== 'string') {
      throw new Error('Message must be a string.');
    }
    this.messages.push(message);
  }

  /**
   * Retrieves all messages from the stream.
   * @returns {Array<string>} An array of messages.
   */
  getMessages() {
    return [...this.messages]; // Return a copy to avoid direct mutation
  }

  /**
   * Removes all messages from the stream.
   */
  clearMessages() {
    this.messages = [];
  }
}

// Export the MessageStream class for use in other files
