import React, { createContext, useState } from 'react';

const HabitTrackerContext = createContext();

function HabitTrackerProvider({ children }) {
  const [habits, setHabits] = useState([]);

  // Helper function to add a new habit
  const addHabit = (habitName) => {
    if (!habitName.trim()) {
      throw new Error('Habit name cannot be empty');
    }
    setHabits([...habits, { id: Date.now(), name: habitName }]);
  };

  // Helper function to update a habit's status
  const toggleHabitStatus = (habitId) => {
    setHabits(
      habits.map((habit) =>
        habit.id === habitId ? { ...habit, completed: !habit.completed } : habit
      )
    );
  };

  // Helper function to remove a habit
  const deleteHabit = (habitId) => {
    setHabits(habits.filter((habit) => habit.id !== habitId));
  };

  // Error handler for context values
  if (!habits || typeof addHabit !== 'function' || typeof toggleHabitStatus !== 'function' || typeof deleteHabit !== 'function') {
    throw new Error('Invalid state or missing functions');
  }

  return (
    <HabitTrackerContext.Provider value={{ habits, addHabit, toggleHabitStatus, deleteHabit }}>
      {children}
    </HabitTrackerContext.Provider>
  );
}

export { HabitTrackerProvider, HabitTrackerContext };
