const HabitSchema = new mongoose.Schema({
  name: String,
  daysOfWeek: Array,
});
const Habit = mongoose.model('Habit', HabitSchema);

// Define API routes

// Endpoint to create a new habit
app.post('/habits', async (req, res) => {
  try {
    const { name, daysOfWeek } = req.body;
    const habit = new Habit({ name, daysOfWeek });
    await habit.save();
    res.status(201).json(habit);
  } catch (error) {
    res.status(500).json({ error: 'Failed to create habit' });
  }
});

// Endpoint to get all habits
app.get('/habits', async (req, res) => {
  try {
    const habits = await Habit.find();
    res.json(habits);
  } catch (error) {
    res.status(500).json({ error: 'Failed to retrieve habits' });
  }
});

// Endpoint to get a habit by ID
app.get('/habits/:id', async (req, res) => {
  try {
    const habit = await Habit.findById(req.params.id);
    if (!habit) {
      return res.status(404).json({ error: 'Habit not found' });
    }
    res.json(habit);
  } catch (error) {
    res.status(500).json({ error: 'Failed to retrieve habit' });
  }
});

// Endpoint to update a habit by ID
app.put('/habits/:id', async (req, res) => {
  try {
    const { name, daysOfWeek } = req.body;
    const habit = await Habit.findByIdAndUpdate(req.params.id, { name, daysOfWeek }, { new: true });
    if (!habit) {
      return res.status(404).json({ error: 'Habit not found' });
    }
    res.json(habit);
  } catch (error) {
    res.status(500).json({ error: 'Failed to update habit' });
  }
