              checked={habit.completed}
              onChange={() => updateHabitStatus(habit.id)}
            />
            {habit.name}
          </li>
        ))}
      </ul>
    </div>
  );
}

function HabitContextProvider({ children }) {
  const [habits, setHabits] = useState([]);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch('/api/habits')
      .then(response => response.json())
      .then(data => setHabits(data))
      .catch(error => setError(error));
  }, []);

  if (error) return <div>Error loading habits: {error.message}</div>;

  const updateHabitStatus = (habitId) => {
    // Simulate API call to update habit status
    fetch(`/api/habits/${habitId}`, {
      method: 'PATCH',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ completed: !habits.find(habit => habit.id === habitId).completed })
    }).then(response => response.json())
      .then(data => setHabits([...habits.map(habit => habit.id === habitId ? data : habit)]))
      .catch(error => setError(error));
  };

  return (
    <HabitContext.Provider value={{ habits, updateHabitStatus }}>
      {children}
    </HabitContext.Provider>
  );
}

