// utils/index.js

/**
 * Converts a list of days into an array of boolean values representing checkbox states.
 * @param {Array} days - An array of day names (e.g., ['Monday', 'Tuesday']).
 * @returns {Array} - An array of boolean values indicating checked state for each day.
 */
function mapDaysToCheckedState(days) {
  const today = new Date();
  return days.map(day => {
    const targetDate = new Date(today);
    targetDate.setDate(today.getDate() + (day === 'Today' ? 0 : days.indexOf(day)));
    if (targetDate.toDateString() === today.toDateString()) {
      return true;
    }
    return false;
  });
}

/**
 * Generates a list of checkbox labels based on the current date and selected days.
 * @param {Array} selectedDays - An array of selected day names.
 * @returns {Array} - An array of checkbox labels.
 */
function generateDayLabels(selectedDays) {
  const today = new Date();
  return ['Today'].concat(
    Array.from({ length: 7 }, (_, i) => {
      const date = new Date(today);
      date.setDate(today.getDate() + i);
      const dayName = date.toDateString().split(' ')[0];
      return selectedDays.includes(dayName) ? `${dayName} (Checked)` : dayName;
    })
  );
}

/**
 * Validates if the input is an array of strings and has at least one element.
 * @param {Array} arr - The array to validate.
 * @returns {boolean} - True if valid, false otherwise.
 */
function isValidDayList(arr) {
  return Array.isArray(arr) && arr.length > 0;
}

// Exporting functions
module.exports = {
  mapDaysToCheckedState,
  generateDayLabels,
  isValidDayList
};
