To implement form validation in React using functional components, you can follow these steps:

1. **Set Up Your React Component**: Start by creating a functional component that represents your form.

2. **Define Validation Logic**: Create functions to handle the validation of each input field.

3. **State Management**: Use React's `useState` hook to manage the state of the form fields and any error messages.

4. **Handle Form Submission**: Implement a function to handle form submission, which will validate all fields before submitting the form data.

Here's an example implementation:

```jsx
import React, { useState } from 'react';

const RegistrationForm = () => {
  // State to hold form data and errors
  const [formData, setFormData] = useState({
    username: '',
    email: '',
    password: ''
  });

  const [errors, setErrors] = useState({
    username: '',
    email: '',
    password: ''
  });

  // Validation functions for each input field
  const validateUsername = (value) => {
    if (!value.trim()) {
      return 'Username is required';
    }
    return '';
  };

  const validateEmail = (value) => {
    const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return !re.test(String(value).toLowerCase()) ? 'Invalid email format' : '';
  };

  const validatePassword = (value) => {
    if (!value.trim()) {
      return 'Password is required';
    }
    return value.length < 8 ? 'Password must be at least 8 characters long' : '';
  };

  // Function to handle form submission
  const handleSubmit = (e) => {
    e.preventDefault();

    const usernameError = validateUsername(formData.username);
    const emailError = validateEmail(formData.email);
    const passwordError = validatePassword(formData.password);

    setErrors({
      username: usernameError,
      email: emailError,
      password: passwordError
    });

    // If there are no errors, proceed with form submission
    if (!usernameError && !emailError && !passwordError) {
      console.log('Form submitted:', formData);
      // You can here send the data to a server or perform other actions
    }
  };

  // Handle input changes
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label htmlFor="username">Username:</label>
        <input
          type="text"
          id="username"
          name="username"
          value={formData.username}
          onChange={handleChange}
        />
        {errors.username && <p style={{ color: 'red' }}>{errors.username}</p>}
      </div>
      <div>
        <label htmlFor="email">Email:</label>
        <input
          type="text"
          id="email"
          name="email"
          value={formData.email}
          onChange={handleChange}
        />
        {errors.email && <p style={{ color: 'red' }}>{errors.email}</p>}
      </div>
      <div>
        <label htmlFor="password">Password:</label>
        <input
          type="password"
          id="password"
          name="password"
          value={formData.password}
          onChange={handleChange}
        />
        {errors.password && <p style={{ color: 'red' }}>{errors.password}</p>}
      </div>
      <button type="submit">Register</button>
    </form>
  );
};

export default RegistrationForm;
