To build a React component for a countdown timer widget, we can use the `useState` hook to manage the state of the countdown timer and its display. We'll also need to handle user input for the countdown duration. Below is an example implementation:

```jsx
import React, { useState } from 'react';

const CountdownTimerWidget = () => {
  // State variables
  const [duration, setDuration] = useState('');
  const [countdown, setCountdown] = useState(0);
  const [isActive, setIsActive] = useState(false);

  // Function to update countdown timer
  const startCountdown = () => {
    setIsActive(true);
    const interval = setInterval(() => {
      if (countdown > 0) {
        setCountdown(countdown - 1);
      } else {
        clearInterval(interval);
        setIsActive(false);
        alert('Time is up!');
      }
    }, 1000);
  };

  // Function to reset countdown timer
  const resetCountdown = () => {
    setDuration('');
    setCountdown(0);
    setIsActive(false);
  };

  return (
    <div>
      <h2>Countdown Timer Widget</h2>

      {/* Duration input */}
      <input
        type="number"
        value={duration}
        onChange={(e) => setDuration(e.target.value)}
        placeholder="Enter countdown duration in seconds"
      />

      {/* Start/Stop button */}
      {isActive ? (
        <button onClick={() => setIsActive(false)}>Pause</button>
      ) : (
        <button onClick={startCountdown}>Start</button>
      )}

      {/* Countdown display */}
      {isActive && (
        <h3>Time remaining: {countdown} seconds</h3>
      )}

      {/* Reset button */}
      <button onClick={resetCountdown}>Reset</button>
    </div>
  );
};

export default CountdownTimerWidget;
