Here's an example of how to set up a basic Express server with a JWT validation endpoint:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');

// Create an instance of the Express application
const app = express();

// Middleware to parse JSON bodies
app.use(express.json());

// Sample secret key for JWT signing and verification (should be kept secure)
const SECRET_KEY = 'your-secret-key';

// Route to validate a JWT token
app.post('/validate-token', (req, res) => {
  // Get the token from the request header
  const token = req.headers.authorization;

  if (!token) {
    return res.status(401).json({ error: 'No token provided' });
  }

  try {
    // Verify the token using the SECRET_KEY
    const decoded = jwt.verify(token, SECRET_KEY);

    // If verification is successful, send a success response
    res.json({ message: 'Token is valid', user: decoded.user });
  } catch (error) {
    if (error.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token has expired' });
    }
    // If token is invalid, send an error response
    res.status(403).json({ error: 'Invalid token' });
  }
});

