```

Here's the complete code:

```javascript
const WebSocket = require('ws');

// Create a WebSocket server on port 8080
const wss = new WebSocket.Server({ port: 8080 });

console.log('WebSocket server is running on port 8080.');

let clients = [];

wss.on('connection', (ws) => {
    console.log('Client connected');

    // Handle messages from the client
    ws.on('message', (message) => {
        console.log(`Received message: ${message}`);

        // Broadcast the received message to all connected clients
        clients.forEach((client) => {
            if (client.readyState === WebSocket.OPEN) {
                client.send(message);
            }
        });
    });

    // Handle when a client disconnects
    ws.on('close', () => {
        console.log('Client disconnected');
        clients = clients.filter(client => client !== ws);
    });
});

// Broadcasting middleware function
function broadcastMiddleware(req, res, next) {
    if (req.url.startsWith('/broadcast')) {
        const message = req.query.message;
        if (typeof message === 'string') {
            // Broadcast the received message to all connected clients
            clients.forEach((client) => {
                if (client.readyState === WebSocket.OPEN) {
                    client.send(message);
                }
            });
        } else {
            res.status(400).send('Invalid message');
        }
    } else {
        next();
    }
}

// Example route using the broadcasting middleware
wss.on('/broadcast', broadcastMiddleware, (req, res) => {
    res.writeHead(200, { 'Content-Type': 'text/plain' });
    res.end('Broadcast endpoint accessed');
});
