   ```

2. **Create the Middleware**:

   ```javascript
   const CryptoJS = require('crypto-js');
   const fs = require('fs');

   // Load your encryption key from a file or other secure source
   const secretKey = 'your-secret-key-16-bytes'; // 16 bytes for AES-128, 32 bytes for AES-256

   // Function to generate a random initialization vector (IV)
   function generateIv() {
     return CryptoJS.lib.WordArray.random(16).toString(CryptoJS.enc.Hex);
   }

   // Middleware for JSON payload encryption and decryption
   const encryptDecryptMiddleware = (req, res, next) => {
     try {
       // Encrypt the JSON payload if it's not already encrypted
       if (!req.body || !('encryptedPayload' in req.body)) {
         const iv = generateIv();
         const encryptedData = CryptoJS.AES.encrypt(JSON.stringify(req.body), secretKey).toString();
         req.body.encryptedPayload = { iv: iv, cipherText: encryptedData };
       }

       // Decrypt the JSON payload if it's encrypted
       if (req.body && 'encryptedPayload' in req.body) {
         const { iv, cipherText } = req.body.encryptedPayload;
         const decryptedData = CryptoJS.AES.decrypt(cipherText, secretKey).toString(CryptoJS.enc.Utf8);
         const parsedData = JSON.parse(decryptedData);
         req.body = parsedData;
       }

       next();
     } catch (error) {
       console.error('Error encrypting or decrypting JSON payload:', error);
       res.status(500).json({ message: 'Internal Server Error' });
     }
   };

   module.exports = encryptDecryptMiddleware;
   ```

3. **Usage**:

