Certainly! Below is an example of how you might create a basic PHP class for handling database operations using the PDO (PHP Data Objects) extension, which provides a uniform interface to access databases without needing to write different code for each type of database.

```php
<?php

class Database {
    private $host;
    private $dbname;
    private $username;
    private $password;
    private $pdo;

    public function __construct($host, $dbname, $username, $password) {
        $this->host = $host;
        $this->dbname = $dbname;
        $this->username = $username;
        $this->password = $password;

        // Attempt to connect to the database
        try {
            $dsn = "mysql:host=$this->host;dbname=$this->dbname;charset=utf8mb4";
            $options = [
                PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
                PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
                PDO::ATTR_EMULATE_PREPARES => false
            ];

            $this->pdo = new PDO($dsn, $this->username, $this->password, $options);
        } catch (PDOException $e) {
            echo "Connection failed: " . $e->getMessage();
            exit;
        }
    }

    public function query($sql, $params = []) {
        // Prepare and execute the SQL statement
        $stmt = $this->pdo->prepare($sql);

        if ($params) {
            foreach ($params as $key => $value) {
                $stmt->bindParam(":$key", $value);
            }
        }

        try {
            $stmt->execute();
            return $stmt;
        } catch (PDOException $e) {
            echo "Query failed: " . $e->getMessage();
            exit;
        }
    }

    public function fetchAll($sql, $params = []) {
        // Execute the query and fetch all rows
        $result = $this->query($sql, $params);
        return $result->fetchAll();
    }

    public function fetchOne($sql, $params = []) {
        // Execute the query and fetch a single row
        $result = $this->query($sql, $params);
        return $result->fetch();
    }

    public function insert($table, $data) {
        // Prepare an INSERT statement
        $fields = implode(', ', array_keys($data));
        $placeholders = ':' . implode(', :', array_keys($data));

        $sql = "INSERT INTO $table ($fields) VALUES ($placeholders)";

        // Execute the query
        return $this->query($sql, $data);
    }

    public function update($table, $data, $where) {
        // Prepare an UPDATE statement
        $updates = [];
        foreach ($data as $key => $value) {
            $updates[] = "$key = :$key";
        }

        $whereClause = "WHERE $where";

        $sql = "UPDATE $table SET " . implode(', ', $updates) . " $whereClause";

        // Execute the query
        return $this->query($sql, array_merge($data, [$where => $where]));
    }

    public function delete($table, $where) {
        // Prepare a DELETE statement
        $whereClause = "WHERE $where";

        $sql = "DELETE FROM $table $whereClause";

        // Execute the query
        return $this->query($sql);
    }
}

