echo "Insert ID: " . $insertResult->lastInsertId() . "\n";

$updateResult = $db->update('users', ['email' => 'johndoe@example.com'], 'id=1');
echo "Rows updated: " . $updateResult->rowCount() . "\n";

$deleteResult = $db->delete('users', 'id=1');
echo "Rows deleted: " . $deleteResult->rowCount() . "\n";
```

