```php
<?php

class FileManager {
    private $filename;

    // Constructor to initialize the filename
    public function __construct($filename) {
        $this->filename = $filename;
    }

    // Method to read from a file
    public function readFile() {
        if (file_exists($this->filename)) {
            return file_get_contents($this->filename);
        } else {
            throw new Exception("File not found");
        }
    }

    // Method to write to a file, overwriting existing content
    public function writeFile($content) {
        $result = file_put_contents($this->filename, $content);
        if ($result === false) {
            throw new Exception("Failed to write to file");
        } else {
            return true;
        }
    }

    // Method to append to a file
    public function appendToFile($content) {
        $result = file_put_contents($this->filename, $content, FILE_APPEND);
        if ($result === false) {
            throw new Exception("Failed to append to file");
        } else {
            return true;
        }
    }

    // Method to delete a file
    public function deleteFile() {
        if (file_exists($this->filename)) {
            unlink($this->filename);
            return true;
        } else {
            throw new Exception("File does not exist");
        }
    }
}

