        // Set the start element handler
        xml_set_element_handler($parser, 'startElement', 'handleStartElement');

        // Set the end element handler
        xml_set_end_element_handler($parser, 'handleEndElement');

        // Set the character data handler
        xml_set_character_data_handler($parser, 'handleCharacterData');

        // Parse the XML content
        if (!xml_parse($parser, $xmlContent)) {
            throw new Exception("XML parse error: " . xml_error_string(xml_get_last_error()));
        }

        // Free up memory allocated for parser
        xml_parser_free($parser);

        // Return the parsed data as an associative array
        return $this->assocArray;
    }

    private function handleStartElement($parser, $elementName) {
        // Initialize or reset the current element
        if (!isset($this->currentElement)) {
            $this->currentElement = [];
        }
    }

    private function handleEndElement($parser, $elementName) {
        // Pop the last element from the stack and set as parent
        array_pop($this->stack);
    }

    private function handleCharacterData($parser, $data) {
        // Append character data to the current element or nested element
        if (isset($this->currentElement)) {
            if (!isset($this->currentElement['text'])) {
