```php
<?php

class PdoSafeStatement {
    protected $pdo;
    protected $query;

    /**
     * Constructor initializes the PDO object.
     *
     * @param \PDO $pdo PDO instance
     */
    public function __construct($pdo) {
        if (!($pdo instanceof \PDO)) {
            throw new InvalidArgumentException('The first argument must be a PDO instance.');
        }
        $this->pdo = $pdo;
    }

    /**
     * Sets the SQL query to be executed.
     *
     * @param string $sql The SQL query
     */
    public function setQuery($sql) {
        $this->query = $sql;
    }

    /**
     * Binds parameters to the prepared statement and executes it.
     *
     * @param array $params An associative array of parameters to bind
     * @return \PDOStatement|false Result set or false on error
     */
    public function execute($params) {
        if (!is_array($params)) {
            throw new InvalidArgumentException('The second argument must be an associative array.');
        }

        $stmt = $this->pdo->prepare($this->query);
        foreach ($params as $key => $value) {
            $stmt->bindValue(":$key", $value, PDO::PARAM_STR); // Default to string
        }
        return $stmt->execute();
    }
}

