<?php

function verifyPassword($hash, $password) {
    // Use the default bcrypt algorithm for hashing passwords
    $algorithm = 'bcrypt';

    // Check if the hash has a valid prefix indicating its type
    switch (substr($hash, 0, 5)) {
        case '$2y$':
            $algorithm = 'bcrypt';
            break;
        case '$2a$':
            $algorithm = 'bcrypt';
            break;
        case '$5$':
            $algorithm = 'md5';
            break;
        default:
            return false; // Invalid hash format
    }

    // Verify the password using the correct algorithm
    switch ($algorithm) {
        case 'bcrypt':
            return password_verify($password, $hash);
        case 'md5':
            return md5($password) === $hash;
        default:
            return false; // Unsupported algorithm
    }
}

