```php
<?php

class Router {
    protected $routes = [];

    public function __construct() {
        // You can define routes here or load them from a configuration file
        $this->addRoute('GET', '/', 'HomeController@index');
        $this->addRoute('POST', '/submit', 'SubmitController@processForm');
    }

    public function addRoute($method, $path, $controller) {
        // Normalize the path to remove trailing slashes and ensure it ends with a slash
        $normalizedPath = rtrim($path, '/') . '/';

        if (!isset($this->routes[$method][$normalizedPath])) {
            $this->routes[$method][$normalizedPath] = [];
        }

        $this->routes[$method][$normalizedPath][] = $controller;
    }

    public function dispatch() {
        $requestMethod = $_SERVER['REQUEST_METHOD'];
        $requestUri = rtrim($_SERVER['REQUEST_URI'], '/');

        // Check if the route exists for the current method and URI
        foreach ($this->routes[$requestMethod] as $route => $controllers) {
            // Check if the route matches the current request URI
            if (strpos($requestUri, $route) === 0) {
                // Extract parameters from the path
                $parameters = [];
                preg_match_all('/{(\w+)}/', $route, $matches);
                foreach ($matches[1] as $index => $paramName) {
                    $value = isset($_GET[$paramName]) ? $_GET[$paramName] : null;
                    $parameters[] = $value;
                }

                // Call the first controller in the list
                list($controllerClass, $actionMethod) = array_shift($controllers);
                $controllerInstance = new $controllerClass();
                call_user_func_array([$controllerInstance, $actionMethod], $parameters);

                return;
            }
        }

        // If no route is found, you can handle 404 here
        http_response_code(404);
        echo "404 Not Found";
    }
}

// Example controller classes
