To provide a REST API endpoint for managing the custom taxonomy, you can use the `register_rest_route` function:

```php
function register_custom_taxonomy_routes() {
    // Get all terms in the custom category taxonomy
    add_action('rest_api_init', function () {
        register_rest_route('custom-taxonomy/v1', '/categories', array(
            'methods'  => 'GET',
            'callback' => 'get_all_categories',
        ));

        // Add a new category
        register_rest_route('custom-taxonomy/v1', '/categories', array(
            'methods'  => 'POST',
            'callback' => 'add_new_category',
        ));

        // Update an existing category
        register_rest_route('custom-taxonomy/v1', '/categories/(?P<id>[0-9]+)', array(
            'methods'  => 'PUT',
            'callback' => 'update_category',
        ));

        // Delete a category
        register_rest_route('custom-taxonomy/v1', '/categories/(?P<id>[0-9]+)', array(
            'methods'  => 'DELETE',
            'callback' => 'delete_category',
        ));
    });
}

// Function to get all categories
function get_all_categories($request) {
    $terms = get_terms(array('taxonomy' => 'custom_category'));
    return rest_ensure_response($terms);
}

// Function to add a new category
function add_new_category($request) {
    $data = $request->get_json_params();
    if (empty($data['name'])) {
        return new WP_Error('no_name', __('Name is required.', 'textdomain'), array('status' => 400));
    }

    $term = term_exists($data['name'], 'custom_category');
    if ($term) {
        return new WP_Error('category_exists', __('Category already exists.', 'textdomain'), array('status' => 409));
    }

    $new_term_id = wp_insert_term($data['name'], 'custom_category');
    if (is_wp_error($new_term_id)) {
        return rest_ensure_response(array('error' => $new_term_id->get_error_message()));
    }

    return rest_ensure_response($new_term_id);
}

// Function to update a category
function update_category($request) {
    $term_id = $request['id'];
    $data = $request->get_json_params();
    if (empty($data['name'])) {
        return new WP_Error('no_name', __('Name is required.', 'textdomain'), array('status' => 400));
    }

    $updated_term = wp_update_term($term_id, 'custom_category', array(
        'name' => $data['name']
    ));

    if (is_wp_error($updated_term)) {
        return rest_ensure_response(array('error' => $updated_term->get_error_message()));
    }

    return rest_ensure_response($updated_term);
}

// Function to delete a category
function delete_category($request) {
    $term_id = $request['id'];
    $deleted = wp_delete_term($term_id, 'custom_category');

    if (is_wp_error($deleted)) {
        return rest_ensure_response(array('error' => $deleted->get_error_message()));
    }

    return rest_ensure_response(true);
}

// Hook the function to 'rest_api_init'
add_action('rest_api_init', 'register_custom_taxonomy_routes');
