function enqueue_custom_scripts_styles() {
    // Check if the current post type is 'my_custom_post_type'
    global $post;
    if ($post->post_type === 'my_custom_post_type') {
        // Enqueue your scripts
        wp_enqueue_script('my-script', get_template_directory_uri() . '/assets/js/my-script.js', array(), '1.0', true);

        // Enqueue your styles
        wp_enqueue_style('my-style', get_template_directory_uri() . '/assets/css/my-style.css');
