            <input class="widefat" id="<?php echo $this->get_field_id('title'); ?>" name="<?php echo $this->get_field_name('title'); ?>" type="text" value="<?php echo esc_attr($title); ?>">
        </p>
        <?php
    }

    public function update($new_instance, $old_instance) {
        $instance = array();
        $instance['title'] = (!empty($new_instance['title'])) ? strip_tags($new_instance['title']) : '';
        return $instance;
    }
}

function register_bulk_actions_widget() {
    register_widget('BulkActionsWidget');
}
add_action('widgets_init', 'register_bulk_actions_widget');

// AJAX handler for bulk actions
function handle_bulk_actions() {
    if (!isset($_POST['action']) || !wp_verify_nonce($_POST['bulk-actions-widget-nonce'], 'bulk_actions_widget_nonce')) {
        wp_die();
    }

    $action = sanitize_text_field($_POST['action']);
    $ids = isset($_POST['ids']) ? $_POST['ids'] : array();

    if ($action === 'trash') {
        foreach ($ids as $id) {
            wp_trash_post($id);
        }
    } elseif ($action === 'delete') {
        foreach ($ids as $id) {
            wp_delete_post($id, true); // true for force delete
        }
    }

    echo json_encode(array('success' => true));
    die();
}
add_action('wp_ajax_handle_bulk_actions', 'handle_bulk_actions');
