import React, { useState, useEffect, useContext } from 'react';
import { useParams, useHistory } from 'react-router-dom';
import { PostContext } from '../context/PostContext';

const DetailPage = () => {
  const [post, setPost] = useState(null);
  const [error, setError] = useState(null);
  const history = useHistory();
  const { postId } = useParams();

  // Fetch the post data based on the postId parameter
  useEffect(() => {
    const fetchPost = async () => {
      try {
        const response = await fetch(`https://api.example.com/posts/${postId}`);
        if (!response.ok) {
          throw new Error('Network response was not ok');
        }
        const data = await response.json();
        setPost(data);
      } catch (err) {
        setError(err.message);
      }
    };
    fetchPost();
  }, [postId]);

  // Handle error
  useEffect(() => {
    if (error) {
      setTimeout(() => history.push('/'), 3000); // Redirect to home page after 3 seconds
    }
  }, [error, history]);

  if (!post && !error) return <div>Loading...</div>;

  if (error) return (
    <div>
      <h1>Error: {error}</h1>
      <button onClick={() => history.push('/')}>Go back to home</button>
    </div>
  );

  const handleDelete = async () => {
    try {
      const response = await fetch(`https://api.example.com/posts/${postId}`, {
        method: 'DELETE',
      });
      if (!response.ok) {
        throw new Error('Network response was not ok');
      }
      history.push('/');
    } catch (err) {
      setError(err.message);
    }
  };

  return (
    <div>
      <h1>{post.title}</h1>
      <p>{post.content}</p>
      <ul>
        {post.comments.map((comment, index) => (
          <li key={index}>{comment.text}</li>
        ))}
      </ul>
      <button onClick={handleDelete}>Delete Post</button>
    </div>
  );
};

export default DetailPage;
