import React, { useState, useEffect, useContext } from 'react';
import axios from 'axios';
import { useHistory } from 'react-router-dom';
import { AuthContext } from '../context/AuthContext';

const FormPage = ({ editMode, initialData }) => {
  const history = useHistory();
  const [formData, setFormData] = useState(initialData || {});
  const [errors, setErrors] = useState({});
  const { user } = useContext(AuthContext);

  useEffect(() => {
    if (editMode) {
      // Fetch data from backend to populate form fields
      axios.get(`/api/items/${initialData.id}`)
        .then(response => setFormData(response.data))
        .catch(error => console.error('Error fetching item:', error));
    }
  }, [initialData, editMode]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      // Validate form data
      if (!formData.title || !formData.content) {
        return setErrors({
          title: 'Title is required',
          content: 'Content is required'
        });
      }

      const token = localStorage.getItem('token');
      const headers = { Authorization: `Bearer ${token}` };

      if (editMode) {
        // Update item
        await axios.put(`/api/items/${initialData.id}`, formData, { headers });
        history.push('/');
      } else {
        // Create new item
        const response = await axios.post('/api/items', { ...formData, userId: user.id }, { headers });
        setFormData({});
        history.push('/');
      }

      // Clear errors
      setErrors({});
    } catch (error) {
      console.error('Error submitting form:', error);
      setErrors({ serverError: 'There was a problem with the server.' });
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label htmlFor="title">Title:</label>
        <input
          type="text"
          id="title"
          name="title"
          value={formData.title || ''}
          onChange={handleChange}
          required
          className={errors.title ? 'error' : ''}
        />
        {errors.title && <p>{errors.title}</p>}
      </div>
      <div>
        <label htmlFor="content">Content:</label>
        <textarea
          id="content"
          name="content"
          value={formData.content || ''}
          onChange={handleChange}
          required
          className={errors.content ? 'error' : ''}
        />
        {errors.content && <p>{errors.content}</p>}
      </div>
      {errors.serverError && <p style={{ color: 'red' }}>{errors.serverError}</p>}
      <button type="submit">Submit</button>
    </form>
  );
};

export default FormPage;
```

