<?php

// Load WordPress environment
require_once(ABSPATH . 'wp-load.php');

class TodoListAPI {
    private $wpdb;

    public function __construct() {
        $this->wpdb = $GLOBALS['wpdb'];
        add_action('rest_api_init', array($this, 'register_routes'));
    }

    public function register_routes() {
        register_rest_route('todo/v1', '/todos/(?P<id>\d+)', array(
            'methods' => 'GET',
            'callback' => array($this, 'get_todo'),
        ));
        register_rest_route('todo/v1', '/todos', array(
            'methods' => 'POST',
            'callback' => array($this, 'create_todo'),
        ));
    }

    public function get_todo($request) {
        $id = (int)$request['id'];
        $todo = $this->wpdb->get_row("SELECT * FROM wp_todos WHERE id = {$id}", ARRAY_A);
        if ($todo && wp_check_admin_referer('wp_rest', '_nonce')) {
            return rest_ensure_response($todo);
        } else {
            return new WP_Error('not_found', __('Todo not found'), array('status' => 404));
        }
    }

    public function create_todo($request) {
        $title = sanitize_text_field($request['title']);
        if (!empty($title)) {
            $todo_id = $this->wpdb->insert('wp_todos', array(
                'title' => $title,
            ), array('%s'));
            return rest_ensure_response(array('id' => $todo_id));
        } else {
            return new WP_Error('invalid_request', __('Title is required'), array('status' => 400));
        }
    }

}

new TodoListAPI();
?>
