import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

const FormPage = () => {
  const [item, setItem] = useState({
    name: '',
    price: '',
    description: '',
    quantity: 1,
  });
  const [errors, setErrors] = useState({});
  const navigate = useNavigate();

  // Simulate fetching item details from server for edit
  useEffect(() => {
    if (window.location.pathname.includes('/edit/')) {
      axios.get(`/api/items/${window.location.pathname.split('/')[2]}`)
        .then((response) => {
          setItem(response.data);
        })
        .catch((error) => console.error('Error fetching item details:', error));
    }
  }, []);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setItem({ ...item, [name]: value });
    if (value.trim() === '') {
      setErrors({ ...errors, [name]: 'This field is required.' });
    } else {
      delete errors[name];
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    let hasError = false;
    for (const key in item) {
      if (item[key].trim() === '') {
        hasError = true;
        setErrors({ ...errors, [key]: 'This field is required.' });
      } else if (key === 'price' && isNaN(item.price)) {
        hasError = true;
        setErrors({ ...errors, price: 'Price must be a number.' });
      }
    }

    if (!hasError) {
      try {
        await axios.post('/api/items', item);
        navigate('/');
      } catch (error) {
        console.error('Error creating/editing item:', error);
      }
    }
  };

  return (
    <form onSubmit={handleSubmit}>
      <div>
        <label htmlFor="name">Item Name:</label>
        <input
          type="text"
          id="name"
          name="name"
          value={item.name}
          onChange={handleChange}
        />
        {errors.name && <p style={{ color: 'red' }}>{errors.name}</p>}
      </div>
      <div>
        <label htmlFor="price">Price:</label>
        <input
