      </div>
      <div>
        <label htmlFor="description">Description:</label>
        <textarea
          id="description"
          name="description"
          value={item.description}
          onChange={handleChange}
        />
      </div>
      <button type="submit">{window.location.pathname.includes('/edit/') ? 'Edit' : 'Create'}</button>
    </form>
  );
};

