            <li><a href="/cart">Cart</a></li>
          </ul>
        </nav>

        <Switch>
          <Route path="/" exact>
            <ProductList products={products} addToCart={addToCart} />
          </Route>
          <Route path="/cart">
            <ShoppingCart cartItems={cartItems} />
          </Route>
          {/* Redirect to Home if user goes to undefined route */}
          <Redirect to="/" />
        </Switch>
      </div>
    </Router>
  );
}

// Context Provider for managing cart
const CartContextProvider = ({ children }) => {
  return (
    <CartContext.Provider value={{ cartItems, addToCart }}>
      {children}
    </CartContext.Provider>
  );
};

// Product List component to display products
function ProductList({ products, addToCart }) {
  if (!products) return <p>Loading...</p>;

  return (
    <div className="product-list">
      {products.map(product => (
        <div key={product.id}>
          <h3>{product.name}</h3>
          <p>Price: ${product.price}</p>
          <button onClick={() => addToCart(product)}>Add to Cart</button>
        </div>
      ))}
    </div>
  );
}

// ShoppingCart component to display cart items
function ShoppingCart({ cartItems }) {
  if (cartItems.length === 0) return <p>Your cart is empty.</p>;

  const total = cartItems.reduce((acc, item) => acc + item.price * item.quantity, 0);

  return (
    <div className="shopping-cart">
      <h3>Shopping Cart</h3>
      <ul>
        {cartItems.map(item => (
          <li key={item.id}>
            {item.name} - Quantity: {item.quantity} - Price: ${item.price * item.quantity}
          </li>
        ))}
      </ul>
      <p>Total: ${total.toFixed(2)}</p>
    </div>
  );
}

// Exporting components and provider
export { App, CartContextProvider };
