const express = require('express');
const bodyParser = require('body-parser');
const jwt = require('jsonwebtoken');
const logger = require('./logger'); // Assuming you have a logger module

// Middleware to parse JSON bodies
app.use(bodyParser.json());

// Authentication middleware using JWT
const authenticate = async (req, res, next) => {
  try {
    const token = req.headers['x-access-token'];
    if (!token) return res.status(401).json({ message: 'No token provided' });

    jwt.verify(token, process.env.JWT_SECRET, (err, decoded) => {
      if (err) return res.status(500).json({ message: 'Failed to authenticate token' });
      req.user = decoded; // Attach user info to request
      next();
    });
  } catch (error) {
    logger.error('Authentication failed:', error);
    res.status(401).json({ message: 'Failed to authenticate token' });
  }
};

// Validation middleware for product IDs
const validateProductId = async (req, res, next) => {
  const productId = req.params.id;
  if (!productId || !/^\d+$/.test(productId)) {
    return res.status(400).json({ message: 'Invalid product ID' });
  }

  // Example database query to check if product exists
  try {
    const productExists = await Product.findById(productId);
    if (!productExists) {
      throw new Error('Product not found');
    }
  } catch (error) {
    logger.error('Error checking product existence:', error);
    res.status(500).json({ message: 'Failed to validate product ID' });
  }

  req.productId = productId; // Attach product ID to request
  next();
};

module.exports = { authenticate, validateProductId };
