import React, { useState, useEffect } from 'react';
import { Form, Button, Alert, Container } from 'react-bootstrap';

// Dummy API for demonstration purposes
const API_URL = 'https://api.taskmanagement.com/items';

function FormPage() {
  const [item, setItem] = useState({
    id: '',
    title: '',
    description: '',
    status: ''
  });

  const [errors, setErrors] = useState({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [successMessage, setSuccessMessage] = useState('');

  useEffect(() => {
    // Retrieve item if an ID is provided in the URL
    fetch(`${API_URL}/${itemId}`)
      .then(response => response.json())
      .then(data => setItem(data))
      .catch(error => console.error('Error fetching item:', error));
  }, [itemId]);

  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setItem({ ...item, [name]: value });
  };

  const handleSubmit = async (event) => {
    event.preventDefault();
    setIsSubmitting(true);

    try {
      // Validate input
      const validationErrors = {};
      if (!item.title.trim()) validationErrors.title = 'Title is required';
      if (!item.description.trim()) validationErrors.description = 'Description is required';

      setErrors(validationErrors);

      if (Object.keys(validationErrors).length > 0) return;

      // Create or update item
      const response = await fetch(API_URL + (itemId ? `/${itemId}` : ''), {
        method: itemId ? 'PUT' : 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(item)
      });

      if (!response.ok) throw new Error('Failed to create or update item');

      const result = await response.json();
      setSuccessMessage('Item saved successfully');
      setIsSubmitting(false);
    } catch (error) {
      console.error('Error saving item:', error);
      setIsSubmitting(false);
    }
  };

  return (
    <Container>
      {successMessage && <Alert variant="success">{successMessage}</Alert>}
      <h1>{itemId ? 'Edit Item' : 'Create New Item'}</h1>
      <Form onSubmit={handleSubmit}>
        <Form.Group controlId="title">
          <Form.Label>Title</Form.Label>
          <Form.Control
            type="text"
            name="title"
            value={item.title}
            onChange={handleInputChange}
            isInvalid={!!errors.title}
          />
          <Form.Control.Feedback type="invalid">{errors.title}</Form.Control.Feedback>
        </Form.Group>

        <Form.Group controlId="description">
          <Form.Label>Description</Form.Label>
          <Form.Control
            as="textarea"
            rows={3}
            name="description"
            value={item.description}
            onChange={handleInputChange}
            isInvalid={!!errors.description}
          />
          <Form.Control.Feedback type="invalid">{errors.description}</Form.Control.Feedback>
        </Form.Group>

        <Form.Group controlId="status">
          <Form.Label>Status</Form.Label>
          <Form.Select
            name="status"
            value={item.status}
            onChange={handleInputChange}
          >
            <option value="">-- Select Status --</option>
            <option value="pending">Pending</option>
            <option value="in progress">In Progress</option>
            <option value="completed">Completed</option>
          </Form.Select>
        </Form.Group>

        <Button variant="primary" type="submit" disabled={isSubmitting}>
          {isSubmitting ? 'Saving...' : itemId ? 'Update Item' : 'Create Item'}
        </Button>
      </Form>
    </Container>
  );
}

export default FormPage;
