// App.jsx

import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Route, Switch, Redirect, useHistory } from 'react-router-dom';
import Home from './components/Home';
import TeamDetails from './components/TeamDetails';
import TeamForm from './components/TeamForm';
import ErrorPage from './components/ErrorPage';

// Context for team management
const TeamContext = React.createContext();

function App() {
  const [teams, setTeams] = useState([]);
  const history = useHistory();

  // Fetch teams on component mount
  useEffect(() => {
    fetch('https://api.example.com/teams')
      .then(response => response.json())
      .then(data => setTeams(data))
      .catch(error => console.error('Error fetching teams:', error));
  }, []);

  const addTeam = (newTeam) => {
    // Simulate adding a team to the server
    fetch('https://api.example.com/teams', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newTeam),
    })
      .then(response => response.json())
      .then(data => setTeams([...teams, data]))
      .catch(error => console.error('Error adding team:', error));
  };

  const updateTeam = (id, updatedTeam) => {
    // Simulate updating a team on the server
    fetch(`https://api.example.com/teams/${id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(updatedTeam),
    })
      .then(response => response.json())
      .then(data => setTeams(teams.map(t => t.id === id ? data : t)))
      .catch(error => console.error('Error updating team:', error));
  };

  const deleteTeam = (id) => {
    // Simulate deleting a team from the server
    fetch(`https://api.example.com/teams/${id}`, { method: 'DELETE' })
      .then(() => setTeams(teams.filter(t => t.id !== id)))
      .catch(error => console.error('Error deleting team:', error));
  };

  return (
    <Router>
      <TeamContext.Provider value={{ teams, addTeam, updateTeam, deleteTeam }}>
        <nav>
          <ul>
            <li><Link to="/">Home</Link></li>
            <li><Link to="/teams">Teams</Link></li>
            <li><Link to="/add-team">Add Team</Link></li>
          </ul>
        </nav>
        <Switch>
          <Route path="/" exact component={Home} />
          <Route path="/teams" render={() => <TeamList teams={teams} />} />
          <Route path="/teams/:id" component={({ match }) => (
            <TeamDetails teamId={match.params.id} />
          )} />
          <Route path="/add-team" component={TeamForm} />
          <Route component={ErrorPage} />
        </Switch>
      </TeamContext.Provider>
    </Router>
  );
}

function TeamList({ teams }) {
  return (
    <div>
      <h1>Teams</h1>
      {teams.length === 0 ? (
        <p>No teams available.</p>
      ) : (
        <ul>
          {teams.map(team => (
            <li key={team.id}>
              {team.name} - {team.description}
              <button onClick={() => history.push(`/teams/${team.id}`)}>View Details</button>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default App;
