function FormPage() {
  // State for form input fields and error handling
  const [formData, setFormData] = useState({
    name: '',
    temperature: '',
  });

  const [errors, setErrors] = useState({});
  const [submitting, setSubmitting] = useState(false);

  // Function to handle form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    setSubmitting(true);
    try {
      // Simulate API call for creating or editing an item
      const response = await axios.post('/api/items', formData);
      // Assuming the API returns updated data
      const updatedData = { ...formData, id: response.data.id };
      // Set state with new data and reset form
      setFormData(updatedData);
      setErrors({});
    } catch (error) {
      console.error('Error submitting form:', error);
      setErrors(error.response ? error.response.data.errors : {});
    } finally {
      setSubmitting(false);
    }
  };

  // Function to handle input changes
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value,
    });
  };

  return (
    <div>
      <h1>Form Page</h1>
      <form onSubmit={handleSubmit}>
        <div>
          <label htmlFor="name">Name:</label>
          <input
            type="text"
            id="name"
            name="name"
            value={formData.name}
            onChange={handleChange}
            required
