  const [loading, setLoading] = useState(false);
  const { id } = useParams();

  // Context provider to share loading state with children components
  return (
    <LoadingContext.Provider value={{ loading }}>
      <div className="detail-page">
        {/* Conditional rendering based on loading state */}
        {loading ? (
          <p>Loading...</p>
        ) : item ? (
          <div>
            <h1>{item.title}</h1>
            <p>{item.description}</p>
            {/* Add more details as needed */}
          </div>
        ) : (
          <p>No item found</p>
        )}
      </div>
    </LoadingContext.Provider>
  );
}

// Higher-order component to manage API fetching and loading states
function withDetailFetching(Component) {
  return function WrappedComponent({ ...props }) {
    const [loading, setLoading] = useState(true);
    const { id } = useParams();
    const [item, setItem] = useState(null);

    // Fetch item data from API on component mount
    useEffect(() => {
      const fetchData = async () => {
        try {
          setLoading(true);
          const response = await axios.get(`https://api.example.com/items/${id}`);
          if (response.data) {
            setItem(response.data);
          }
        } catch (error) {
          console.error('Error fetching item:', error);
        } finally {
          setLoading(false);
        }
      };

      fetchData();
    }, [id]);

    // Pass loading state as context to children components
    return (
      <LoadingContext.Provider value={{ loading }}>
        <Component {...props} item={item} />
      </LoadingContext.Provider>
    );
  };
}

// Example usage of withDetailFetching higher-order component
function ItemDetails({ item }) {
