<?php

class RandomQuoteGeneratorPlugin {
    private $db;
    private $api_url = 'https://api.example.com/quote'; // Replace with your API URL

    public function __construct($wpdb) {
        $this->db = $wpdb;

        add_action('init', [$this, 'register_post_type']);
        add_action('wp_enqueue_scripts', [$this, 'enqueue_scripts']);
        add_action('the_content', [$this, 'add_random_quote_button']);
    }

    public function register_post_type() {
        register_post_type('random-quote', array(
            'public' => true,
            'has_archive' => true,
            'rewrite' => array('slug' => 'quotes'),
        ));
    }

    public function enqueue_scripts() {
        wp_enqueue_script('random-quote-generator-script', plugin_dir_url(__FILE__) . 'js/random-quote-generator.js');
    }

    public function add_random_quote_button($content) {
        if (is_single('random-quote')) {
            $button_html = '<a href="#" class="load-quote">Load Quote</a>';
            return $content . $button_html;
        }
        return $content;
    }

    public function load_quote() {
        // Sanitize and validate input
        $post_id = filter_input(INPUT_GET, 'post', FILTER_VALIDATE_INT);
        if (!$post_id) {
            wp_die('Invalid post ID');
        }

        // Query the database for existing quote
        $quote_query = $this->db->prepare("SELECT quote FROM wp_posts WHERE id = %d", $post_id);
        $existing_quote = $this->db->get_var($quote_query);

        if (!$existing_quote) {
            // Fetch random quote from API
            try {
                $response = file_get_contents($this->api_url);
                $data = json_decode($response, true);

                if (isset($data['quote'])) {
                    // Insert the quote into the database
                    $insert_query = $this->db->prepare("INSERT INTO wp_posts (post_title, post_content) VALUES (%s, %s)", $data['author'], $data['quote']);
                    $result = $this->db->query($insert_query);

                    if ($result === false) {
                        wp_die('Error saving quote');
                    }

                    // Return the new post ID
                    $new_post_id = $this->db->last_insert_id();
                    echo json_encode(array('id' => $new_post_id));
                } else {
                    wp_die('Invalid API response');
                }
            } catch (Exception $e) {
                wp_die('Error fetching quote from API: ' . $e->getMessage());
            }
        }

        // Display the existing or newly fetched quote
        return '<p>' . htmlspecialchars($existing_quote) . '</p>';
    }

}

add_action('plugins_loaded', function () {
    global $wpdb;
    new RandomQuoteGeneratorPlugin($wpdb);
});
?>
