// Define the API endpoint class
class WP_API_Endpoint {
    private $db_host;
    private $db_user;
    private $db_pass;
    private $db_name;

    public function __construct($host, $user, $pass, $dbname) {
        $this->db_host = $host;
        $this->db_user = $user;
        $this->db_pass = $pass;
        $this->db_name = $dbname;
    }

    // Function to get a random quote
    public function getRandomQuote() {
        global $wpdb;

        try {
            // Connect to the database
            $wpdb->connect();

            // Prepare and execute the query
            $query = "SELECT * FROM quotes ORDER BY RAND() LIMIT 1";
            $result = $wpdb->get_row($query);

            if ($result) {
                return array(
                    'id' => $result->id,
                    'quote' => esc_html($result->quote),
                    'author' => esc_html($result->author)
                );
            }

        } catch (Exception $e) {
            // Handle any database errors
            error_log('Error fetching quote: ' . $e->getMessage());
            return array('error' => 'An error occurred while fetching the quote.');
        }
    }
}

