  // Function to add a new expense
  const handleAddExpense = () => {
    if (newExpense) {
      setExpenses([...expenses, { id: expenses.length + 1, amount: parseFloat(newExpense) }]);
      setBalance(balance + parseFloat(newExpense));
      setNewExpense('');
    }
  };

  // Function to delete an expense
  const handleDeleteExpense = (id) => {
    setExpenses(expenses.filter((expense) => expense.id !== id));
    setBalance(balance - expenses.find((e) => e.id === id).amount);
  };

  useEffect(() => {
