    const mockData = [
      { id: 1, amount: -50 },
      { id: 2, amount: 100 }
    ];
    setExpenses(mockData);
    setBalance(mockData.reduce((acc, expense) => acc + expense.amount, 0));
  }, []);

  return (
    <ExpenseContext.Provider value={{ expenses, balance }}>
      <div className="home-page">
