// Import necessary modules
const express = require('express');
const bodyParser = require('body-parser');
const mongoose = require('mongoose');

// Initialize Express application
const app = express();

// Connect to MongoDB database
mongoose.connect('mongodb://localhost:27017/expenseTracker', { useNewUrlParser: true, useUnifiedTopology: true });

// Middleware setup
app.use(bodyParser.json());

// Define Expense model schema
const expenseSchema = new mongoose.Schema({
  description: String,
  amount: Number,
  category: String,
});

const Expense = mongoose.model('Expense', expenseSchema);

// Error handling middleware
function errorHandler(err, req, res, next) {
  console.error(err);
  res.status(500).send('Something went wrong');
}

app.use(errorHandler);

// API endpoints

// Get all expenses
app.get('/expenses', async (req, res) => {
  try {
    const expenses = await Expense.find();
    res.json(expenses);
  } catch (err) {
    next(err);
  }
});

// Create a new expense
app.post('/expenses', async (req, res) => {
  const { description, amount, category } = req.body;
  if (!description || !amount || !category) {
    return res.status(400).send('Missing required fields');
  }

  try {
    const expense = new Expense({ description, amount, category });
    await expense.save();
    res.json(expense);
  } catch (err) {
    next(err);
  }
});

// Delete an expense by ID
app.delete('/expenses/:id', async (req, res) => {
  try {
    const expense = await Expense.findByIdAndDelete(req.params.id);
    if (!expense) {
      return res.status(404).send('Expense not found');
    }
    res.json(expense);
  } catch (err) {
    next(err);
  }
});

// Update an expense by ID
app.put('/expenses/:id', async (req, res) => {
  const { description, amount, category } = req.body;
  if (!description && !amount && !category) {
    return res.status(400).send('Missing required fields');
  }

  try {
    const expense = await Expense.findByIdAndUpdate(req.params.id, { description, amount, category }, { new: true });
    if (!expense) {
      return res.status(404).send('Expense not found');
    }
    res.json(expense);
  } catch (err) {
    next(err);
  }
});

// Start the server
