import React, { useState, useEffect, useContext } from 'react';
import { TodoContext } from './TodoContext'; // Assuming TodoContext is defined in another file

const FormPage = () => {
  const [todoText, setTodoText] = useState('');
  const [errors, setErrors] = useState({});
  const { todos, createTodo, updateTodo, deleteTodo, currentEditingIndex } = useContext(TodoContext);

  useEffect(() => {
    if (currentEditingIndex !== null) {
      setTodoText(todos[currentEditingIndex].text);
    }
  }, [currentEditingIndex, todos]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    let errorCount = 0;

    // Validate input
    if (!todoText.trim()) {
      setErrors((prevErrors) => ({
        ...prevErrors,
        text: 'Todo text is required.',
      }));
      errorCount++;
    }

    if (errorCount === 0 && currentEditingIndex !== null) {
      updateTodo(currentEditingIndex, todoText);
    } else if (currentEditingIndex === null) {
      createTodo(todoText);
    }
  };

  const handleInputChange = (e) => {
    setTodoText(e.target.value);
    setErrors((prevErrors) => ({
      ...prevErrors,
      text: '',
    }));
  };

  return (
    <form onSubmit={handleSubmit}>
      <input
        type="text"
        value={todoText}
        onChange={handleInputChange}
        placeholder="Add new todo"
        className={`form-control ${errors.text ? 'is-invalid' : ''}`}
      />
      {errors.text && <div className="invalid-feedback">{errors.text}</div>}
      <button type="submit" className="btn btn-primary mt-2">
        {currentEditingIndex !== null ? 'Update Todo' : 'Add Todo'}
      </button>
    </form>
  );
};

export default FormPage;
