const express = require('express');
const router = express.Router();
const jwt = require('jsonwebtoken');

// Mock database for demonstration purposes
let todos = [];

// Middleware to validate token
router.use((req, res, next) => {
  const token = req.headers.authorization;

  if (!token) return res.status(401).json({ error: 'No token provided' });

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded.userId; // Assuming the token contains userId
    next();
  } catch (err) {
    return res.status(403).json({ error: 'Invalid token' });
  }
});

// Middleware to log requests
router.use((req, res, next) => {
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.url}`);
  next();
});

// Mock data validation middleware
const validateTodo = (todo) => {
  if (!todo.title || !todo.completed) throw new Error('Title and completed fields are required');
};

// CRUD operations with authentication/validaton

// Create a todo item
router.post('/todos', async (req, res) => {
  try {
    const { title, completed } = req.body;
    validateTodo({ title, completed });
    todos.push({ id: todos.length + 1, title, completed });
    res.status(201).json(todos[todos.length - 1]);
  } catch (err) {
    res.status(400).json({ error: err.message });
  }
});

// Get all todo items
router.get('/todos', async (req, res) => {
  try {
    res.json(todos);
  } catch (err) {
    res.status(500).json({ error: 'Error fetching todos' });
  }
});

// Update a todo item by ID
router.put('/todos/:id', async (req, res) => {
  const { id } = req.params;
  const { title, completed } = req.body;

  try {
    validateTodo({ title, completed });

    const todoIndex = todos.findIndex(t => t.id === parseInt(id));
    if (todoIndex === -1) return res.status(404).json({ error: 'Todo not found' });

    todos[todoIndex] = { id: todos[todoIndex].id, title, completed };
    res.json(todos[todoIndex]);
  } catch (err) {
    res.status(400).json({ error: err.message });
  }
});

// Delete a todo item by ID
router.delete('/todos/:id', async (req, res) => {
  const { id } = req.params;

  try {
    const todoIndex = todos.findIndex(t => t.id === parseInt(id));
    if (todoIndex === -1) return res.status(404).json({ error: 'Todo not found' });

    todos.splice(todoIndex, 1);
    res.json({ message: 'Todo deleted successfully' });
