import React, { useState, useEffect } from 'react';
import axios from 'axios';

// Context for form data
const FormContext = React.createContext();

// FormPage component
const FormPage = () => {
  const [formData, setFormData] = useState({
    name: '',
    value: '',
    currency: ''
  });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [showSuccessMessage, setShowSuccessMessage] = useState(false);

  // Function to handle form change
  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData({ ...formData, [name]: value });
    validateField(name, value);
  };

  // Function to validate a field
  const validateField = (field, value) => {
    let newErrors = {};

    switch (field) {
      case 'name':
        if (!value.trim()) {
          newErrors.name = 'Name is required';
        }
        break;
      case 'value':
        if (isNaN(value)) {
          newErrors.value = 'Value must be a number';
        } else if (value <= 0) {
          newErrors.value = 'Value must be greater than zero';
        }
        break;
      case 'currency':
        if (!value.trim()) {
          newErrors.currency = 'Currency is required';
        }
        break;
      default:
        break;
    }

    setErrors(newErrors);
  };

  // Function to handle form submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      await axios.post('/api/items', formData);
      setShowSuccessMessage(true);
    } catch (error) {
      console.error('Error creating item:', error);
      setErrors({ server: 'Failed to create item. Please try again.' });
    } finally {
      setLoading(false);
    }
  };

  // Clear success message after 5 seconds
  useEffect(() => {
    if (showSuccessMessage) {
      setTimeout(() => setShowSuccessMessage(false), 5000);
    }
  }, [showSuccessMessage]);

  return (
    <FormContext.Provider value={{ formData, handleChange }}>
      <form onSubmit={handleSubmit} className="form">
        <div>
          <label htmlFor="name">Name:</label>
          <input
            type="text"
            id="name"
            name="name"
            value={formData.name}
            onChange={handleChange}
            placeholder="Item Name"
            required
          />
          {errors.name && <span className="error">{errors.name}</span>}
        </div>
        <div>
          <label htmlFor="value">Value:</label>
          <input
            type="number"
            id="value"
            name="value"
            value={formData.value}
            onChange={handleChange}
            placeholder="Item Value"
            required
          />
          {errors.value && <span className="error">{errors.value}</span>}
        </div>
        <div>
          <label htmlFor="currency">Currency:</label>
          <input
            type="text"
            id="currency"
            name="currency"
            value={formData.currency}
            onChange={handleChange}
            placeholder="Item Currency"
            required
          />
          {errors.currency && <span className="error">{errors.currency}</span>}
        </div>
        <button type="submit" disabled={loading}>
          {loading ? 'Submitting...' : 'Submit'}
        </button>
      </form>
      {showSuccessMessage && (
        <p className="success">Item created successfully!</p>
      )}
    </FormContext.Provider>
  );
};

export default FormPage;
```

