const ListPage = () => {
    // Context for shared state and functions
    const CounterContext = React.createContext();

    // Local state management
    const [count, setCount] = useState(0);
    const [stepSize, setStepSize] = useState(1);

    // Effect to handle initial value update
    useEffect(() => {
        try {
            if (localStorage.getItem('count')) {
                setCount(JSON.parse(localStorage.getItem('count')));
            }
            if (localStorage.getItem('stepSize')) {
                setStepSize(JSON.parse(localStorage.getItem('stepSize')));
            }
        } catch (error) {
            console.error('Error reading local storage:', error);
        }
    }, []);

    // Effect to save state changes to local storage
    useEffect(() => {
        try {
            localStorage.setItem('count', JSON.stringify(count));
            localStorage.setItem('stepSize', JSON.stringify(stepSize));
        } catch (error) {
            console.error('Error writing to local storage:', error);
        }
    }, [count, stepSize]);

    // Function to increment count
    const increment = () => {
        setCount((prevCount) => prevCount + stepSize);
    };

    // Function to decrement count
    const decrement = () => {
        if (count > 0) {
            setCount((prevCount) => prevCount - stepSize);
        }
    };

    // Function to reset count
    const reset = () => {
        setCount(0);
    };

    return (
