<?php

namespace CounterMaster;

use WP_REST_Controller;
use WP_Error;
use WP_REST_Request;

class CounterMaster extends WP_REST_Controller {

    public function __construct() {
        $this->namespace = 'counter-master/v1';
        $this->rest_base = 'counter';
        parent::__construct();
    }

    /**
     * Register the routes for this controller.
     */
    public function register_routes() {
        register_rest_route(
            $this->namespace,
            '/' . $this->rest_base . '/increment',
            array(
                'methods'  => WP_REST_Server::POST,
                'callback' => array($this, 'increment_counter'),
                'permission_callback' => '__return_true',
            )
        );

        register_rest_route(
            $this->namespace,
            '/' . $this->rest_base . '/decrement',
            array(
                'methods'  => WP_REST_Server::POST,
                'callback' => array($this, 'decrement_counter'),
                'permission_callback' => '__return_true',
            )
        );

        register_rest_route(
            $this->namespace,
            '/' . $this->rest_base . '/reset',
            array(
                'methods'  => WP_REST_Server::POST,
                'callback' => array($this, 'reset_counter'),
                'permission_callback' => '__return_true',
            )
        );

        register_rest_route(
            $this->namespace,
            '/' . $this->rest_base . '/set-step',
            array(
                'methods'  => WP_REST_Server::POST,
                'callback' => array($this, 'set_step'),
                'permission_callback' => '__return_true',
            )
        );
    }

    /**
     * Increment the counter.
     *
     * @param \WP_REST_Request $request The request object.
     * @return mixed
     */
    public function increment_counter($request) {
        global $wpdb;

        // Validate and sanitize input parameters
        $step = (int)$request->get_param('step', 1);
        if ($step < 0) {
            return new WP_Error('invalid_step', 'Step size must be a non-negative integer.', array('status' => 400));
        }

        // Prepare the SQL query to update the counter
        $sql = "UPDATE wp_counter_master SET value = value + %d";
        $values = array($step);

        // Execute the SQL query and return response
        $result = $wpdb->query($wpdb->prepare($sql, $values));
        if ($result === false) {
            return new WP_Error('database_error', 'Database error occurred.', array('status' => 500));
        }

        // Return updated counter value
        return new WP_REST_Response(array('value' => get_counter_value()));
    }

    /**
     * Decrement the counter.
     *
     * @param \WP_REST_Request $request The request object.
     * @return mixed
     */
    public function decrement_counter($request) {
        global $wpdb;

        // Validate and sanitize input parameters
        $step = (int)$request->get_param('step', 1);
        if ($step < 0) {
            return new WP_Error('invalid_step', 'Step size must be a non-negative integer.', array('status' => 400));
        }

        // Prepare the SQL query to update the counter
        $sql = "UPDATE wp_counter_master SET value = value - %d";
        $values = array($step);

        // Execute the SQL query and return response
        $result = $wpdb->query($wpdb->prepare($sql, $values));
        if ($result === false) {
            return new WP_Error('database_error', 'Database error occurred.', array('status' => 500));
        }

        // Return updated counter value
        return new WP_REST_Response(array('value' => get_counter_value()));
    }

    /**
     * Reset the counter.
     *
     * @param \WP_REST_Request $request The request object.
     * @return mixed
     */
    public function reset_counter($request) {
        global $wpdb;

        // Prepare the SQL query to reset the counter
        $sql = "UPDATE wp_counter_master SET value = 0";
        $values = array();

        // Execute the SQL query and return response
        $result = $wpdb->query($wpdb->prepare($sql, $values));
        if ($result === false) {
            return new WP_Error('database_error', 'Database error occurred.', array('status' => 500));
        }

        // Return updated counter value
        return new WP_REST_Response(array('value' => get_counter_value()));
    }

    /**
     * Set the step size for increment/decrement operations.
     *
     * @param \WP_REST_Request $request The request object.
     * @return mixed
     */
    public function set_step($request) {
        global $wpdb;

        // Validate and sanitize input parameters
        $step = (int)$request->get_param('step', 1);
        if ($step < 0) {
            return new WP_Error('invalid_step', 'Step size must be a non-negative integer.', array('status' => 400));
        }

        // Prepare the SQL query to update the step size
        $sql = "UPDATE wp_counter_master SET step = %d";
        $values = array($step);

        // Execute the SQL query and return response
        $result = $wpdb->query($wpdb->prepare($sql, $values));
        if ($result === false) {
            return new WP_Error('database_error', 'Database error occurred.', array('status' => 500));
        }

        // Return updated step size
        return new WP_REST_Response(array('step' => get_step_value()));
    }
}

// Helper function to get the current counter value from the database
