<?php
namespace ECommerce\ShoppingCart;

use WP_REST_Server;
use WP_REST_Request;
use WP_REST_Response;
use InvalidArgumentException;

class RESTAPIEndpoints {
    protected $db;

    public function __construct($db) {
        $this->db = $db;
    }

    // Register the API routes
    public function register_routes() {
        register_rest_route('ecomm/v1', '/cart/items', [
            'methods' => WP_REST_Server::READABLE | WP_REST_Server::CREATABLE,
            'callback' => [$this, 'get_cart_items'],
            'permission_callback' => '__return_true'
        ]);

        register_rest_route('ecomm/v1', '/cart/add-item', [
            'methods' => WP_REST_Server::CREATABLE,
            'callback' => [$this, 'add_item_to_cart'],
            'permission_callback' => '__return_true'
        ]);

        register_rest_route('ecomm/v1', '/cart/remove-item', [
            'methods' => WP_REST_Server::DELETABLE,
            'callback' => [$this, 'remove_item_from_cart'],
            'permission_callback' => '__return_true'
        ]);
    }

    // Get cart items
    public function get_cart_items(WP_REST_Request $request) {
        global $wpdb;
        $results = $wpdb->get_results(
            "SELECT product_id, quantity FROM `ecomm_cart`"
        );
        return new WP_REST_Response($results);
    }

    // Add item to cart
    public function add_item_to_cart(WP_REST_Request $request) {
        $product_id = sanitize_text_field($request->get_param('product_id'));
        $quantity = (int)$request->get_param('quantity');

        if ($quantity <= 0) {
            throw new InvalidArgumentException("Quantity must be greater than zero.");
        }

        // Prepare and execute the query
        global $wpdb;
        $result = $wpdb->insert(
            'ecomm_cart',
            [
                'product_id' => $product_id,
                'quantity' => $quantity
            ],
            ['%d', '%d']
        );

        if ($result === false) {
            throw new InvalidArgumentException("Error adding item to cart.");
        }

        return new WP_REST_Response(['message' => 'Item added successfully']);
    }

    // Remove item from cart
    public function remove_item_from_cart(WP_REST_Request $request) {
        $product_id = sanitize_text_field($request->get_param('product_id'));

        // Prepare and execute the query
        global $wpdb;
        $result = $wpdb->delete(
            'ecomm_cart',
            [
                'product_id' => $product_id
            ],
            ['%d']
        );

        if ($result === false) {
            throw new InvalidArgumentException("Error removing item from cart.");
        }

        return new WP_REST_Response(['message' => 'Item removed successfully']);
    }
}

// Usage: Instantiate the class and register routes in WordPress
