import React, { useState, useEffect, useContext } from 'react';
import { CartContext } from './CartContext';

const FormPage = () => {
  // State to hold form data and validation errors
  const [formData, setFormData] = useState({
    name: '',
    price: '',
    quantity: ''
  });
  const [errors, setErrors] = useState({});

  // Context for accessing cart state and functions
  const { addItemToCart } = useContext(CartContext);

  // Function to handle form submission
  const handleSubmit = (e) => {
    e.preventDefault();
    if (!validateForm()) return;

    // Add item to the cart with validation passed data
    addItemToCart(formData);
    setFormData({ name: '', price: '', quantity: '' });
    alert('Item added successfully!');
  };

  // Function to validate form fields
  const validateForm = () => {
    let isValid = true;
    const newErrors = {};

    if (!formData.name) {
      newErrors.name = 'Name is required';
      isValid = false;
    }
    if (isNaN(formData.price) || formData.price <= 0) {
      newErrors.price = 'Price must be a positive number';
      isValid = false;
    }
    if (isNaN(formData.quantity) || formData.quantity <= 0) {
      newErrors.quantity = 'Quantity must be a positive number';
      isValid = false;
    }

    setErrors(newErrors);
    return isValid;
  };

  // Function to handle input changes
  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  return (
    <div className="FormPage">
      <h2>{formData.id ? 'Edit Item' : 'Create Item'}</h2>
      <form onSubmit={handleSubmit}>
        <div>
          <label>Name:</label>
          <input
            type="text"
            name="name"
            value={formData.name}
            onChange={handleChange}
            className={errors.name ? 'error-input' : ''}
          />
          {errors.name && <span className="error">{errors.name}</span>}
        </div>
        <div>
          <label>Price:</label>
          <input
            type="number"
            name="price"
            value={formData.price}
            onChange={handleChange}
            className={errors.price ? 'error-input' : ''}
          />
          {errors.price && <span className="error">{errors.price}</span>}
        </div>
        <div>
          <label>Quantity:</label>
          <input
            type="number"
            name="quantity"
            value={formData.quantity}
            onChange={handleChange}
            className={errors.quantity ? 'error-input' : ''}
          />
          {errors.quantity && <span className="error">{errors.quantity}</span>}
        </div>
        <button type="submit">{formData.id ? 'Update Item' : 'Add Item'}</button>
      </form>
    </div>
  );
};

