import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Route, Switch, Redirect } from 'react-router-dom';
import CartProvider, { useCartContext } from './CartProvider';
import Home from './Home';
import ProductDetails from './ProductDetails';
import Checkout from './Checkout';

const App = () => {
  // State to track the cart items
  const [cartItems, setCartItems] = useState([]);

  useEffect(() => {
    // Simulate fetching data from an API or local storage
    const savedCartItems = JSON.parse(localStorage.getItem('cart')) || [];
    setCartItems(savedCartItems);
  }, []);

  useEffect(() => {
    // Save cart items to local storage when they change
    localStorage.setItem('cart', JSON.stringify(cartItems));
  }, [cartItems]);

  return (
    <Router>
      <Switch>
        <Route path="/">
          <Home onAddToCart={addItemToCart} />
        </Route>
        <Route path="/product/:id">
          <ProductDetails onAddToCart={addItemToCart} />
        </Route>
        <Route path="/checkout" component={Checkout} />
        {/* Add other routes as needed */}
        <Redirect to="/" />
      </Switch>
    </Router>
  );
};

// Custom hook for adding items to the cart
const addItemToCart = (productId) => {
  const newCartItem = { productId, quantity: 1 };
  setCartItems((prevItems) =>
    prevItems.some(item => item.productId === productId)
      ? prevItems.map(item =>
          item.productId === productId ? { ...item, quantity: item.quantity + 1 } : item
        )
      : [...prevItems, newCartItem]
  );
};

// Wrapper component to provide cart context for other components
const AppWithContext = () => (
  <CartProvider>
    <App />
  </CartProvider>
);

export default AppWithContext;
