        );

        foreach ( $routes as $endpoint => $args ) {
            register_rest_route( 'custom/v1', $endpoint, $args );
        }
    }

    public function get_products() {
        global $wpdb;
        $products = $wpdb->get_results("SELECT * FROM products");
        return rest_ensure_response($products);
    }

    public function manage_cart($request) {
        $action = sanitize_text_field($request['action']);
        $product_id = intval($request['product_id']);
        $quantity = intval($request['quantity']);

        switch ($action) {
            case 'add':
                return $this->add_to_cart($product_id, $quantity);
            case 'update':
                return $this->update_cart($product_id, $quantity);
            case 'remove':
                return $this->remove_from_cart($product_id);
            default:
                return new WP_Error('invalid_action', __('Invalid action'), array('status' => 400));
        }
    }

    private function add_to_cart($product_id, $quantity) {
        global $wpdb;
        $user = wp_get_current_user();
        if (!$user->ID) {
            return new WP_Error('unauthenticated', __('Unauthorized access'), array('status' => 401));
        }

        // Check if product exists
        $product = $wpdb->get_row("SELECT * FROM products WHERE id = $product_id");
        if (!$product) {
            return new WP_Error('product_not_found', __('Product not found'), array('status' => 404));
        }

        // Add to cart logic
        $cart_data = json_decode(get_user_meta($user->ID, 'cart_data', true), true);
        if (!isset($cart_data[$product_id])) {
            $cart_data[$product_id] = array(
                'id' => $product_id,
                'name' => $product->name,
                'price' => $product->price,
                'quantity' => 0
            );
        }
        $cart_data[$product_id]['quantity'] += $quantity;
        update_user_meta($user->ID, 'cart_data', json_encode($cart_data));

        return rest_ensure_response(array('message' => __('Product added to cart')));
    }

    private function update_cart($product_id, $quantity) {
        global $wpdb;
        $user = wp_get_current_user();
        if (!$user->ID) {
            return new WP_Error('unauthenticated', __('Unauthorized access'), array('status' => 401));
        }

        // Check if product exists
        $product = $wpdb->get_row("SELECT * FROM products WHERE id = $product_id");
        if (!$product) {
            return new WP_Error('product_not_found', __('Product not found'), array('status' => 404));
        }

        // Update cart logic
        $cart_data = json_decode(get_user_meta($user->ID, 'cart_data', true), true);
        if (!isset($cart_data[$product_id])) {
            return new WP_Error('product_not_in_cart', __('Product not in cart'), array('status' => 403));
        }
        $cart_data[$product_id]['quantity'] = $quantity;
        update_user_meta($user->ID, 'cart_data', json_encode($cart_data));

        return rest_ensure_response(array('message' => __('Cart updated')));
    }

    private function remove_from_cart($product_id) {
        global $wpdb;
        $user = wp_get_current_user();
        if (!$user->ID) {
            return new WP_Error('unauthenticated', __('Unauthorized access'), array('status' => 401));
        }

        // Remove from cart logic
        $cart_data = json_decode(get_user_meta($user->ID, 'cart_data', true), true);
        unset($cart_data[$product_id]);
        update_user_meta($user->ID, 'cart_data', json_encode($cart_data));

        return rest_ensure_response(array('message' => __('Product removed from cart')));
    }
}

