import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Route, Switch, Redirect } from 'react-router-dom';
import ProfilePage from './ProfilePage'; // Assuming ProfilePage is a component for profile view
import LoginPage from './LoginPage'; // Assuming LoginPage is a component for login page
import Navbar from './Navbar'; // Assuming Navbar is a component for navigation bar

// Context to manage authentication status and token
const AuthContext = React.createContext();

function App() {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [userToken, setUserToken] = useState(null);

  useEffect(() => {
    // Simulated API call to check authentication on page load
    fetch('/api/auth/status')
      .then(response => response.json())
      .then(data => {
        if (data.isLoggedIn) {
          setIsLoggedIn(true);
          setUserToken(data.token);
        }
      })
      .catch(error => {
        console.error('Error checking auth status:', error);
      });
  }, []);

  const handleLogin = (token) => {
    setIsLoggedIn(true);
    setUserToken(token);
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUserToken(null);
  };

  return (
    <Router>
      <AuthContext.Provider value={{ isLoggedIn, userToken, handleLogin, handleLogout }}>
        <Navbar />
        <Switch>
          <Route path="/" exact component={LoginPage} />
          <ProtectedRoute path="/profile" component={ProfilePage} />
          <Redirect from="*" to="/" />
        </Switch>
      </AuthContext.Provider>
    </Router>
  );
}

// Protected route component that checks if user is authenticated
const ProtectedRoute = ({ component: Component, ...props }) => {
  const { isLoggedIn } = React.useContext(AuthContext);

  return isLoggedIn ? (
    <Component {...props} />
  ) : (
    <Redirect to="/login" />
  );
};

export default App;
