<?php

// Define the WordPress REST API namespace and version
namespace WP_API;

use WP_REST_Server;
use WP_REST_Request;
use WP_REST_Response;
usewpdb;

class UserProfileHub extends \WP_REST_Controller {
    public function __construct() {
        $this->namespace = 'userprofilehub/v1';
        $this->rest_base = 'profiles';
        parent::__construct();
    }

    // Register the API routes
    public function register_routes() {
        register_rest_route(
            $this->namespace,
            '/' . $this->rest_base,
            array(
                'methods'  => WP_REST_Server::READABLE,
                'callback' => array( $this, 'get_profiles' ),
                'permission_callback' => '__return_true',
            )
        );

        register_rest_route(
            $this->namespace,
            '/' . $this->rest_base . '/(?P<id>[\d]+)',
            array(
                'methods'  => WP_REST_Server::READABLE,
                'callback' => array( $this, 'get_profile_by_id' ),
                'permission_callback' => '__return_true',
            )
        );

        register_rest_route(
            $this->namespace,
            '/' . $this->rest_base,
            array(
                'methods'  => WP_REST_Server::CREATABLE,
                'callback' => array( $this, 'create_profile' ),
                'permission_callback' => '__return_true',
            )
        );
    }

    // Retrieve all user profiles
    public function get_profiles(WP_REST_Request $request) {
        global $wpdb;
        $profiles = $wpdb->get_results("SELECT * FROM wp_usermeta WHERE meta_key LIKE '%user_profile%'");

        return rest_ensure_response($profiles);
    }

    // Retrieve a specific user profile by ID
    public function get_profile_by_id(WP_REST_Request $request) {
        global $wpdb;
        $id = $request->get_param('id');
        $profile = $wpdb->get_row("SELECT * FROM wp_usermeta WHERE meta_key LIKE '%user_profile%' AND user_id=$id");

        return rest_ensure_response($profile);
    }

    // Create a new user profile
    public function create_profile(WP_REST_Request $request) {
        global $wpdb;

        // Sanitize and validate inputs
        $name = sanitize_text_field( $request['name'] );
        $email = sanitize_email( $request['email'] );

        if ( empty($name) || empty($email) ) {
            return new WP_REST_Response(array('error' => 'Name and email are required'), 400);
        }

        // Prepare the data for insertion
        $data = array(
            'meta_key' => 'user_profile',
            'meta_value' => json_encode(array('name' => $name, 'email' => $email)),
