const express = require('express');
const bodyParser = require('body-parser');
const mongoose = require('mongoose');
const path = require('path');

// Initialize the Express application
const app = express();

// Connect to MongoDB using Mongoose
mongoose.connect('mongodb://localhost:27017/recipeFinder', {
  useNewUrlParser: true,
  useUnifiedTopology: true,
});

// Middleware setup
app.use(bodyParser.json());
app.use(express.static(path.join(__dirname, 'public')));

// Models
const Recipe = mongoose.model('Recipe', new mongoose.Schema({
  title: { type: String, required: true },
  description: String,
  ingredients: [String],
  instructions: [String],
}));

// Error handling middleware
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).send('Something broke!');
});

// Routes

// GET all recipes
app.get('/recipes', async (req, res) => {
  try {
    const { page = 1, limit = 10 } = req.query;
    const skip = (page - 1) * limit;
    const recipes = await Recipe.find().skip(skip).limit(limit);
    res.json(recipes);
  } catch (err) {
    next(err);
  }
});

// GET a single recipe by ID
app.get('/recipes/:id', async (req, res, next) => {
  try {
    const recipe = await Recipe.findById(req.params.id);
    if (!recipe) return res.status(404).send('Recipe not found');
    res.json(recipe);
  } catch (err) {
    next(err);
  }
});

// POST a new recipe
app.post('/recipes', async (req, res, next) => {
  try {
    const newRecipe = new Recipe(req.body);
    await newRecipe.save();
    res.status(201).json(newRecipe);
  } catch (err) {
    next(err);
  }
});

// PUT update a recipe by ID
app.put('/recipes/:id', async (req, res, next) => {
  try {
    const updatedRecipe = await Recipe.findByIdAndUpdate(req.params.id, req.body, { new: true });
    if (!updatedRecipe) return res.status(404).send('Recipe not found');
    res.json(updatedRecipe);
  } catch (err) {
    next(err);
  }
});

// DELETE a recipe by ID
app.delete('/recipes/:id', async (req, res, next) => {
  try {
    const deletedRecipe = await Recipe.findByIdAndDelete(req.params.id);
    if (!deletedRecipe) return res.status(404).send('Recipe not found');
    res.json(deletedRecipe);
  } catch (err) {
    next(err);
  }
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
