<?php

// WordPress API Endpoint: Recipe Finder Advanced Filtering, Searching, and Pagination

use WP_REST_Server;
use WP_Error;

class Recipe_API_Endpoint {
    private $wpdb; // Database connection

    public function __construct() {
        global $wpdb;
        $this->wpdb = $wpdb;
        add_action('rest_api_init', array($this, 'register_routes'));
    }

    public function register_routes() {
        register_rest_route('recipes/v1', '/search', array(
            'methods' => WP_REST_Server::READABLE,
            'callback' => array($this, 'get_recipes'),
            'args' => array(
                'term' => array(
                    'required' => true,
                    'type' => 'string',
                    'sanitize_callback' => 'sanitize_text_field'
                ),
                'category' => array(
                    'required' => false,
                    'type' => 'integer',
                    'sanitize_callback' => 'absint'
                )
            )
        ));
    }

    public function get_recipes(WP_REST_Request $request) {
        global $wpdb;

        $term = sanitize_text_field($request->get_param('term'));
        $category_id = (int)$request->get_param('category');

        // Prepare the query
        $args = array(
            'post_type' => 'recipe',
            'posts_per_page' => -1,
            'tax_query' => array(
                array(
                    'taxonomy' => 'recipe_category',
                    'field' => 'term_id',
                    'terms' => $category_id > 0 ? array($category_id) : array()
                )
            ),
            's' => $term
        );

        // Execute the query
        $query = new WP_Query($args);

        // Prepare the response
        $response_data = array();
        if ($query->have_posts()) {
            while ($query->have_posts()) {
                $query->the_post();
                $recipe_id = get_the_ID();
                $recipe_title = get_the_title();

                $response_data[] = array(
                    'id' => $recipe_id,
                    'title' => $recipe_title
                );
            }
        } else {
            return new WP_Error('no_recipes_found', 'No recipes found with that term or category.');
        }

        wp_reset_postdata();
        return rest_ensure_response($response_data);
    }
}

// Initialize the endpoint class
$recipe_api_endpoint = new Recipe_API_Endpoint();

?>
