const ListPage = () => {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchItems = async () => {
      try {
        const storedData = await getItem('movieWatchlist');
        if (storedData) {
          setItems(JSON.parse(storedData));
        }
      } catch (err) {
        setError(err);
      } finally {
        setLoading(false);
      }
    };

    fetchItems();
  }, []);

  const addItem = async (item) => {
    try {
      await saveItem('movieWatchlist', JSON.stringify([...items, item]));
      setItems([...items, item]);
    } catch (err) {
      setError(err);
    }
  };

  const removeItem = async (id) => {
    try {
      const updatedItems = items.filter(item => item.id !== id);
      await saveItem('movieWatchlist', JSON.stringify(updatedItems));
      setItems(updatedItems);
    } catch (err) {
      setError(err);
    }
