import React, { useState, useEffect, useContext } from 'react';
import { useLocalStorageState } from '../hooks/useLocalStorage'; // Custom hook for local storage

// Context to manage movie data globally
const MovieContext = React.createContext();

function DetailPage() {
  const [movieId, setMovieId] = useState(null);
  const [movieData, setMovieData] = useLocalStorageState(movieId, null);

  useEffect(() => {
    // Fetch movie details from API based on movieId and update local storage
    if (movieId) {
      fetch(`/api/movies/${movieId}`)
        .then(response => response.json())
        .then(data => {
          setMovieData(data);
        })
        .catch(error => console.error('Error fetching movie:', error));
    }
  }, [movieId]);

  const handleRateChange = (rating) => {
    // Update movie data in local storage with new rating
    if (movieId && movieData) {
      setMovieData(prevState => ({ ...prevState, rating }));
    }
  };

  return (
    <div>
      {movieData ? (
        <>
          <h1>{movieData.title}</h1>
          <p>Rating: {movieData.rating} out of 5</p>
          {/* Add more movie details as needed */}
          <button onClick={() => handleRateChange(movieData.rating + 1)}>
            Rate up
          </button>
          <button onClick={() => handleRateChange(movieData.rating - 1)}>
            Rate down
          </button>
        </>
      ) : (
        <p>Loading...</p>
      )}
    </div>
  );
}

export default DetailPage;

// Custom hook to manage local storage
function useLocalStorageState(key, defaultValue) {
  const [value, setValue] = useState(() => {
    try {
      return JSON.parse(window.localStorage.getItem(key)) || defaultValue;
    } catch (error) {
      console.error('Error parsing local storage:', error);
      return defaultValue;
    }
  });

  useEffect(() => {
    window.localStorage.setItem(key, JSON.stringify(value));
  }, [key, value]);

  return [value, setValue];
}
