      await editMovie(newMovie);
      history.push('/');
    } catch (err) {
      setError(`Failed to ${movieId ? 'edit' : 'create'} movie`);
    }
  };

  // Handle cancel button click
  const handleCancel = () => {
    history.goBack();
  };

