import React, { useState, useEffect, useContext } from 'react';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
import './App.css'; // Importing CSS for styling

// Context to manage movie data and ratings
const MovieContext = React.createContext();

function App() {
  const [movies, setMovies] = useState([]);

  useEffect(() => {
    // Load movies from local storage on component mount
    const storedMovies = localStorage.getItem('movies');
    if (storedMovies) {
      setMovies(JSON.parse(storedMovies));
    }
  }, []);

  useEffect(() => {
    // Save movies to local storage when they change
    localStorage.setItem('movies', JSON.stringify(movies));
  }, [movies]);

  function addMovie(movieTitle, rating) {
    const newMovie = { title: movieTitle, rating };
    setMovies([...movies, newMovie]);
  }

  function deleteMovie(index) {
    movies.splice(index, 1);
    setMovies([...movies]);
  }

  return (
    <div className="App">
      <header>
        <h1>Movie Watchlist</h1>
      </header>
      <main>
        <MovieContext.Provider value={{ movies, addMovie }}>
          <Switch>
            <Route path="/" exact component={Home} />
            <Route path="/add" component={AddMovie} />
          </Switch>
        </MovieContext.Provider>
      </main>
    </div>
  );
}

function Home() {
  const { movies } = useContext(MovieContext);
  return (
    <div>
      <h2>My Watchlist</h2>
      <ul>
        {movies.map((movie, index) => (
          <li key={index}>
            {movie.title} - Rating: {movie.rating}
            <button onClick={() => deleteMovie(index)}>Delete</button>
          </li>
        ))}
      </ul>
    </div>
  );
}

function AddMovie() {
  const [title, setTitle] = useState('');
  const [rating, setRating] = useState('');

  function handleSubmit(event) {
    event.preventDefault();
    if (title.trim() === '' || rating.trim() === '') {
      alert('Title and Rating are required');
      return;
    }
    addMovie(title, rating);
    setTitle('');
    setRating('');
  }

  return (
    <div>
      <h2>Add Movie</h2>
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          placeholder="Movie Title"
        />
        <input
          type="number"
          min="0"
          max="10"
          value={rating}
          onChange={(e) => setRating(e.target.value)}
          placeholder="Rating (0-10)"
        />
        <button type="submit">Add</button>
      </form>
    </div>
  );
}

export default App;
