  const calculateTrend = () => {
    if (!cryptoData || !cryptoData.market_data.current_price.usd) return null;
    const currentPrice = cryptoData.market_data.current_price.usd;
    const previousDayPrice = cryptoData.market_data.previous_day_usd;
    return currentPrice > previousDayPrice ? 'Up' : 'Down';
  };

  if (loading) return <div>Loading...</div>;
  if (error) return <div>Error: {error}</div>;

  const trend = calculateTrend();
  const symbol = cryptoData.symbol.toUpperCase();

  return (
    <CryptoContext.Provider value={cryptoData}>
      <div className="detail-page">
        <h1>{cryptoData.name} ({symbol})</h1>
        <p>Current Price: ${cryptoData.market_data.current_price.usd.toLocaleString()}</p>
        <p>Trend: {trend}</p>
        {/* Add more detailed information as needed */}
      </div>
    </CryptoContext.Provider>
  );
}

export default DetailPage;
