const express = require('express');
const bodyParser = require('body-parser');
const cors = require('cors');
const logger = require('morgan');
const axios = require('axios');
require('dotenv').config();

// Initialize Express app
const app = express();
const PORT = process.env.PORT || 3000;

// Middleware setup
app.use(cors());
app.use(logger('dev'));
app.use(bodyParser.json());

// Database operations (example using async/await)
async function fetchCryptoPrices(tickers) {
    const promises = tickers.map(async ticker => {
        try {
            const response = await axios.get(`https://api.coingecko.com/api/v3/simple/price?ids=${ticker}&vs_currencies=usd`);
            return { symbol: ticker, price: response.data[ticker].usd };
        } catch (error) {
            console.error(`Error fetching price for ${ticker}:`, error);
            return null;
        }
    });
    return Promise.all(promises);
}

// Route to get crypto prices
app.get('/prices', async (req, res) => {
    const tickers = req.query.tickers || ['bitcoin', 'ethereum'];
    try {
        const prices = await fetchCryptoPrices(tickers);
        if (prices.some(price => price === null)) {
            return res.status(500).json({ error: 'Failed to fetch some prices' });
        }
        const sortedPrices = prices.sort((a, b) => a.price - b.price);
        res.json(sortedPrices);
