    private $dbHost = 'localhost';
    private $dbName = 'crypto_tracker';
    private $dbUser = 'root';
    private $dbPass = '';
    private $pdo;

    public function __construct() {
        try {
            $this->pdo = new PDO("mysql:host=$this->dbHost;dbname=$this->dbName", $this->dbUser, $this->dbPass);
            $this->pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
        } catch (PDOException $e) {
            error_log('Database connection failed: ' . $e->getMessage());
            exit;
        }
    }

    public function getPrices($symbol) {
        $stmt = $this->pdo->prepare("SELECT * FROM prices WHERE symbol = :symbol ORDER BY timestamp DESC LIMIT 1");
        $stmt->bindParam(':symbol', $symbol, PDO::PARAM_STR);
        $stmt->execute();
        return $stmt->fetch(PDO::FETCH_ASSOC);
    }

    public function trackPrice($data) {
        if (!$this->isDataValid($data)) {
            error_log('Invalid data received');
            return false;
        }

        try {
            $stmt = $this->pdo->prepare("INSERT INTO prices (symbol, price, timestamp) VALUES (:symbol, :price, NOW())");
            $stmt->bindParam(':symbol', $data['symbol'], PDO::PARAM_STR);
            $stmt->bindParam(':price', $data['price'], PDO::PARAM_FLOAT);
            $stmt->execute();
            return true;
        } catch (PDOException $e) {
            error_log('Error inserting price data: ' . $e->getMessage());
            return false;
        }
    }

    private function isDataValid($data) {
        if (!isset($data['symbol']) || !isset($data['price'])) {
            return false;
        }

        if (empty(trim($data['symbol'])) || !is_float($data['price'])) {
            return false;
        }

        return true;
    }
}

