<?php

// Define the plugin directory path
define('PLUGIN_DIR', __DIR__);

// Load necessary WordPress core files
require_once ABSPATH . 'wp-load.php';

// Check if the REST API is enabled and we are in a request to fetch data
if (defined('REST_REQUEST') && REST_REQUEST) {
    add_action('rest_api_init', function() {
        register_rest_route('crypto/v1', '/price', array(
            'methods' => 'GET',
            'callback' => 'fetch_crypto_price',
            'permission_callback' => '__return_true'
        ));
    });

    /**
     * Function to fetch and process crypto price data
     *
     * @param WP_REST_Request $request The incoming request object
     * @return WP_REST_Response|WP_Error
     */
    function fetch_crypto_price($request) {
        // Validate the input parameters (e.g., cryptocurrency symbol)
        if (!isset($request['symbol'])) {
            return new WP_Error('invalid_parameter', 'Missing cryptocurrency symbol');
        }

        // Sanitize and validate the input data
        $symbol = sanitize_text_field($request['symbol']);

        try {
            // Prepare a database query to fetch the latest price for the specified crypto
            global $wpdb;
            $table_name = $wpdb->prefix . 'crypto_prices';
            $query = "SELECT price, timestamp FROM $table_name WHERE symbol = '%s' ORDER BY timestamp DESC LIMIT 1";
            $result = $wpdb->get_row($wpdb->prepare($query, $symbol), ARRAY_A);

            if (!$result) {
                return new WP_Error('price_not_found', 'Crypto price not found');
            }

            // Prepare the response
            $response_data = array(
                'symbol' => $result['symbol'],
                'price' => floatval($result['price']),
                'timestamp' => strtotime($result['timestamp'])
            );

            return new WP_REST_Response($response_data, 200);
        } catch (Exception $e) {
            // Log the error and return an internal server error response
            error_log('Error fetching crypto price: ' . $e->getMessage());
            return new WP_Error('internal_server_error', 'Failed to fetch crypto price');
        }
    }
}
