import { BrowserRouter as Router, Switch, Route } from 'react-router-dom';
import Home from './Home'; // Assuming Home component exists for the homepage
import CardCarousel from './CardCarousel'; // Assuming CardCarousel component exists for the carousel

const App = () => {
  const [flashcards, setFlashcards] = useState([]);
  const [currentCardIndex, setCurrentCardIndex] = useState(0);
  const [flipped, setFlipped] = useState(false);

  useEffect(() => {
    // Fetch flashcard data from API or JSON file
    fetch('/api/flashcards')
      .then(response => response.json())
      .then(data => setFlashcards(data))
      .catch(error => console.error('Error fetching flashcards:', error));
  }, []);

  const handleFlip = () => {
    if (currentCardIndex < flashcards.length - 1) {
      setCurrentCardIndex(currentCardIndex + 1);
    } else {
      setCurrentCardIndex(0); // Loop to the first card after last
    }
    setFlipped(!flipped);
  };

  return (
    <Router>
      <div className="app-container">
        {/* Navbar or header */}

        <Switch>
          <Route exact path="/">
            <Home />
          </Route>
          <Route path="/flashcards">
            <CardCarousel
              cards={flashcards}
              currentCardIndex={currentCardIndex}
              flipped={flipped}
              handleFlip={handleFlip}
            />
          </Route>
        </Switch>

        {/* Footer or bottom */}
      </div>
    </Router>
  );
};

export default App;
