// Import necessary modules
const express = require('express');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const { UserModel } = require('./models/userModel'); // Assuming you have a User model

const router = express.Router();

// Middleware to hash passwords before saving them in the database
router.use(async (req, res, next) => {
  if (!req.body.password) return res.status(400).send({ message: 'Password is required' });

  const hashedPassword = await bcrypt.hash(req.body.password, 10);
  req.body.password = hashedPassword;

  next();
});

// Authentication middleware
router.use(async (req, res, next) => {
  try {
    const token = req.headers['authorization'];

    if (!token) return res.status(401).send({ message: 'Access denied. No token provided' });

    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;

    next();
  } catch (err) {
    console.error(err);
    res.status(403).send({ message: 'Failed to authenticate token' });
  }
});

// Middleware to check if user has the required role
router.use(async (req, res, next) => {
  const roles = req.query.roles || [];

  for (const role of roles) {
    if (!req.user.roles.includes(role)) {
      return res.status(403).send({ message: 'Access denied. Insufficient permissions' });
    }
  }

  next();
});

// Middleware to log user activity
router.use((req, res, next) => {
  console.log(`Logged in as ${req.user.username}`);
  next();
});

module.exports = router;
