    const hasCategoriesFilter = categoriesFilter.length > 0;

    const doesItemMatchTags = item.tags.some(tag =>
      tagsFilter.includes(tag)
    );
    const doesItemMatchCategories = categoriesFilter.every(category =>
      item.categories.includes(category)
    );

    return !(hasTagsFilter && !doesItemMatchTags) && !(hasCategoriesFilter && !doesItemMatchCategories);
  };

  if (!isFilteredOut()) {
    return <div>Item is not in the filtered list.</div>;
  }

  return (
    <div>
      <h1>{item.title}</h1>
      <p>{item.description}</p>
      <p>Category: {item.category}</p>
      <p>Tags: {item.tags.join(', ')}</p>
    </div>
  );
};

export default DetailPage;
