import React, { useState, useEffect } from 'react';
import ReactDOM from 'react-dom/client';
import axios from 'axios';

// Create context for sorting and filtering states
const FiltersContext = React.createContext();

function App() {
  const [jobs, setJobs] = useState([]);
  const [filters, setFilters] = useState({});

  // Fetch job data when the component mounts
  useEffect(() => {
    async function fetchJobs() {
      try {
        const response = await axios.get('https://api.example.com/jobs');
        setJobs(response.data);
      } catch (error) {
        console.error('Error fetching jobs:', error);
      }
    }
    fetchJobs();
  }, []);

  // Handle sorting and filtering based on user input
  function handleFilterChange(key, value) {
    const newFilters = { ...filters };
    if (value === '') delete newFilters[key];
    else newFilters[key] = value;
    setFilters(newFilters);
  }

  // Apply filters to jobs
  const filteredJobs = jobs.filter(job => {
    for (const [key, value] of Object.entries(filters)) {
      if (typeof job[key] !== 'string') continue; // Skip non-string fields
      if (!job[key].includes(value.toLowerCase())) return false;
    }
    return true;
  });

  return (
    <FiltersContext.Provider value={{ filters, handleFilterChange }}>
      <div>
        <h1>Job Board</h1>
        {/* Filter input components */}
        <input
          type="text"
          placeholder="Location"
          onChange={(e) => handleFilterChange('location', e.target.value)}
        />
        <input
          type="text"
          placeholder="Keywords"
          onChange={(e) => handleFilterChange('keywords', e.target.value)}
        />
        {/* Job listing */}
        {filteredJobs.length === 0 ? (
          <p>No jobs found matching the filters.</p>
        ) : (
          filteredJobs.map((job, index) => (
            <div key={index}>
              <h2>{job.title}</h2>
              <p>Location: {job.location}</p>
              {/* Add more job details */}
            </div>
          ))
        )}
      </div>
    </FiltersContext.Provider>
  );
}

const root = ReactDOM.createRoot(document.getElementById('root'));
root.render(<App />);
