  const client = new MongoClient(uri);

  try {
    await client.connect();
    console.log('Connected to MongoDB');
    return client;
  } catch (error) {
    console.error(error);
    throw error; // Re-throw the error so it can be handled by other middleware or caught at a higher level
  }
}

