    try {
      const query = {};

      // Handle sorting based on tags and conditional filter states
      if (req.query.tags && req.query.filterState) {
        query.$and = [
          { tags: { $in: JSON.parse(req.query.tags) } },
          { state: req.query.filterState }
        ];
      } else if (req.query.tags) {
        query.tags = { $in: JSON.parse(req.query.tags) };
      } else if (req.query.filterState) {
        query.state = req.query.filterState;
      }

      const cursor = db.collection('jobs').find(query);
      const jobs = await cursor.toArray();
      res.json(jobs);
    } catch (error) {
      next(error); // Pass error to the global error handler
    }
  });

