  const [filters, setFilters] = useState({ tags: [] });
  const location = useLocation();
  const history = useHistory();
  const { jobs, setError } = React.useContext(JobBoardContext);

  useEffect(() => {
    if (location.search) {
      const queryParams = new URLSearchParams(location.search);
      const tagFilter = queryParams.get('tag');
      if (tagFilter) {
        setFilters((prevFilters) => ({
          ...prevFilters,
          tags: [tagFilter],
        }));
      }
    }

    // Fetch job data or handle loading state
    fetch('/api/jobs')
      .then(response => response.json())
      .then(data => {
        if (data.success) {
          setJobs(data.jobs);
        } else {
          setError('Failed to load jobs');
        }
      })
      .catch(error => setError(`Error fetching data: ${error.message}`));
  }, [location.search, history]);

  const handleFilterChange = (event) => {
    const { name, value } = event.target;
    if (name === 'tags') {
      setFilters((prevFilters) => ({
        ...prevFilters,
        tags: Array.from(new Set([...prevFilters.tags, value])),
      }));
    }
  };

  const handleResetFilter = () => {
    setFilters({ tags: [] });
