import React, { useState, useEffect } from 'react';
import PropTypes from 'prop-types';

// Context to manage sorting and filtering states
const ListContext = React.createContext();

function ListPage({ items }) {
  // State for sorting order (ascending or descending)
  const [sortOrder, setSortOrder] = useState('asc');
  // State for selected tags
  const [tags, setTags] = useState([]);
  // State to store filtered results
  const [filteredItems, setFilteredItems] = useState([]);

  useEffect(() => {
    // Calculate the sorted list based on sortOrder
    let sortedItems = [...items];
    if (sortOrder === 'desc') {
      sortedItems.sort((a, b) => new Date(b.createdAt) - new Date(a.createdAt));
    } else {
      sortedItems.sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));
    }

    // Filter items based on selected tags
    const filtered = sortedItems.filter(item =>
      tags.every(tag => item.tags.includes(tag))
    );
    setFilteredItems(filtered);
  }, [items, sortOrder, tags]);

  // Function to handle tag selection
  const handleTagSelect = (tag) => {
    if (tags.includes(tag)) {
      setTags(tags.filter(t => t !== tag));
    } else {
      setTags([...tags, tag]);
    }
  };

  return (
    <ListContext.Provider value={{ tags, handleTagSelect }}>
      <div className="list-page">
        <h1>Job Board Listings</h1>
        <div className="sort-options">
          <button onClick={() => setSortOrder('asc')}>
            Sort by Newest
          </button>
          <button onClick={() => setSortOrder('desc')}>
            Sort by Oldest
          </button>
        </div>
        <div className="filter-options">
          {items.map(item => (
            item.tags.map(tag => (
              <label key={tag}>
                <input
                  type="checkbox"
                  checked={tags.includes(tag)}
                  onChange={() => handleTagSelect(tag)}
                />
                {tag}
              </label>
            ))
          ))}
        </div>
        <ul className="item-list">
          {filteredItems.map(item => (
            <li key={item.id}>
              <h2>{item.title}</h2>
              <p>{item.description}</p>
              <p>Location: {item.location}</p>
            </li>
          ))}
        </ul>
      </div>
    </ListContext.Provider>
  );
}

ListPage.propTypes = {
  items: PropTypes.arrayOf(PropTypes.shape({
    id: PropTypes.string.isRequired,
    title: PropTypes.string.isRequired,
    description: PropTypes.string.isRequired,
    location: PropTypes.string.isRequired,
    tags: PropTypes.arrayOf(PropTypes.string).isRequired,
    createdAt: PropTypes.string.isRequired,
  })).isRequired,
};

export default ListPage;
