const jobSchema = new mongoose.Schema({
  title: String,
  description: String,
  tags: [String],
  location: String,
  applied: Boolean, // State for conditional filter
});

const JobListing = mongoose.model('JobListing', jobSchema);

// Route to handle GET requests for all job listings
app.get('/jobs', async (req, res) => {
  try {
    const { tags } = req.query;
    let query = {};

    if (tags) {
      query.tags = { $in: tags.split(',') };
    }

    // Example of conditional filter: Apply state
    if (req.query.applied !== undefined) {
      query.applied = JSON.parse(req.query.applied);
    }

    const jobListings = await JobListing.find(query).sort('title');
    res.json(jobListings);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Server error' });
  }
});

// Route to handle POST requests for new job listings
app.post('/jobs', async (req, res) => {
  try {
    const { title, description, tags, location } = req.body;
    if (!title || !description || !tags || !location) {
      return res.status(400).json({ message: 'Missing required fields' });
    }

    const jobListing = new JobListing({
      title,
      description,
      tags,
      location,
      applied: false, // Default state
    });

    await jobListing.save();
    res.json(jobListing);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Server error' });
  }
});

// Route to handle PUT requests for updating a specific job listing by ID
app.put('/jobs/:id', async (req, res) => {
  try {
    const { title, description, tags, location } = req.body;
    if (!title || !description || !tags || !location) {
      return res.status(400).json({ message: 'Missing required fields' });
    }

    const jobListing = await JobListing.findByIdAndUpdate(req.params.id, {
      title,
      description,
      tags,
      location,
    }, { new: true });

    if (!jobListing) {
      return res.status(404).json({ message: 'Job listing not found' });
    }

    res.json(jobListing);
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Server error' });
