const bodyParser = require('body-parser');
const logger = require('morgan');

// Create an Express app
const app = express();

// Use body-parser middleware to parse JSON bodies
app.use(bodyParser.json());

// Use Morgan middleware for request logging
app.use(logger('dev'));

// Connect to MongoDB using Mongoose
mongoose.connect('mongodb://localhost:27017/jobboard', {
  useNewUrlParser: true,
  useUnifiedTopology: true,
});

// Define a Job schema and model
const jobSchema = new mongoose.Schema({
  title: String,
  description: String,
  tags: [String],
  salary: Number,
  location: String,
});

const Job = mongoose.model('Job', jobSchema);

// Middleware to handle errors globally
app.use((err, req, res, next) => {
  logger.error(err.stack);
  res.status(500).send('Something broke!');
});

// Define routes for handling requests

// Route to get all jobs sorted by tags and filter by conditions
app.get('/jobs', async (req, res) => {
  try {
    const { tags, salaryMin, salaryMax } = req.query;
    let query = {};

    // Apply filtering based on query parameters
    if (tags && Array.isArray(tags)) {
      query.tags = { $in: tags };
    }
    if (salaryMin || salaryMax) {
      query.salary = {};
      if (salaryMin) {
        query.salary.$gte = parseInt(salaryMin, 10);
      }
      if (salaryMax) {
        query.salary.$lte = parseInt(salaryMax, 10);
      }
    }

    // Sort jobs by tags
    const sortedJobs = await Job.find(query).sort({ tags: 1 });

    res.json(sortedJobs);
  } catch (err) {
    next(err);
  }
});

// Start the server
app.listen(3000, () => {
  console.log('Server is running on port 3000');
