import React, { useState, useEffect } from 'react';
import axios from 'axios';
import GridItem from './GridItem'; // Assuming a component for each grid item

const HomePage = () => {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    const loadMoreItems = async () => {
      try {
        setLoading(true);
        const response = await axios.get('https://api.example.com/items');
        setItems([...items, ...response.data]);
        // Add logic to handle pagination if needed
      } catch (err) {
        setError(err);
      } finally {
        setLoading(false);
      }
    };

    loadMoreItems();
  }, [items]);

  const observerRef = React.createRef();

  useEffect(() => {
    const intersectionObserver = new IntersectionObserver((entries) => {
      if (entries[0].isIntersecting && !loading && items.length < 100) { // Assuming a limit of 100 items
        loadMoreItems();
      }
    });

    observerRef.current && intersectionObserver.observe(observerRef.current);

    return () => intersectionObserver.unobserve(observerRef.current);
  }, [items, loading]);

  if (error) {
    return <div>Error: {error.message}</div>;
  }

  return (
    <div>
      <h1>Home Page</h1>
      <p>Welcome to the homepage!</p>

      <div style={{ height: '400px', overflowY: 'auto' }}>
        <ul ref={observerRef}>
          {items.map((item, index) => (
            <li key={index} className="grid-item">
              <GridItem item={item} />
            </li>
          ))}
        </ul>
      </div>

      {loading && <p>Loading...</p>}
    </div>
  );
};

export default HomePage;
