import React, { useState, useEffect } from 'react';
import axios from 'axios';

const ListPage = () => {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [hasMore, setHasMore] = useState(true);
  const [lastItemIndex, setLastItemIndex] = useState(0);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting && hasMore) {
          fetchMoreItems();
        }
      },
      { threshold: 1.0 }
    );

    // Fetch initial items
    fetchInitialItems();

    return () => {
      observer.disconnect();
    };
  }, []);

  const fetchInitialItems = async () => {
    try {
      const response = await axios.get('/api/items');
      setItems(response.data);
      setLoading(false);
    } catch (err) {
      setError(err);
      setLoading(false);
    }
  };

  const fetchMoreItems = async () => {
    try {
      const nextResponse = await axios.get('/api/items', {
        params: { startFrom: lastItemIndex },
      });
      setItems((prevItems) => [...prevItems, ...nextResponse.data]);
      setLastItemIndex(nextResponse.data.length + lastItemIndex);
      hasMore = !!nextResponse.data.length;
    } catch (err) {
      setError(err);
      setLoading(false);
    }
  };

  if (loading) return <p>Loading...</p>;
  if (error) return <p>Error: {error.message}</p>;

  return (
    <div>
      <ul>
        {items.map((item, index) => (
          <li key={index}>{item.title}</li>
        ))}
      </ul>
    </div>
  );
};

export default ListPage;
