import React, { useState, useEffect } from 'react';
import axios from 'axios';

// Context to manage gallery items
const GalleryContext = React.createContext();
const GalleryProvider = ({ children }) => {
  const [galleryItems, setGalleryItems] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchMoreItems = async () => {
      try {
        setLoading(true);
        const response = await axios.get('https://api.example.com/galleries');
        if (response.data) {
          setGalleryItems([...galleryItems, ...response.data]);
        }
      } catch (err) {
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    // Simulate intersection observer by adding a div to the page and watching it
    const div = document.createElement('div');
    div.style.position = 'fixed';
    div.style.top = '-100px';
    document.body.appendChild(div);

    const observer = new IntersectionObserver((entries) => {
      if (entries[0].isIntersecting && !loading) {
        fetchMoreItems();
      }
    });

    observer.observe(div);

    return () => {
      // Clean up the observer and remove the div
      observer.unobserve(div);
      document.body.removeChild(div);
    };
  }, [galleryItems]);

  return (
    <GalleryContext.Provider value={{ galleryItems, loading, error }}>
      {children}
    </GalleryContext.Provider>
  );
};

// Component to render gallery items
const GalleryItem = ({ item }) => {
  return (
    <div className="gallery-item">
      <img src={item.image} alt={item.title} />
      <h2>{item.title}</h2>
      <p>{item.description}</p>
    </div>
  );
};

// Main App component
const App = () => {
  const { galleryItems, loading, error } = React.useContext(GalleryContext);

  if (error) {
    return <div>Error: {error}</div>;
  }

  return (
    <div className="app">
      <h1>Infinite Scroll Gallery</h1>
      {loading ? <p>Loading...</p> : null}
      <GalleryProvider>
        <div className="gallery-container">
          {galleryItems.map((item) => (
            <GalleryItem key={item.id} item={item} />
          ))}
        </div>
      </GalleryProvider>
    </div>
  );
};

export default App;
