        const response = await axios.get('https://api.example.com/gallery-items'); // Replace with actual API endpoint
        setGalleryItems(response.data.items);
        setLoading(false);
      } catch (err) {
        setError(err);
        setLoading(false);
      }
    }

    fetchData();
  }, []);

  return (
