}

// Functional component for handling infinite scroll
function InfiniteScrollGallery({ items }) {
  const [scrollPosition, setScrollPosition] = useState(0);
  const [hasMore, setHasMore] = useState(true);

  // Function to handle intersection observer
  const handleIntersection = (entries) => {
    if (entries[0].isIntersecting && hasMore) {
      loadMoreItems();
    }
  };

  // Fetch more items when user scrolls near the end of the gallery
  async function loadMoreItems() {
    try {
      const response = await axios.get('https://api.example.com/gallery-items?page=2'); // Replace with actual API endpoint for paginated data
      setGalleryItems([...galleryItems, ...response.data.items]);
      hasMore = response.data.hasMore; // Update hasMore based on the response
    } catch (err) {
      setError(err);
      hasMore = false;
    }
  }

  return (
    <div className="gallery">
      {items.map((item, index) => (
        <div key={index} className="gallery-item">
          {/* Display item content */}
          <img src={item.imageUrl} alt={item.title} />
        </div>
      ))}
      <div ref={(el) => el && IntersectionObserver([handleIntersection], { threshold: 0.5 }).observe(el)}></div> {/* Infinite scroll trigger */}
    </div>
  );
}

