import React, { useState, useEffect } from 'react';
import axios from 'axios';

// Context to share loading state between components
const GalleryContext = React.createContext();

function App() {
  const [images, setImages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [hasMore, setHasMore] = useState(true);

  useEffect(() => {
    // Fetch initial images
    fetchInitialImages();
  }, []);

  useEffect(() => {
    if (loading && hasMore) {
      fetchNextImages();
    }
  }, [loading, hasMore]);

  const fetchInitialImages = async () => {
    try {
      setLoading(true);
      const response = await axios.get('/api/images');
      setImages(response.data.images);
      setHasMore(response.data.hasMore);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching initial images:', error);
      setLoading(false);
    }
  };

  const fetchNextImages = async () => {
    try {
      const response = await axios.get('/api/images', { params: { offset: images.length } });
      setImages(prevImages => [...prevImages, ...response.data.images]);
      setHasMore(response.data.hasMore);
    } catch (error) {
      console.error('Error fetching next images:', error);
    }
  };

  const handleImageLoad = async () => {
    if (!loading && hasMore) {
      await fetchNextImages();
    }
  };

  return (
    <GalleryContext.Provider value={{ loading }}>
      <div>
        {images.map((image, index) => (
          <img key={index} src={`/path/to/${image.filename}`} onLoad={handleImageLoad} alt={`Image ${index + 1}`}/>
        ))}
        {loading && <p>Loading more images...</p>}
        {!hasMore && !loading && <p>No more images to load.</p>}
      </div>
    </GalleryContext.Provider>
  );
}

export default App;
