      {currentStep === 2 && <StepTwo formData={formData} onChange={(data) => setFormData(data)} errors={errors} onNextStep={handleNextStep} />}
      {currentStep === 3 && (
        <form onSubmit={handleSubmit}>
          <div>
            <label>Name: </label>
            <input type="text" name="name" value={formData.name} onChange={(e) => setFormData({ ...formData, [e.target.name]: e.target.value })} />
            {errors.name && <span style={{ color: 'red' }}>{errors.name}</span>}
          </div>
          <div>
            <label>Email: </label>
            <input type="email" name="email" value={formData.email} onChange={(e) => setFormData({ ...formData, [e.target.name]: e.target.value })} />
            {errors.email && <span style={{ color: 'red' }}>{errors.email}</span>}
          </div>
          <div>
            <label>Password: </label>
            <input type="password" name="password" value={formData.password} onChange={(e) => setFormData({ ...formData, [e.target.name]: e.target.value })} />
            {errors.password && <span style={{ color: 'red' }}>{errors.password}</span>}
          </div>
