const validateFormData = (req, res, next) => {
    const { username, password, email } = req.body;

    // Basic validation regex rules
    const usernameRegex = /^[a-zA-Z0-9._]{3,20}$/;
    const passwordRegex = /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]{8,}$/;
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

    if (!usernameRegex.test(username)) {
        return res.status(400).json({ error: 'Invalid username format' });
    }
    if (!passwordRegex.test(password)) {
        return res.status(400).json({ error: 'Password must be at least 8 characters long and include uppercase, lowercase letters, numbers, and special characters' });
    }
    if (!emailRegex.test(email)) {
        return res.status(400).json({ error: 'Invalid email format' });
    }

    next();
};

// POST /signup
router.post('/signup', validateFormData, async (req, res) => {
    const { username, password, email } = req.body;

    try {
        // Check if user already exists
