import React, { useState, useEffect } from 'react';
import Router from './Router'; // Assuming you have a router file for routing

// Context to store form data and validation errors
const FormContext = React.createContext();

function App() {
  const [formData, setFormData] = useState({
    email: '',
    password: '',
    confirmPassword: ''
  });

  const [errors, setErrors] = useState({
    email: '',
    password: '',
    confirmPassword: ''
  });

  useEffect(() => {
    // Function to validate email format
    const validateEmail = (email) =>
      /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

    // Function to validate password strength
    const validatePassword = (password) =>
      /^(?=.*[A-Z])(?=.*\d)(?=.*[!@#$%^&*()_+\-=\[\]{};':"\\|,.<>\/?]).{8,}$/.test(password);

    // Validate each field
    const newErrors = {
      email: !validateEmail(formData.email) ? 'Invalid email format' : '',
      password: !validatePassword(formData.password)
        ? 'Password must be at least 8 characters long and include uppercase letter, a number, and special character'
        : '',
      confirmPassword:
        formData.confirmPassword !== formData.password
          ? 'Passwords do not match'
          : ''
    };

    setErrors(newErrors);
  }, [formData]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prevData) => ({
      ...prevData,
      [name]: value
    }));
  };

  return (
    <FormContext.Provider value={{ formData, errors, handleInputChange }}>
      <Router />
    </FormContext.Provider>
  );
}

