const express = require('express');
const bodyParser = require('body-parser');
const { Pool } = require('pg');

// Create an Express application
const app = express();

// Use body-parser middleware to parse JSON bodies
app.use(bodyParser.json());

// Setup a PostgreSQL database connection pool
const pool = new Pool({
  user: 'your_username',
  host: 'localhost', // or your database host
  database: 'your_database_name',
  password: 'your_password',
  port: 5432, // default PostgreSQL port
});

// Middleware to handle errors globally
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(500).send('Internal Server Error');
});

// Function to connect and query the database
async function queryDatabase(queryText, params = []) {
  try {
    const client = await pool.connect();
    const result = await client.query(queryText, params);
    client.release();
    return result.rows;
  } catch (error) {
    console.error(`Error executing ${queryText}:`, error.stack);
    throw error;
  }
}

// Example route for adding a new user to the database
app.post('/users', async (req, res) => {
  const { username, password, email } = req.body;

  // Validate input using regex rules
  if (!username || !password || !email) {
    return res.status(400).json({ error: 'Username, password, and email are required' });
  }

  const validateRegex = /^[a-zA-Z0-9_]{3,}$/; // Username must be at least 3 characters long and contain only letters, numbers, or underscores
  if (!validateRegex.test(username)) {
    return res.status(400).json({ error: 'Username must contain only letters, numbers, or underscores' });
  }

  const validateEmail = /^[^\s@]+@[^\s@]+\.[^\s@]+$/; // Email must be a valid email address
  if (!validateEmail.test(email)) {
    return res.status(400).json({ error: 'Invalid email format' });
  }

  // Hash the password before storing it in the database (not shown for brevity)

  try {
    const { rowCount } = await queryDatabase(
      'INSERT INTO users (username, password, email) VALUES ($1, $2, $3)',
      [username, password, email]
    );
    res.status(201).json({ message: `${rowCount} user added` });
  } catch (error) {
    return res.status(500).json({ error: 'Failed to add user' });
  }
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});
