    e.preventDefault();
    try {
      if (!formData.title || !formData.artist || !formData.duration || !formData.url) {
        throw new Error('Please fill in all fields.');
      }

      const newItem = {
        title: formData.title,
        artist: formData.artist,
        duration: formData.duration,
        url: formData.url
      };

      if (formData.id) { // If editing existing item
