// Custom hook for audio control
const useAudioControl = () => {
  const [audio, setAudio] = useState(null);
  const [isPlaying, setIsPlaying] = useState(false);

  useEffect(() => {
    if (audio) {
      audio.volume = 0.5; // Set initial volume
    }
  }, [audio]);

  const play = () => {
    if (audio && !isPlaying) {
      audio.play();
      setIsPlaying(true);
    }
  };

  const pause = () => {
    if (audio && isPlaying) {
      audio.pause();
      setIsPlaying(false);
    }
  };

  return { audio, play, pause };
};

