// Import necessary modules
const express = require('express');
const bcrypt = require('bcryptjs');
const jwt = require('jsonwebtoken');
const db = require('../db'); // Assuming a database connection setup

const router = express.Router();

// Middleware to authenticate user token
router.use((req, res, next) => {
  const token = req.headers['x-access-token'];

  if (!token) return res.status(403).send('No token provided');

  try {
    const decoded = jwt.verify(token, process.env.JWT_SECRET);
    req.user = decoded;
    next();
  } catch (err) {
    console.error(err);
    return res.status(401).send('Invalid token');
  }
});

// Middleware to validate user permissions
router.use((req, res, next) => {
  if (!req.user.permissions.includes('admin')) {
    return res.status(403).send('Forbidden access');
  }
  next();
});

// User authentication middleware
router.post('/login', async (req, res) => {
  const { username, password } = req.body;

  try {
    const user = await db.query(`SELECT * FROM users WHERE username = $1`, [username]);

    if (!user.length) return res.status(401).send('Invalid credentials');

    const isMatch = await bcrypt.compare(password, user[0].password);

    if (!isMatch) return res.status(401).send('Invalid credentials');

    const token = jwt.sign({ id: user[0].id, username: user[0].username }, process.env.JWT_SECRET, {
      expiresIn: 86400 // expires in 24 hours
    });

    res.json({
      id: user[0].id,
      username: user[0].username,
      token
    });
  } catch (err) {
    console.error(err);
    res.status(500).send('Server error');
  }
});

// Middleware to protect routes that require admin permission
router.get('/admin', async (req, res) => {
  const { id, username } = req.user;

  try {
    res.json({
      message: `Hello ${username}, you are an admin`,
      userId: id
    });
  } catch (err) {
    console.error(err);
    res.status(500).send('Server error');
  }
});

module.exports = router;
