import React, { useState, useEffect } from 'react';

// Define a context to hold the query state and debounced function
const SearchContext = React.createContext();

// Custom hook for debouncing queries
function useDebounce(value, delay) {
  const [debouncedValue, setDebouncedValue] = useState(value);

  useEffect(() => {
    const handler = setTimeout(() => {
      setDebouncedValue(value);
    }, delay);

    return () => clearTimeout(handler);
  }, [value, delay]);

  return debouncedValue;
}

// DetailPage component
function DetailPage({ itemId }) {
  // State to hold the query string
  const [query, setQuery] = useState('');
  // Context consumer to get debounce function from SearchContext
  const { debounce } = React.useContext(SearchContext);

  // Function to handle input changes and update debounced query
  const handleChange = (e) => {
    setQuery(e.target.value);
  };

  // Use useEffect to fetch item details based on the debounced query
  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch(`/api/items/${itemId}`);
        if (!response.ok) {
          throw new Error(`Failed to fetch data: ${response.statusText}`);
        }
        const data = await response.json();
        console.log(data);
      } catch (error) {
        console.error('Error fetching item details:', error);
      }
    };

    // Call fetchData with the debounced query
    fetchData(query);
  }, [debounce, itemId]);

  return (
    <div>
      <h1>Item Details</h1>
      <input
        type="text"
        value={query}
        onChange={handleChange}
        placeholder="Search for related items"
      />
      {/* Placeholder for item details */}
      {/* <p>Details of item with ID: {itemId}</p> */}
    </div>
  );
}

// Provider for SearchContext
const SearchProvider = ({ children }) => {
  const debounce = useDebounce(300); // Debounce delay of 300ms

  return (
    <SearchContext.Provider value={{ debounce }}>
      {children}
    </SearchContext.Provider>
  );
};

export default function App() {
  return (
    <SearchProvider>
      <DetailPage itemId="123" />
    </SearchProvider>
  );
}
