      <button onClick={handleDelete}>Delete Item</button>
    </div>
  );
}

// Provider component for context
function DetailPageProvider({ children }) {
  const [items, setItems] = useState([]);

  useEffect(() => {
    // Mock data retrieval from a server or API
    setTimeout(() => {
      const mockItems = Array.from({ length: 10 }, (_, index) => ({
        id: `${index + 1}`,
        title: `Task ${index + 1}`,
        description: `Description of Task ${index + 1}`,
        assignedTo: `User ${Math.floor(Math.random() * 5) + 1}`,
        error: null,
        index,
      }));
      setItems(mockItems);
    }, 2000);
  }, []);

  // Function to update item position
  const updateItemPosition = (id, newIndex) => {
    const newItems = [...items];
    const oldIndex = items.findIndex((item) => item.id === id);

    if (oldIndex !== -1 && newIndex !== oldIndex) {
      newItems.splice(oldIndex, 1);
      newItems.splice(newIndex, 0, { ...items[oldIndex], index: newIndex });
      setItems(newItems);
    }
  };

  // Function to delete an item
  const deleteItem = (id) => {
    const newItems = items.filter((item) => item.id !== id);
    setItems(newItems);
  };

  return (
    <DetailPageContext.Provider value={{ updateItemPosition, deleteItem }}>
      {children}
    </DetailPageContext.Provider>
  );
}

