import React, { useState, useEffect } from 'react';

// Define context to manage alert queue
const AlertContext = React.createContext();

// Provider component to wrap components using the context
function AlertProvider({ children }) {
  const [queue, setQueue] = useState([]);

  // Function to add an alert to the queue
  const enqueueAlert = (alert) => {
    setQueue([...queue, alert]);
  };

  // Function to remove an alert from the queue
  const dequeueAlert = () => {
    if (queue.length > 0) {
      setQueue(queue.slice(1));
    }
  };

  return (
    <AlertContext.Provider value={{ queue, enqueueAlert, dequeueAlert }}>
      {children}
    </AlertContext.Provider>
  );
}

// Consumer component to access the alert context
const AlertConsumer = ({ children }) => {
  const { queue } = React.useContext(AlertContext);

  // Function to render alerts from the queue
  const renderAlerts = () => (
    <div>
      {queue.map((alert, index) => (
        <div key={index}>{alert.message}</div>
      ))}
    </div>
  );

  return children({ renderAlerts });
};

// Main ListPage component
const ListPage = ({ items }) => {
  const [currentItemIndex, setCurrentItemIndex] = useState(0);
  const [delay, setDelay] = useState(1000); // Delay in milliseconds

  useEffect(() => {
    if (queue.length > 0) {
      const alert = queue[0];
      setTimeout(() => {
        enqueueAlert(alert); // Re-enqueue the alert
        dequeueAlert(); // Remove the alert from the queue
      }, delay);
    }
  }, [queue, setQueue]);

  return (
    <div>
      {renderAlerts()}
      {/* Render items */}
      <ul>
        {items.map((item, index) => (
          <li key={index}>{item.name}</li>
        ))}
      </ul>

      {/* Add new item button */}
      <button onClick={() => {
        const newItem = `Item ${queue.length + 1}`;
        setQueue([...queue, { message: `Added ${newItem}` }]);
        setTimeout(() => {
          enqueueAlert({ message: `Added ${newItem} after delay` });
          dequeueAlert();
        }, delay);
      }}>
        Add Item
      </button>
    </div>
  );
};

