import React, { useState, useEffect } from 'react';
import axios from 'axios';

// Context for managing form state
const FormContext = React.createContext();

function FormPage() {
  const [item, setItem] = useState({ title: '', author: '', quantity: 0 });
  const [errors, setErrors] = useState({});
  const [loading, setLoading] = useState(false);
  const [successMessage, setSuccessMessage] = useState('');

  useEffect(() => {
    // Simulate fetching item data
    axios.get('https://api.example.com/item')
      .then(response => {
        setItem(response.data);
      })
      .catch(error => console.error('Error fetching item:', error));
  }, []);

  const validateForm = () => {
    let errors = {};

    if (!item.title) {
      errors.title = 'Title is required';
    }
    if (!item.author) {
      errors.author = 'Author is required';
    }
    if (typeof item.quantity !== 'number' || isNaN(item.quantity)) {
      errors.quantity = 'Quantity must be a number';
    }

    return errors;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setErrors(validateForm());

    if (Object.keys(errors).length > 0) {
      return;
    }

    setLoading(true);
    try {
      await axios.post('https://api.example.com/item', item);
      setSuccessMessage('Item saved successfully!');
      // Optionally, reset the form after saving
      setItem({ title: '', author: '', quantity: 0 });
    } catch (error) {
      console.error('Error saving item:', error);
      setSuccessMessage('Failed to save item.');
    }
    setLoading(false);
  };

  return (
    <div>
      <h1>{item._id ? 'Edit Item' : 'Create Item'}</h1>
      {successMessage && <p style={{ color: successMessage.startsWith('Error') ? 'red' : 'green' }}>{successMessage}</p>}
      <FormContext.Provider value={item}>
