const express = require('express');
const mongoose = require('mongoose');

// Initialize Express app
const app = express();

// Middleware to parse JSON bodies
app.use(express.json());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/book_inventory_manager', {
  useNewUrlParser: true,
  useUnifiedTopology: true,
});

// Database connection error handling
mongoose.connection.on('error', (err) => {
  console.error('MongoDB connection error:', err);
});

// Database connection success message
mongoose.connection.once('open', () => {
  console.log('Connected to MongoDB');
});

// Define a schema for the Book model
const bookSchema = new mongoose.Schema({
  title: String,
  author: String,
  genre: String,
  yearPublished: Number,
});

// Create a model based on the schema
const Book = mongoose.model('Book', bookSchema);

// Route to handle GET requests and sort/search book data dynamically
app.get('/books', async (req, res) => {
  try {
    // Extract query parameters for sorting and searching
    const { sortBy, searchQuery } = req.query;

    // Create a filter object based on the query parameters
    const filter = {};

    if (searchQuery) {
      filter.$or = [
        { title: { $regex: new RegExp(searchQuery, 'i') } },
        { author: { $regex: new RegExp(searchQuery, 'i') } },
        { genre: { $regex: new RegExp(searchQuery, 'i') } },
      ];
    }

    // Perform sorting based on the sortBy parameter
    const sortOptions = {};
    if (sortBy) {
      if (sortBy === 'asc' || sortBy === 'desc') {
        sortOptions[sortBy] = 1;
      } else {
        throw new Error('Invalid sorting order. Use "asc" or "desc".');
      }
    }

    // Fetch and return books from the database
    const books = await Book.find(filter).sort(sortOptions);
    res.json(books);
  } catch (error) {
    console.error('Error fetching books:', error);
    res.status(500).json({ error: 'Internal Server Error' });
  }
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
