import React, { useState, useEffect } from 'react';
import { useContext } from 'react'; // Assuming a context is used for managing book data
import { BookContext } from '../context/BookContext';
import Table from './Table';

const HomePage = () => {
  const [books, setBooks] = useState([]);
  const { booksData, loading, error } = useContext(BookContext);

  useEffect(() => {
    if (loading) return;
    if (error) throw error; // Handle error in production
    setBooks(booksData);
  }, [loading, error]);

  const handleSort = (column) => {
    const sortedBooks = [...books];
    sortedBooks.sort((a, b) => (b[column] > a[column]) ? -1 : 1); // Sort by column value in descending order
