    <div className="HomePage">
      {loading && <p>Loading...</p>}
      {error && <p>Error: {error.message}</p>}
      <h1>Book Inventory Manager</h1>
      <input
        type="text"
        placeholder="Search by title or author"
        onChange={handleSearch}
