// Import necessary modules
const express = require('express');
const app = express();
const router = express.Router();
const { PrismaClient } = require('@prisma/client');

// Initialize Prisma client
const prisma = new PrismaClient();

// Middleware to log incoming requests
app.use((req, res, next) => {
    console.log(`Received ${req.method} request for ${req.url}`);
    next();
});

// Route handler for sorting and searching books by column
router.get('/books', async (req, res) => {
    try {
        const { sortBy, sortOrder, searchTerm } = req.query;

        // Validate inputs
        if (!sortBy || !sortOrder || typeof sortBy !== 'string' || typeof sortOrder !== 'string') {
            return res.status(400).json({ error: 'Invalid query parameters' });
        }

        // Construct the search filter
        const where = searchTerm ? { name: { contains: searchTerm } } : {};

        // Perform sorting and filtering
        const books = await prisma.book.findMany({
            orderBy: { [sortBy]: sortOrder },
            where,
        });

        res.json(books);
    } catch (error) {
        console.error('Error fetching books:', error);
        res.status(500).json({ error: 'Internal Server Error' });
    }
});

// Route handler for adding a new book
router.post('/books', async (req, res) => {
    try {
        const { name, author, publishedYear } = req.body;

        // Validate inputs
        if (!name || !author || typeof name !== 'string' || typeof author !== 'string' || !publishedYear || typeof publishedYear !== 'number') {
            return res.status(400).json({ error: 'Invalid book data' });
        }

        const newBook = await prisma.book.create({
            data: { name, author, publishedYear },
        });

        res.status(201).json(newBook);
    } catch (error) {
        console.error('Error creating new book:', error);
        res.status(500).json({ error: 'Internal Server Error' });
    }
});

// Route handler for updating a book
router.put('/books/:id', async (req, res) => {
    try {
        const { id } = req.params;
        const { name, author, publishedYear } = req.body;

        // Validate inputs
        if (!name || !author || typeof name !== 'string' || typeof author !== 'string' || !publishedYear || typeof publishedYear !== 'number') {
            return res.status(400).json({ error: 'Invalid book data' });
        }

        const updatedBook = await prisma.book.update({
            where: { id },
            data: { name, author, publishedYear },
