  connectionString: process.env.DATABASE_URL,
  max: 10, // Max number of connections in the pool
});

// Define middleware to log request and response details
function logMiddleware(req, res, next) {
  console.log(`Method: ${req.method}, URL: ${req.url}`);
  next();
}

// Middleware to handle database errors
function errorHandler(err, req, res, next) {
  console.error('Error:', err.stack);
  res.status(500).json({ error: 'Internal Server Error' });
}

// Function to connect to the database and execute a query
async function executeQuery(query, values = []) {
  try {
    const client = await dbPool.connect();
    const result = await client.query(query, values);
    client.release();
    return result;
  } catch (error) {
    throw error; // Rethrow errors to be handled by errorHandler
  }
}

// Export the necessary functions and middleware
module.exports = {
  logMiddleware,
  errorHandler,
  executeQuery,
};
