<?php

// Define the WordPress REST API endpoint class
class BookInventoryManagerAPI {
    public function __construct() {
        add_action('rest_api_init', [$this, 'register_routes']);
    }

    // Register REST API routes
    public function register_routes() {
        register_rest_route('book-inventory/v1', '/books', [
            'methods' => WP_REST_Server::READABLE,
            'callback' => [$this, 'get_books'],
            'args' => [
                'columns' => new WP_REST_Param([
                    'description' => 'Array of columns to sort by',
                    'type' => 'array',
                    'required' => false,
                    'sanitize_callback' => function($value) {
                        return array_map('sanitize_text_field', $value);
                    },
                ]),
                'search' => new WP_REST_Param([
                    'description' => 'Search query',
                    'type' => 'string',
                    'required' => false,
                    'sanitize_callback' => 'sanitize_text_field',
                ]),
            ],
        ]);
    }

    // Handle GET request for books
    public function get_books(WP_REST_Request $request) {
        $columns = $request->get_param('columns');
        $search = $request->get_param('search');

        try {
            // Sanitize and validate inputs
            if (!is_array($columns)) $columns = [];
            if (empty($search)) $search = '';

            // Prepare database query parameters
            $params = [
                'search' => '%' . esc_sql($search) . '%',
                'order' => !empty($columns) ? $columns : ['id'],
                'orderby' => 'DESC'
            ];

            // Get books from the database using prepared statements
            $books = $this->get_books_from_db($params);

            // Return success response with the books data
            return new WP_REST_Response($books, 200);
        } catch (Exception $e) {
            // Log error and return error response
            error_log('Error fetching books: ' . $e->getMessage());
            return new WP_REST_Response(['error' => 'Failed to fetch books'], 500);
        }
    }

    // Helper method to get books from the database using prepared statements
    private function get_books_from_db($params) {
        global $wpdb;

        // Prepare SQL query
        $sql = "SELECT * FROM `books` WHERE `title` LIKE %s ORDER BY `id` DESC";
        foreach ($params['order'] as $key => $column) {
            $sql .= ", `$column` ASC" if ($key === 0);
            $sql .= ", `$column` DESC" if (isset($params['orderby']) && $params['orderby'] === 'DESC');
        }

        // Execute query
        return $wpdb->get_results($wpdb->prepare($sql, $params['search']));
    }
}

// Initialize the API class
new BookInventoryManagerAPI();
