function ListPage({ items }) {
  const [pollResults, setPollResults] = useState(null);
  const [loading, setLoading] = useState(true);

  // Fetch poll results using a hypothetical API
  useEffect(() => {
    fetch('/api/poll-results') // Replace with actual API endpoint
      .then(response => response.json())
      .then(data => setPollResults(data))
      .catch(error => console.error('Error fetching poll results:', error))
      .finally(() => setLoading(false));
  }, []);

  const handleVote = (itemId) => {
    fetch('/api/vote', { method: 'POST', body: JSON.stringify({ itemId }) })
      .then(response => response.json())
      .catch(error => console.error('Error voting for item:', error));
  };

  // Calculate percentage based on votes and total
  const calculatePercentage = (voteCount, totalVotes) => {
