  };

  if (loading) {
    return <div>Loading...</div>;
  }

  // Render items with percentages
  return (
    <PollContext.Provider value={pollResults}>
      <div className="list-page">
        {items.map(item => (
          <Item key={item.id} item={item} onVote={handleVote} />
        ))}
      </div>
    </PollContext.Provider>
  );
}

