  const { pollResults } = React.useContext(PollContext);

  if (!pollResults || !item.id) return null;

  // Calculate the current vote count for this item
  const voteCount = pollResults[item.id] || 0;
  const totalVotes = Object.values(pollResults).reduce((acc, val) => acc + val, 0);
  const percentage = calculatePercentage(voteCount, totalVotes);

  return (
