      <p>Vote Count: {voteCount} ({percentage}%)</p>
      <button onClick={() => onVote(item.id)}>Vote</button>
    </div>
  );
};

Item.propTypes = {
  item: PropTypes.shape({
    id: PropTypes.number.isRequired,
    title: PropTypes.string.isRequired
  }),
