<?php

// Check if it's a request to the REST API
if (!defined('WP_REST_REQUEST')) {
    return;
}

// Include necessary WordPress functions and classes
require_once ABSPATH . 'wp-includes/rest-api/endpoints/class-wp-rest-posts-controller.php';
require_once ABSPATH . 'wp-includes/rest-api/endpoints/class-wp-rest-comments-controller.php';

class CustomCommentsController extends WP_REST_Comments_Controller {
    protected $namespace = 'custom-v1'; // Your custom namespace
    protected $rest_base = 'comments';   // Endpoint base

    public function __construct() {
        parent::__construct('post');
    }

    public function register_routes() {
        register_rest_route($this->namespace, '/' . $this->rest_base, array(
            'methods' => WP_REST_Server::CREATABLE | WP_REST_Server::READABLE,
            'callback' => array($this, 'create_item'),
            'args' => array(
                'comment_post_ID' => array(
                    'required' => true,
                    'type' => 'integer',
                ),
                'content' => array(
                    'required' => false,
                    'type' => 'string',
                ),
                'author_name' => array(
                    'required' => false,
                    'type' => 'string',
                ),
                'author_email' => array(
                    'required' => false,
                    'type' => 'string',
                ),
            ),
        ));
    }

    public function create_item($request) {
        $post_id = sanitize_text_field($request['comment_post_ID']);
        $content = sanitize_textarea_field($request['content']);
        $author_name = sanitize_text_field($request['author_name']);
        $author_email = sanitize_email($request['author_email']);

        // Prepare the data for database insertion
        $data = array(
            'comment_content' => $content,
            'comment_author' => $author_name,
            'comment_author_email' => $author_email,
            'comment_approved' => true, // or false if you want to approve manually
            'post_id' => $post_id,
        );

        // Insert comment using WordPress's wp_insert_comment function with prepared statements
        $comment_ID = wp_insert_comment($data);

        if (is_wp_error($comment_ID)) {
            return new WP_Error('create_comment_failed', __('Comment creation failed'), array('status' => 500));
        }

        return new WP_REST_Response(get_comment($comment_ID), 201);
    }
}

// Hook into the REST API
add_action('rest_api_init', function() {
    new CustomCommentsController();
});
