    $comment_id = $_POST['comment_id'];
    $reply_text = filter_input(INPUT_POST, 'reply', FILTER_SANITIZE_STRING);

    if (!empty($reply_text)) {
        // Insert comment reply into database using prepared statement
        $stmt = $mysqli->prepare("INSERT INTO comments (parent_id, content, author_id) VALUES (?, ?, ?)");
        $stmt->bind_param('iis', $comment_id, $reply_text, $_SESSION['user_id']);

        if ($stmt->execute()) {
            echo 'Reply added successfully!';
        } else {
            echo 'Error: ' . $stmt->error;
        }
    }
}

// Sanitize input for comment deletion
if (isset($_POST['delete']) && isset($_POST['comment_id'])) {
    $comment_id = $_POST['comment_id'];

    // Delete comment from database using prepared statement
    $stmt = $mysqli->prepare("DELETE FROM comments WHERE id = ?");
