import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Comment = ({ post }) => {
  const [comment, setComment] = useState('');
  const [replies, setReplies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  // Fetch replies to the comment
  useEffect(() => {
    async function fetchReplies() {
      try {
        const response = await axios.get(`/api/replies/${post.id}`);
        setReplies(response.data);
      } catch (err) {
        setError(err);
      }
      setLoading(false);
    }

    if (!loading) {
      fetchReplies();
    }
  }, [post, loading]);

  // Function to handle comment submission
  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await axios.post('/api/comments', { postId: post.id, content: comment });
      setComment('');
      setReplies([...replies, response.data]);
    } catch (err) {
      setError(err);
    }
  };

  // Function to handle reply submission
  const handleReplySubmit = async (e, replyId) => {
    e.preventDefault();
    try {
      const response = await axios.post('/api/replies', { parentId: replyId, content: comment });
      setComment('');
      setReplies([...replies, response.data]);
    } catch (err) {
      setError(err);
    }
  };

  if (loading) return <p>Loading...</p>;
  if (error) return <p>Error loading comments: {error.message}</p>;

  return (
    <div className="comment">
      <h3>{post.content}</h3>
      <form onSubmit={handleSubmit}>
        <textarea value={comment} onChange={(e) => setComment(e.target.value)} placeholder="Add a comment" />
        <button type="submit">Submit</button>
      </form>
      {replies.length > 0 ? (
        <div className="replies">
          {replies.map((reply, index) => (
            <div key={index} className="reply">
              <p>{reply.content}</p>
              <form onSubmit={(e) => handleReplySubmit(e, reply.id)}>
                <textarea value={comment} onChange={(e) => setComment(e.target.value)} placeholder="Add a reply" />
                <button type="submit">Submit</button>
              </form>
            </div>
          ))}
        </div>
      ) : (
        <p>No replies yet.</p>
      )}
    </div>
  );
};

export default Comment;
```

