// utils.js

/**
 * Utility functions used across the Blog CMS with Comments project.
 */

/**
 * Determines if a comment has children (replies) and sets the `hasReplies` flag accordingly.
 * @param {Object} comment - The comment object containing replies.
 */
export function setHasReplies(comment) {
  if (Array.isArray(comment.replies) && comment.replies.length > 0) {
    comment.hasReplies = true;
  } else {
    comment.hasReplies = false;
  }
}

/**
 * Formats a date string for display.
 * @param {string} dateString - The input date string in 'YYYY-MM-DD' format.
 * @returns {string} Formatted date string in 'MM/DD/YYYY'.
 */
export function formatDate(dateString) {
  try {
    const date = new Date(dateString);
    return `${date.getMonth() + 1}/${date.getDate()}/${date.getFullYear()}`;
  } catch (error) {
    console.error('Error formatting date:', error);
    return dateString; // Return original string if parsing fails
  }
}

/**
 * Ensures a comment has a unique identifier.
 * @param {Object} comment - The comment object to be processed.
 */
export function ensureCommentId(comment) {
  if (!comment.id) {
    comment.id = Math.random().toString(36).substr(2, 9); // Generate random ID
  }
}

/**
 * Calculates the depth of a comment in the tree structure.
 * @param {Object} comment - The current comment object to calculate depth for.
 * @returns {number} The depth of the comment.
 */
export function calculateCommentDepth(comment) {
  let depth = 0;
  if (comment.parentId) {
    const parent = findParentCommentById(comment, comments);
    if (parent) {
      depth = 1 + calculateCommentDepth(parent);
    }
  }
  return depth;
}

/**
 * Searches for a parent comment by its ID.
 * @param {Object} child - The comment object whose parent is to be found.
 * @returns {Object|null} The parent comment or null if not found.
 */
export function findParentCommentById(child, comments) {
  return comments.find(parent => parent.id === child.parentId);
}

/**
 * Ensures a comment's parent ID exists in the context of all comments.
 * @param {Object} comment - The comment object to be processed.
 */
export function ensureParentExists(comment, comments) {
  if (comment.parentId && !comments.some(c => c.id === comment.parentId)) {
    throw new Error(`Parent comment with ID ${comment.parentId} not found.`);
  }
}

/**
 * Converts a string into a slug format.
 * @param {string} text - The input string to be converted to a slug.
 * @returns {string} The slugified string.
 */
export function createSlug(text) {
  return text.toLowerCase().replace(/[^a-z0-9\s]/g, '').replace(/\s+/g, '-');
}

/**
 * Checks if an object is empty (has no properties).
 * @param {Object} obj - The object to check.
 * @returns {boolean} True if the object is empty, false otherwise.
 */
export function isEmpty(obj) {
  return Object.keys(obj).length === 0;
}
