const express = require('express');
const db = require('../database'); // Assuming you have a database setup

// Initialize Express router
const router = express.Router();

// Middleware to parse JSON body
router.use(express.json());

// Route to get all comments
router.get('/', async (req, res) => {
  try {
    const comments = await db.query('SELECT * FROM comments');
    res.json(comments);
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Failed to fetch comments' });
  }
});

// Route to create a new comment
router.post('/', async (req, res) => {
  try {
    const { content, userId, postId, parentId } = req.body;
    const newComment = await db.query('INSERT INTO comments SET ?', { content, userId, postId, parentId });
    res.status(201).json(newComment);
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Failed to create comment' });
  }
});

// Route to update a comment
router.put('/:id', async (req, res) => {
  try {
    const { content, state } = req.body;
    const { id } = req.params;
    const updatedComment = await db.query('UPDATE comments SET content = ?, state = ? WHERE id = ?', [content, state, id]);
    if (updatedComment.affectedRows === 0) {
      res.status(404).json({ error: 'Comment not found' });
    } else {
      res.json(updatedComment);
    }
  } catch (error) {
    console.error(error);
    res.status(500).json({ error: 'Failed to update comment' });
  }
});

// Route to delete a comment
router.delete('/:id', async (req, res) => {
  try {
    const { id } = req.params;
    const deletedComment = await db.query('DELETE FROM comments WHERE id = ?', [id]);
    if (deletedComment.affectedRows === 0) {
      res.status(404).json({ error: 'Comment not found' });
    } else {
      res.json(deletedComment);
    }
