import { createContext, useContext, useState, useEffect } from 'react';

// Create a context for global state management
const ShoppingAppContext = createContext();

// Custom hook to manage cart items and update them in local storage
function useShoppingCart() {
  // Initial cart state
  const [cartItems, setCartItems] = useState(
    JSON.parse(localStorage.getItem('cart')) || []
  );

  useEffect(() => {
    localStorage.setItem('cart', JSON.stringify(cartItems));
  }, [cartItems]);

  // Function to add an item to the cart
  const addItemToCart = (item) => {
    setCartItems([...cartItems, item]);
  };

  // Function to remove an item from the cart
  const removeFromCart = (itemId) => {
    setCartItems(cartItems.filter(item => item.id !== itemId));
  };

  // Function to update an item's quantity in the cart
  const updateCartItemQuantity = (itemId, newQuantity) => {
    if (newQuantity <= 0) {
      return;
    }
    setCartItems(
      cartItems.map(item =>
        item.id === itemId ? { ...item, quantity: newQuantity } : item
      )
    );
  };

  // Function to clear the entire cart
  const clearCart = () => {
    setCartItems([]);
  };

  return {
    cartItems,
    addItemToCart,
    removeFromCart,
    updateCartItemQuantity,
    clearCart
  };
}

// Higher-order component to wrap your app with the context provider
function ShoppingAppProvider({ children }) {
  return (
    <ShoppingAppContext.Provider value={useShoppingCart()}>
      {children}
    </ShoppingAppContext.Provider>
  );
}

export { ShoppingAppProvider, useShoppingCart };
