```
import { createSlice, PayloadAction } from '@reduxjs/toolkit';

export interface CartItem {
  id: number;
  name: string;
  price: number;
  quantity: number;
}

interface ShoppingState {
  cart: CartItem[];
  totalItems: number;
  totalPrice: number;
}

const initialState: ShoppingState = {
  cart: [],
  totalItems: 0,
  totalPrice: 0,
};

export const shoppingSlice = createSlice({
  name: 'shopping',
  initialState,
  reducers: {
    addItemToCart(state, action: PayloadAction<CartItem>) {
      const itemIndex = state.cart.findIndex((i) => i.id === action.payload.id);

      if (itemIndex !== -1) {
        // Item already exists in the cart, increase quantity
        state.cart[itemIndex].quantity += 1;
      } else {
        // Add new item to the cart
        state.cart.push({ ...action.payload, quantity: 1 });
      }

      // Update total items and total price
      state.totalItems = state.cart.reduce((sum, item) => sum + item.quantity, 0);
      state.totalPrice = state.cart.reduce(
        (sum, item) => sum + item.price * item.quantity,
        0
      );
    },
    removeItemFromCart(state, action: PayloadAction<CartItem>) {
      const itemIndex = state.cart.findIndex((i) => i.id === action.payload.id);

      if (itemIndex !== -1) {
        // Decrease quantity or remove item if quantity becomes zero
        state.cart[itemIndex].quantity -= 1;

        if (state.cart[itemIndex].quantity <= 0) {
          const updatedCart = state.cart.filter((i) => i.id !== action.payload.id);
          state.cart = updatedCart;
        }
      }

      // Update total items and total price
      state.totalItems = state.cart.reduce((sum, item) => sum + item.quantity, 0);
      state.totalPrice = state.cart.reduce(
        (sum, item) => sum + item.price * item.quantity,
        0
      );
    },
    clearCart(state) {
      // Clear the cart
      state.cart = [];
      state.totalItems = 0;
      state.totalPrice = 0;
    },
  },
});

export const { addItemToCart, removeItemFromCart, clearCart } = shoppingSlice.actions;

export default shoppingSlice.reducer;
```

