import { createSlice } from '@reduxjs/toolkit';

// Initial state for cart
const initialState = {
  items: [],
  totalItems: 0,
  totalPrice: 0,
};

// Slice creation for cart data
const cartSlice = createSlice({
  name: 'cart',
  initialState,
  reducers: {
    addItem(state, action) {
      // Check if the item already exists in the cart
      const existingItemIndex = state.items.findIndex(
        (item) => item.id === action.payload.id
      );

      // If it exists, update its quantity
      if (existingItemIndex !== -1) {
        state.items[existingItemIndex].quantity += 1;
      } else {
        // Otherwise, add the new item to the cart
        state.items.push({
          ...action.payload,
          quantity: 1,
        });
      }
      // Update total items and total price
      state.totalItems = state.items.reduce((total, item) => total + item.quantity, 0);
      state.totalPrice = state.items.reduce(
        (total, item) => total + item.price * item.quantity,
        0
      );
    },
    removeItem(state, action) {
      // Find the index of the item to be removed
      const indexToRemove = state.items.findIndex((item) => item.id === action.payload.id);

      if (indexToRemove !== -1) {
        // If the quantity is greater than 1, decrement it
        if (state.items[indexToRemove].quantity > 1) {
          state.items[indexToRemove].quantity -= 1;
        } else {
          // Otherwise, remove the item from the cart
          state.items.splice(indexToRemove, 1);
        }
        // Update total items and total price
        state.totalItems = state.items.reduce((total, item) => total + item.quantity, 0);
        state.totalPrice = state.items.reduce(
          (total, item) => total + item.price * item.quantity,
          0
        );
      }
    },
    clearCart(state) {
      // Clear the cart by resetting initial state
      Object.assign(state, initialState);
    },
  },
});

// Export actions from slice
export const { addItem, removeItem, clearCart } = cartSlice.actions;

// Export reducer function for integration with store
export default cartSlice.reducer;
