import React, { useState, useEffect } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { userSlice } from './userReducer';

interface LoginModalProps {
  isOpen: boolean;
  onClose: () => void;
}

const LoginModal: React.FC<LoginModalProps> = ({ isOpen, onClose }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const dispatch = useDispatch();
  const { login } = userSlice.actions;

  useEffect(() => {
    if (isOpen) {
      // Clear any previous error messages
      dispatch(userSlice.actions.clearErrors());
    }
  }, [isOpen]);

  const handleLogin = () => {
    if (!email || !password) {
      dispatch(userSlice.actions.setError('Email and password are required'));
      return;
    }

    try {
      dispatch(login({ email, password }));
    } catch (error: any) {
      dispatch(userSlice.actions.setError(error.message));
    }
  };

  const handleCancel = () => {
    onClose();
    setEmail('');
    setPassword('');
  };

  return (
    <div className={`modal ${isOpen ? 'open' : ''}`}>
      <h2>Login</h2>
      <input
        type="email"
        placeholder="Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)}
      />
      <input
        type="password"
        placeholder="Password"
        value={password}
        onChange={(e) => setPassword(e.target.value)}
      />
      {useSelector((state: RootState) => state.user.errors && (
        <p style={{ color: 'red' }}>{state.user.errors}</p>
      ))}
      <div className="button-group">
        <button onClick={handleLogin}>Login</button>
        <button onClick={handleCancel}>Cancel</button>
      </div>
    </div>
  );
};

export default LoginModal;
