import { createAsyncThunk, createSlice } from '@reduxjs/toolkit';
import axios from 'axios';

// Create an async thunk to handle API requests
export const fetchProducts = createAsyncThunk('products/fetchProducts', async () => {
  try {
    // Make a GET request to the server's API endpoint
    const response = await axios.get('/api/products');
    return response.data;
  } catch (error) {
    throw new Error(`Failed to fetch products: ${error.message}`);
  }
});

// Define a slice for managing product data
export const productsSlice = createSlice({
  name: 'products',
  initialState: {
    products: [],
    loading: false,
    error: null,
  },
  reducers: {},
  extraReducers: (builder) => {
    builder
      .addCase(fetchProducts.pending, (state) => {
        // Set loading to true while fetching
        state.loading = true;
        state.error = null;
      })
      .addCase(fetchProducts.fulfilled, (state, action) => {
        // Update the products array with fetched data and set loading to false
        state.products = action.payload;
        state.loading = false;
        state.error = null;
      })
      .addCase(fetchProducts.rejected, (state, action) => {
        // Set error message if fetching fails and set loading to false
        state.error = `Error: ${action.payload.message}`;
        state.loading = false;
      });
  },
});

// Export the reducer function for the products slice
export default productsSlice.reducer;

// Export the async thunk to fetch products
export { fetchProducts };
