import React, { useState, useEffect } from 'react';
import { useNavigate, Outlet, Navigate, useLocation } from 'react-router-dom';
import axios from 'axios'; // Assuming Axios is used for API requests

const SecureRoute = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(null);
  const location = useLocation();
  const navigate = useNavigate();

  useEffect(() => {
    // Simulate an authentication check by fetching a token
    axios.get('/api/auth/check-token')
      .then((response) => {
        if (response.data.token) {
          setIsLoggedIn(true);
        } else {
          setIsLoggedIn(false);
          navigate('/login', { state: { from: location.pathname }, replace: true });
        }
      })
      .catch((error) => {
        console.error('Error checking authentication:', error);
        navigate('/login', { state: { from: location.pathname }, replace: true });
      });
  }, [location]);

  if (isLoggedIn === null) return <div>Loading...</div>;

  return isLoggedIn ? (
    <Outlet />
  ) : (
    <Navigate to="/login" state={{ from: location.pathname }} />
  );
};

export default SecureRoute;
