import useAuth from './auth'; // Assuming there's a custom auth hook

export const UserContext = createContext();

const UserProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const { login, logout, isAuthenticated } = useAuth(); // Use the auth context to handle user authentication

  useEffect(() => {
    // Initialize user state when component mounts
    if (isAuthenticated()) {
      login().then(setUser);
    }
  }, []); // Dependency array ensures this runs only once on mount

  const logIn = async () => {
    try {
      await login();
      setUser(await login());
    } catch (error) {
      console.error('Error logging in:', error);
    }
  };

  const logOut = async () => {
    try {
      await logout();
      setUser(null);
    } catch (error) {
      console.error('Error logging out:', error);
    }
  };

  return (
    <UserContext.Provider value={{ user, logIn, logOut }}>
      {children}
    </UserContext.Provider>
  );
};

export default UserProvider;
```

