import { useContext, useEffect, useState } from 'react';
import axios from 'axios';

// Context for sharing loader states across components
const LoaderContext = React.createContext();

export function ProvideLoader({ children }) {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  return (
    <LoaderContext.Provider value={{ loading, error }}>
      {children}
    </LoaderContext.Provider>
  );
}

export function useLoader() {
  return useContext(LoaderContext);
}

const fetchData = async (url) => {
  try {
    setLoading(true);
    const response = await axios.get(url);
    if (!response.ok) {
      throw new Error(response.statusText);
    }
    return response.data;
  } catch (error) {
    setError(error.message || 'An error occurred while fetching data');
    console.error('Error fetching data:', error);
  } finally {
    setLoading(false);
  }
};

export function ProtectedRoute({ path, element, loaderUrl }) {
  const { loading, error } = useLoader();

  useEffect(() => {
    if (loading) return;
    fetchData(loaderUrl).catch((err) => console.error(err));
  }, [loading]);

  if (loading) {
    return <div>Loading...</div>;
  }

  if (error) {
    return <div>Error: {error}</div>;
  }

  return element;
}
```

Explanation:
- `LoaderContext` is used to manage loading and error states across components.
- `ProvideLoader` component provides these states as context values.
- `useLoader` hook is a custom hook that accesses the shared loader states.
- `fetchData` function handles network requests with proper error handling and progress indicators using `useState`.
- `ProtectedRoute` is a wrapper component that uses `useLoader` to check loading or error states before rendering its child element. It also calls the `fetchData` function when the route changes but only if not already loading.
