// utils.js

// Function to check if a user is authenticated based on token storage
export const isAuthenticated = () => {
    try {
        // Retrieve token from local storage
        const token = localStorage.getItem('authToken');

        // Check if token exists and it's not expired (assuming expiration handling)
        return token && !isExpired(token); // Implement isExpired function to check token validity
    } catch (error) {
        console.error("Error checking authentication:", error);
        return false;
    }
};

// Helper function to determine if a token has expired
function isExpired(token) {
    const now = new Date();
    const expirationTime = new Date(JSON.parse(atob(token.split('.')[1])).exp * 1000); // Assuming Bearer token format
    return expirationTime < now;
}

// Function to handle logout by clearing the authentication token
export const logOut = () => {
    try {
        localStorage.removeItem('authToken');
        console.log("User logged out successfully.");
    } catch (error) {
        console.error("Error logging out:", error);
    }
};

// Middleware function for protected routes, checks authentication before rendering components
export const secureRouteMiddleware = ({ req, res, next }) => {
    if (!isAuthenticated()) {
        return res.status(401).json({ message: "Unauthorized access." });
    }
    next();
};
