Creating a Node.js utility function for error handling is an important aspect of building robust applications. Below is a simple example of how you can create such a utility function:

```javascript
// Define the error handler utility function
const errorHandler = (err, res) => {
  if (!err || !res) {
    console.error('Error handler called without required arguments');
    return;
  }

  // Log the error for debugging purposes
  console.error(err);

  // Set a default response status and message
  let statusCode = 500; // Internal Server Error
  let errorMessage = 'An unexpected error occurred. Please try again later.';

  // Check if specific error types or messages exist
  if (err.name === 'ValidationError') {
    statusCode = 400; // Bad Request
    const errors = err.errors.map(error => `${error.path}: ${error.message}`);
    errorMessage = `Validation errors: ${errors.join(', ')}`;
  } else if (err.code && err.errno) { // MySQL error
    statusCode = 500;
    errorMessage = `MySQL error (${err.code}): ${err.sqlMessage}`;
  }

  // Send the response with the appropriate status and message
  res.status(statusCode).json({ success: false, error: errorMessage });
};

// Example usage:
module.exports = errorHandler;
```

