Request validation is an important aspect of building robust web applications in Node.js. Stream-based request handling allows you to validate data as it arrives without fully loading the entire body into memory. Here’s how you can implement request validation using Node.js streams.

Let's assume we have a simple HTTP server that processes incoming JSON requests. We want to validate that the incoming JSON object has required fields and that they are of the correct types.

### Step 1: Set Up Your Server

First, create a basic Express server:

```javascript
const express = require('express');
const app = express();
app.use(express.json()); // Middleware to parse JSON bodies

// Define a route for processing JSON requests
app.post('/process', (req, res) => {
  console.log('Received request:', req.body);

  // Validate the incoming data using streams
  validateJson(req)
    .then(() => {
      res.status(200).send('Data validated successfully');
    })
    .catch(error => {
      res.status(400).json({ error: error.message });
    });
});

// Start the server
app.listen(3000, () => {
  console.log('Server is running on port 3000');
});
```

### Step 2: Implement Request Validation Logic

We will use a custom function `validateJson` to handle the validation. This function uses Node.js streams to process the request body:

```javascript
const { Transform } = require('stream');

function validateJson(req) {
  return new Promise((resolve, reject) => {
    const stream = req.rawBody;

    // Use a transform stream to check the structure and types of the JSON object
    const validStream = new Transform({
      transform(chunk, encoding, callback) {
        let parsedData;

        try {
          parsedData = JSON.parse(chunk);
        } catch (error) {
          return callback(error);
        }

        // Define required fields and their expected types
        const requiredFields = {
          name: 'string',
          age: 'number',
          email: 'string'
        };

        for (const [field, type] of Object.entries(requiredFields)) {
          if (!parsedData.hasOwnProperty(field) || typeof parsedData[field] !== type) {
            return callback(new Error(`Missing or invalid field ${field}`));
          }
        }

        // If all checks pass
        callback(null, chunk);
      },
      final(callback) {
        resolve();
      }
    });

    stream.pipe(validStream);
  });
}

// Define the rawBody property to allow access to the request body as a stream
Object.defineProperty(req, 'rawBody', {
  get() {
    const buffers = [];
    req.on('data', (chunk) => buffers.push(chunk));
    req.on('end', () => this.body = Buffer.concat(buffers).toString());
    return req;
  }
});
```

### Explanation

1. **Request Handling**: The server uses `express.json()` middleware to automatically parse incoming JSON bodies into JavaScript objects.

2. **Custom Stream for Validation**: We create a custom transform stream that parses the request body as JSON and checks if it contains required fields with the correct types.

3. **Error Handling**: If any field is missing or of an incorrect type, an error is returned by the stream, which is caught in the promise chain.

4. **Stream API**: The `rawBody` property is defined on the request object to access the incoming body as a stream using Node.js streams API.

This setup allows you to validate JSON data as it arrives without consuming too much memory, making your server more efficient and scalable.
