### Step 3: Create the Server and Endpoint

Create a file named `server.js` and add the following code:

```javascript
const express = require('express');
const sharp = require('sharp');
const multer = require('multer');
const bodyParser = require('body-parser');

const app = express();
const upload = multer({ dest: 'uploads/' });

app.use(bodyParser.json());

// Endpoint to resize an image
app.post('/resize', upload.single('file'), async (req, res) => {
  if (!req.file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }

  const { width, height } = req.body;

  try {
    // Read the image file
    const inputBuffer = fs.readFileSync(req.file.path);

    // Resize the image using sharp
    const resizedImage = await sharp(inputBuffer)
      .resize(width, height, { fit: 'inside' })
      .toBuffer();

    // Send the resized image as a response
    res.writeHead(200, {
      'Content-Type': req.file.mimetype,
      'Content-Length': resizedImage.length,
    });
    res.end(resizedImage);
  } catch (error) {
    console.error('Error resizing image:', error);
    res.status(500).json({ error: 'Failed to resize image' });
  }
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});
```

