```
Creating a Node.js middleware for JSON payload encryption and decryption involves using libraries such as `crypto` or `jwe-js` to handle the encryption and decryption processes. Below is an example of how you can create such a middleware using `crypto` for AES-256-GCM encryption and decryption.

First, ensure you have the necessary npm packages installed:

```bash
npm install crypto@3.14.7
```

Here's a basic implementation of a JSON payload encryption/decryption middleware:

```javascript
const crypto = require('crypto');

// Helper function to generate a random initialization vector (IV)
function generateIv() {
  return crypto.randomBytes(12);
}

// Helper function to create an AES-256-GCM key
function createKey(secret) {
  const key = Buffer.from(secret, 'utf8');
  if (key.length !== 32) {
    throw new Error('Secret must be 32 bytes long for AES-256-GCM.');
  }
  return key;
}

// Middleware function for encrypting and decrypting JSON payloads
function jsonPayloadEncryptionMiddleware(secret) {
  const key = createKey(secret);

  return (req, res, next) => {
    // Middleware to handle incoming requests with encrypted data
    req.decryptJsonPayload = async (encryptedData) => {
      try {
        if (!encryptedData || typeof encryptedData !== 'string') {
          throw new Error('Invalid input: Expected a string containing the encrypted JSON.');
        }

        const [ivBase64, cipherText] = encryptedData.split('.');
        const ivBuffer = Buffer.from(ivBase64, 'base64');
        const decipher = crypto.createDecipheriv('aes-256-gcm', key, ivBuffer);

        // Decrypt the data
        let decryptedData = decipher.update(cipherText, 'hex', 'utf8');
        decryptedData += decipher.final('utf8');

        // Verify and return the original JSON object
        const { data } = JSON.parse(decryptedData);
        if (!data || typeof data !== 'object') {
          throw new Error('Decrypted payload is not a valid JSON object.');
        }

        return data;
      } catch (error) {
        console.error('Error decrypting JSON payload:', error.message);
        res.status(401).json({ error: 'Invalid or corrupted payload' });
        return null;
      }
    };

    // Middleware to handle outgoing responses with encrypted data
    res.encryptJsonPayload = async (data) => {
      try {
        if (!data || typeof data !== 'object') {
          throw new Error('Data must be an object to encrypt.');
        }

        const iv = generateIv();
        const cipher = crypto.createCipheriv('aes-256-gcm', key, iv);

        // Encrypt the JSON string
        let encryptedData = cipher.update(JSON.stringify(data), 'utf8', 'hex');
        encryptedData += cipher.final('hex');

        // Append IV to the encrypted data
        return `${iv.toString('base64')}.${encryptedData}`;
      } catch (error) {
        console.error('Error encrypting JSON payload:', error.message);
        res.status(500).json({ error: 'Failed to encrypt payload' });
        return null;
      }
    };

    next();
  };
}

module.exports = jsonPayloadEncryptionMiddleware;
```

### Usage

To use this middleware, you can include it in your Express application like this:

```javascript
const express = require('express');
const app = express();

// Example secret key
const SECRET_KEY = 'your32bytesecretkey1234567890';

app.use(jsonPayloadEncryptionMiddleware(SECRET_KEY));

app.post('/api/data', (req, res) => {
  const payload = req.body;

  // Encrypt the payload
  const encryptedPayload = await req.encryptJsonPayload(payload);
  console.log('Encrypted Payload:', encryptedPayload);

  // Simulate sending an error response for demonstration purposes
  res.status(500).json({ error: 'Something went wrong' });
});

app.post('/api/data/decrypt', async (req, res) => {
  const encryptedData = req.query.encryptedData;

  if (!encryptedData) {
    return res.status(400).json({ error: 'Missing encrypted data in query parameters' });
  }

  // Decrypt the payload
  const decryptedPayload = await req.decryptJsonPayload(encryptedData);
  console.log('Decrypted Payload:', decryptedPayload);

  res.json(decryptedPayload);
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});
```

### Explanation

- **Key Generation**: The middleware generates a random key using the provided secret.
- **Encryption and Decryption**: It uses AES-256-GCM for encryption and decryption. The IV (Initialization Vector) is randomly generated for each encryption.
- **Middleware Functions**: `decryptJsonPayload` and `encryptJsonPayload` are provided as methods on the request and response objects, allowing you to encrypt and decrypt JSON payloads directly.

This example uses a simple base64 encoding of the IV and encrypted data for storage or transmission. In a production environment, consider using HTTPS to secure the connection between client and server.
```

